var _V2_GRAMMAR_SUBJECTIVE_FORMAT_TYPES = {"수정":"어법수정","수정(DC)":"어법수정(DC)","재작성":"어법재작성","배열":"어법배열","구문영작":"어법구문영작","어형":"어법어형"};
var _V2_GRAMMAR_SUBJECTIVE_REQ_TYPES = new Set(["어법수정","어법수정(DC)","어법재작성","어법배열","어법구문영작","어법어형"]);
var _V2_GRAMMAR_SUBJECTIVE_COMMON_REQ_PARTS = {"beforeHardRules":"\n\n[어법서술 공통 품질 기준]\n1. 반드시 지문 안 실제 문장 또는 그 문장의 의미를 보존한 최소 변형문을 기반으로 출제한다.\n2. 각 문항은 grammar-catalog.md의 Case 하나로 설명 가능해야 하며, items[].grammar_point에는 Case ID와 핵심 문법명을 함께 쓴다. 예: \"Case 24-1 관계대명사 vs 인칭대명사\".\n3. 오류를 만들 때는 의미를 무너뜨리지 말고 문법 판단만 요구되게 한다. 문맥상 말이 안 되는 오류, 상식으로 바로 고치는 오류는 금지한다.\n4. 정답은 유일해야 하며, reason_ko에는 구조 판단 근거를 한 문장으로 쓴다. 오류명만 나열하지 않는다.\n5. 후보 탐색은 수일치·태·시제·준동사·분사뿐 아니라 접속사/관계사(that/what/which), 전치사 vs 접속사(during/while 등), 가주어 it, for/of+목적격+to V, 병렬 구조, 동사 패턴(prompt/help/allow/cause/force+목적어+to V/원형), 기능어 선택(so/such, that/which), 대동사·대용 표현(do/does/did vs be동사), 대명사 지시대상(it/them/its/their)까지 별도 패스로 확인한다. 가능한 포인트를 넓게 뽑되, 최종 문항에는 품질 필터를 통과한 후보만 남긴다. 짧은 표현이라도 앞 문장/절의 술어 구조·생략 구조·지시대상을 복원해야 정답이 결정되면 우선 후보로 살리고, 긴 표현이라도 바로 앞 단어만 보고 1초 소거되면 탈락시킨다.\n6. 후보를 선별할 때는 grammar-catalog.md의 \"⭐ 선호 Case 인덱스\"와 \"출제 우선순위\"를 기준으로 1순위·선호 Case를 먼저 채택하고, 비선호 후보는 선호 Case로 목표 개수를 채울 수 없을 때만 보충용으로 사용한다.\n7. 최종 후보는 필수성(⭐/우선 Case인지)과 분산성(한 문장에 몰리지 않는지)을 먼저 본다. 한 문장에 ⭐ 후보가 여러 개 있으면 그 문장에서는 가장 좋은 하나만 남기고, 다른 문장의 ⭐/우선 후보로 커버리지를 넓힌다.\n8. 어법수정·어법재작성·어법어형은 각 후보를 학생에게 보이는 최종 선택형이 아니라 내부 검수용 [정답 / 오답] 후보쌍으로 먼저 만들어 정답 유일성, 표면상 변별성, 카탈로그 Case, 금지 규칙 통과 여부를 확인한 뒤 유형별 최종 형식으로 변환한다. 최종 선택 단계에서 같은 문장 안 selected 후보끼리 핵심 표현 사이가 7단어 미만이면 서로 정답 단서를 줄 위험이 있으므로 가장 선명한 후보 하나만 남긴다. 같은 표현과 같은 문법 판단이 반복되는 후보는 거리와 무관하게 하나만 남긴다. 예: as though they [are/were] 구조가 두 번 나오면 하나만 selected에 둔다. 어법배열·어법구문영작은 후보 탐색과 Case 검수를 적용하되, 오답 후보쌍 변환은 필요한 경우에만 사용한다.\n9. Case 19-1 당위 that절은 주어가 you/we/they/I처럼 동사원형과 현재형이 겉으로 같은 경우 우선순위를 낮추고, he/she/단수 명사처럼 V/V-s 차이가 드러나는 경우를 우선한다.\n10. 대명사 소유격/목적격/재귀대명사의 지시대상과 수일치는 선행사가 멀거나 주변에 경쟁 명사(단수/복수)가 있어 혼동이 생기는 경우 우선 후보로 본다. 단, 지시대상이 문맥상 여러 개로 해석될 수 있으면 출제하지 않는다.\n11. 지문에 적합한 Case가 부족하면 억지 오류를 만들지 말고 정상 문항 수를 줄이거나 가장 선명한 Case 1개만 사용한다.\n12. 아래 hard rule을 위반한 포인트는 만들지 않는다.\n","betweenHardAndQuality":"\n13. 아래 품질 우선 규칙을 적용하되 문맥상 반대 방향이 더 자연스러우면 유지할 수 있다.\n","afterQualityBeforeTrigger":"\n14. 응답은 지정 JSON만 반환한다. 마크다운, 해설 산문, 코드펜스는 쓰지 않는다.\n- grammar_point 필드는 반드시 grammar-catalog.md의 유효한 Case ID를 포함해야 한다 (예: \"Case 24-1 관계대명사 vs 인칭대명사\"). 카탈로그에 없는 포인트를 사용했으면 가장 가까운 유효 Case로 교체하라.\n- items 배열은 반드시 지문에 등장하는 순서대로 둔다. passage_with_marks 또는 passage_with_blanks의 밑줄/빈칸 순서가 (1)-(2)-(3)... 또는 a-b-c...가 되도록 고정하고, 정답/해설의 id도 같은 순서를 따른다.\n\n","betweenTriggerAndDiversity":"\n\n","betweenDiversityAndConclusion":"\n"};
var _V2_GRAMMAR_SUBJECTIVE_TYPE_REQ_PARTS = {"어법수정":{"beforeUnderlineCount":"\n\n[어법수정 출제 지시]\n지문에서 어법 판단이 가능한 표현을 밑줄 보기로 제시하고, 그중 어법상 틀린 표현만 학생이 올바른 표현으로 고쳐 쓰게 한다.\n- 목표 보기개수: ","betweenUnderlineAndErrorCount":"개 (허용 범위 4~7개)\n- 목표 오류개수: ","betweenErrorCountAndScope":"개 (허용 범위 1~5개)\n- 밑줄범위: ","afterScope":"\n- 목표 보기개수와 목표 오류개수는 완료 기준이다. 원문에 이미 틀린 표현이 부족하면 지문 의미를 크게 바꾸지 않는 범위에서 밑줄 표현을 카탈로그 Case로 설명 가능한 오류 형태로 최소 변형해 목표 오류개수를 맞춘다.\n- 목표 오류개수가 1개 이상이면 전부 올바름으로 출력하지 않는다. passage_with_marks에는 오류 item의 underlined와 같은 실제 오류 형태가 들어가야 하며, answer에는 그 오류의 올바른 수정 답만 쓴다.\n- 최종 출력에는 grammar_candidate_audit를 포함한다. candidate_points에는 넓게 뽑은 후보, selected에는 최종 사용 후보 id, rejected에는 버린 후보와 reason을 기록하고, 버린 후보가 없으면 audit_note에 \"추가 탈락 후보 없음\"이라고 쓴다. items[].candidate_id는 selected 후보 id와 연결한다. selected 후보의 pattern_signature에는 반복 검사용 핵심 표현+선택쌍을 반드시 쓴다.\n- 실제 오류개수는 실제 보기개수보다 반드시 적어야 한다. 정상 보기 최소 1개를 남기고 모든 보기를 오류로 만들지 않는다.\n- instruction에는 최종 보기개수와 오류개수를 반영한다. 지정값을 낮추는 것은 카탈로그 Case로 설명 가능한 오류를 만들 수 없는 경우에만 허용한다.\n- 어법수정 표기는 passage_with_marks, items[].id, 정답, 해설 모두 (1)~(n)만 사용한다. ⓐ~ⓔ 또는 (a)~(e)를 섞지 않는다.\n- passage_with_marks에 등장하는 순서대로 (1), (2), (3)...을 부여하고 items와 해설도 같은 순서를 따른다.\n- 정상 보기는 items[].is_error=false로 두고 정답지에 \"올바름/그대로\"를 명시한다.\n- 오류 표현은 원문 위치가 자연스러워야 하며, 학생이 주변 구조를 봐야 고칠 수 있어야 한다.\n- 응답 JSON: {instruction, passage_with_marks, grammar_candidate_audit:{candidate_points:[{id, source_sentence, target_text, pattern_signature, correct_form, wrong_form, grammar_case, is_preferred_case, priority, quality_score, difficulty_reason, risk, reject_reason}], selected:[id], rejected:[{id, reason}], audit_note}, items:[{id, candidate_id, underlined, is_error, answer, grammar_point, reason_ko, source_sentence}]}"},"어법수정(DC)":{"beforeUnderlineCount":"\n\n[어법수정(DC) 출제 지시 — Design + Combine]\n지문에서 어법 후보를 먼저 설계한 뒤, selected 후보만 사용해 어법수정 문제로 자동 조립한다. 기존 어법수정 JSON 계약은 그대로 유지한다.\n- 목표 보기개수: ","betweenUnderlineAndErrorCount":"개 (허용 범위 4~7개)\n- 목표 오류개수: ","betweenErrorCountAndScope":"개 (허용 범위 1~5개)\n- 밑줄범위: ","afterScope":"\n- 목표 보기개수와 목표 오류개수는 완료 기준이다. 원문에 이미 틀린 표현이 부족하면 지문 의미를 크게 바꾸지 않는 범위에서 밑줄 표현을 카탈로그 Case로 설명 가능한 오류 형태로 최소 변형해 목표 오류개수를 맞춘다.\n- 목표 오류개수가 1개 이상이면 전부 올바름으로 출력하지 않는다. passage_with_marks에는 오류 item의 underlined와 같은 실제 오류 형태가 들어가야 하며, answer에는 그 오류의 올바른 수정 답만 쓴다.\n- 최종 출력에는 grammar_candidate_audit를 포함한다. candidate_points에는 넓게 뽑은 후보, selected에는 최종 사용 후보 id, rejected에는 버린 후보와 reason을 기록하고, 버린 후보가 없으면 audit_note에 \"추가 탈락 후보 없음\"이라고 쓴다. items[].candidate_id는 selected 후보 id와 연결한다. selected 후보의 pattern_signature에는 반복 검사용 핵심 표현+선택쌍을 반드시 쓴다.\n- 실제 오류개수는 실제 보기개수보다 반드시 적어야 한다. 정상 보기 최소 1개를 남기고 모든 보기를 오류로 만들지 않는다.\n- instruction에는 최종 보기개수와 오류개수를 반영한다. 지정값을 낮추는 것은 카탈로그 Case로 설명 가능한 오류를 만들 수 없는 경우에만 허용한다.\n- 어법수정 표기는 passage_with_marks, items[].id, 정답, 해설 모두 (1)~(n)만 사용한다. ⓐ~ⓔ 또는 (a)~(e)를 섞지 않는다.\n- passage_with_marks에 등장하는 순서대로 (1), (2), (3)...을 부여하고 items와 해설도 같은 순서를 따른다.\n- 정상 보기는 items[].is_error=false로 두고 정답지에 \"올바름/그대로\"를 명시한다.\n- 오류 표현은 원문 위치가 자연스러워야 하며, 학생이 주변 구조를 봐야 고칠 수 있어야 한다.\n- 응답 JSON: {instruction, passage_with_marks, grammar_candidate_audit:{candidate_points:[{id, source_sentence, target_text, pattern_signature, correct_form, wrong_form, grammar_case, is_preferred_case, priority, quality_score, difficulty_reason, risk, reject_reason}], selected:[id], rejected:[{id, reason}], audit_note}, items:[{id, candidate_id, underlined, is_error, answer, grammar_point, reason_ko, source_sentence}]}\n- DC 전용: 최종 출력에는 grammar_design_trace를 추가한다. grammar_design_trace에는 used_candidate_ids, skipped_candidate_ids, unsuitable_reason, assembly_only:true를 둔다.\n- DC 전용: grammar_candidate_audit.candidate_points는 role(core/normal_trap/filler_allowed/forbidden/non_catalog/catalog_add_candidate), target_span, candidate_pair를 포함한 설계 후보 역할도 기록한다.\n- DC 전용: selected 후보만 items로 조립한다. 조립 단계에서 새 후보를 추가하지 않고, forbidden/non_catalog/catalog_add_candidate/filler_allowed 후보를 오류 item으로 쓰지 않는다.\n- DC 전용: 좋은 후보가 부족하면 금지 후보로 padding하지 말고 보기개수/오류개수를 줄인 뒤 instruction과 grammar_design_trace.unsuitable_reason에 사유를 남긴다."},"어법재작성":{"beforeErrorCount":"\n\n[어법재작성 출제 지시]\n지문의 문장 일부를 어법상 틀리게 제시하고, 학생이 문장 전체를 자연스럽고 문법적으로 올바르게 다시 쓰게 한다.\n- 오류개수: ","betweenErrorCountAndScope":"개\n- 밑줄범위: ","afterScope":"\n- prompt_sentence는 오류가 포함된 완전한 영어 문장이어야 한다.\n- answer_sentence는 원문의 의미를 보존한 완전한 영어 문장이어야 하며, 불필요한 패러프레이즈를 하지 않는다.\n- 해설은 오류명 나열이 아니라 \"왜 이 형태가 필요한지\"를 한 문장으로 쓴다.\n- 응답 JSON: {instruction, items:[{id, prompt_sentence, answer_sentence, grammar_point, reason_ko, source_sentence}]}"},"어법배열":{"beforeMorphChange":"\n\n[어법배열 출제 지시]\n지문의 핵심 문장을 바탕으로 어구 배열 문제를 만든다.\n- 어형변화: ","betweenMorphChangeAndWordAdd":"\n- 단어추가: ","afterWordAdd":"\n- word_bank는 5~9개 청크로 나누고, 정답 어순을 그대로 드러내지 않게 섞는다.\n- korean_prompt는 지문 내용과 대응되는 자연스러운 한국어 단서여야 한다.\n- 응답 JSON: {instruction, items:[{id, korean_prompt, word_bank, answer_sentence, grammar_point, reason_ko, source_sentence}]}"},"어법구문영작":{"beforeConstruction":"\n\n[어법구문영작 출제 지시]\n지문 내용과 연결되는 한국어 문장을 주고, 지정 구문을 사용해 영어로 쓰게 한다.\n- 구문: ","afterConstruction":"\n- \"자동\"이면 지문에서 가장 선명한 구문 Case를 골라 required_construction에 명시한다.\n- 정답은 지문 내용과 의미가 맞고 지정 구문을 실제로 포함해야 한다.\n- 한국어 단서만 보고 여러 영어 문장이 가능하면 안 된다. 핵심 어휘 또는 구조 제약을 포함한다.\n- 응답 JSON: {instruction, items:[{id, korean_prompt, required_construction, answer_sentence, grammar_point, reason_ko, source_sentence}]}"},"어법어형":{"beforeBlankCount":"\n\n[어법어형 출제 지시]\n지문에서 어법 포인트(시제·준동사·수일치·태·어형변화 등)를 활용할 수 있는 위치를 선정해 빈칸을 만들고, 각 빈칸 옆에 괄호로 동사/명사/형용사 원형을 제시한다.\n- 빈칸수: ","betweenBlankCountAndWordClass":"개\n- 원형제시 품사: ","afterWordClass":"\n- 정답은 문맥·어법 모두 충족하는 유일한 어형이어야 한다.\n- 같은 문법 포인트만 반복하지 말고 가능한 한 서로 다른 Case를 사용한다.\n- 고칠 필요 없는 원형 그대로가 정답인 빈칸도 1개 포함할 수 있다.\n- 응답 JSON: {instruction, passage_with_blanks, items:[{id, hint_word, answer, grammar_point, reason_ko, source_sentence}]}"}};
var _V2_HO_PROMPT_REQ_TYPES = new Set(["네모박스(HO)","핵심어적절(HO)","요약어휘(HO)","어법(HO)","어법(HO)(DC)"]);
var _V2_HO_PRINTABLE_TYPES = new Set(["네모박스(HO)","핵심어적절(HO)","어법(HO)","어법(HO)(DC)","요약어휘(HO)"]);
var _V2_EXTRA_PRINTABLE_TYPES = new Set(['word_order_blank', 'new_order_blank']);
function _usesPrintableQuestion(renderType) {
  return _V2_HO_PRINTABLE_TYPES.has(renderType) || _V2_EXTRA_PRINTABLE_TYPES.has(renderType);
}
var _V2_HO_ADDED_OUTPUT_REQ = "\n- 단락 추가 시 JSON에 added_paragraph, added_paragraph_translation_ko, added_paragraph_word_list를 반드시 출력할 것.\n- passage_displayed에는 원문만 담고, 창작 단락은 added_paragraph에만 담을 것. 두 필드에 동일 내용이 중복되면 안 된다.\n- word_list는 원문 지문 + 추가 단락 + 보기/선지 + 정답 표현에서 중요한 어휘를 함께 수집한다. 추가 단락 어휘만 따로 내고 원문/선지 어휘를 누락하지 않는다.\n- 유의어/반의어 관계는 두 단어가 지문·추가 단락·보기·선지·정답 표현 중 실제로 함께 등장할 때만 origin_word와 relation(synonym|antonym)으로 표시한다.";
var _V2_HO_NEMO_LANGUAGE_REQ = "\n- <보기> ㄱ~ㅂ 진술은 무조건 영어로 작성. 한국어 보기 진술 절대 금지.";
