  if (!_GRAMMAR_SUBJ_TYPES || !_GRAMMAR_SUBJ_TYPES.has(grammarType)) return false;

  var cleaned = {};
  if (params.vocabLevel !== undefined) cleaned.vocabLevel = params.vocabLevel;
  if (type === '어법서술') cleaned.grammarFormat = params.grammarFormat || '수정';
  Object.assign(cleaned, _normalizeGrammarSubjParams(grammarType, params));
  delete cleaned.vocab_level;

  var before = JSON.stringify(params);
  var after = JSON.stringify(cleaned);
