function _providerDisplayName(provider) {
  return provider === 'gemini' ? 'Gemini'
    : provider === 'openai' ? 'OpenAI'
    : provider === 'deepseek' ? 'DeepSeek'
    : provider === 'fable' ? 'Fable'
    : 'Claude';
}

function _getStoredProviderKey(provider) {
  if (provider === 'gemini') return getGeminiKey();
  if (provider === 'openai') return getOpenAIKey();
  if (provider === 'deepseek') return getDeepSeekKey();
  if (provider === 'fable') return getFableKey();
  return getKey();
}

async function _fetchWithTimeout(url, options, timeoutMs) {
  var ctrl = new AbortController();
  var timer = setTimeout(function() { ctrl.abort(); }, timeoutMs || 15000);
  try {
    return await fetch(url, Object.assign({}, options || {}, { signal: ctrl.signal }));
  } finally {
    clearTimeout(timer);
  }
}

async function _checkProviderKey(provider, key) {
  if (provider === 'gemini') {
    return _fetchWithTimeout('https://generativelanguage.googleapis.com/v1beta/models?key=' + encodeURIComponent(key), {
      method: 'GET',
      headers: { 'Content-Type': 'application/json' },
    }, 15000);
  }
  if (provider === 'openai') {
    return _fetchWithTimeout('https://api.openai.com/v1/models', {
      method: 'GET',
      headers: { 'Authorization': 'Bearer ' + key },
    }, 15000);
  }
  if (provider === 'deepseek') {
    return _fetchWithTimeout('https://api.deepseek.com/v1/models', {
      method: 'GET',
      headers: { 'Authorization': 'Bearer ' + key },
    }, 15000);
  }
  return _fetchWithTimeout('https://api.anthropic.com/v1/models', {
    method: 'GET',
    headers: {
      'x-api-key': key,
      'anthropic-version': '2023-06-01',
      'anthropic-dangerous-direct-browser-access': 'true',
    },
  }, 15000);
}

async function checkApiConnection(provider, inputId, statusId, btn) {
  var input = document.getElementById(inputId);
  var status = document.getElementById(statusId);
  var key = ((input && input.value) || '').trim() || _getStoredProviderKey(provider);
  var name = _providerDisplayName(provider);
  if (!key) {
    showToast(name + ' API 키를 먼저 입력하거나 저장해주세요');
    if (status) { status.textContent = '키 필요'; status.className = 'pk-status'; }
    return;
  }

  var oldText = btn ? btn.textContent : '';
  if (btn) { btn.disabled = true; btn.textContent = '확인중'; }
  if (status) { status.textContent = '확인 중'; status.className = 'pk-status'; }
  try {
    var resp = await _checkProviderKey(provider, key);
    if (!resp.ok) {
      var err = await resp.json().catch(function() { return {}; });
      var msg = (err.error && (err.error.message || err.error)) || ('HTTP ' + resp.status);
      throw new Error(msg);
    }
    if (status) { status.textContent = '✓ 연결됨'; status.className = 'pk-status ok'; }
    showToast(name + ' API 연결 확인됨');
  } catch(e) {
    if (status) { status.textContent = '연결 실패'; status.className = 'pk-status'; }
    showToast(name + ' 연결 실패: ' + (e.message || e));
  } finally {
    if (btn) { btn.disabled = false; btn.textContent = oldText || '연결확인'; }
  }
}

/* ── 키 상태 전체 갱신 (세 탭 공유) ── */
function _refreshAllKeyStatus() {
  var hasC = !!getKey(), hasG = !!getGeminiKey(), hasO = !!getOpenAIKey(), hasD = !!getDeepSeekKey(), hasF = !!getFableKey();
  var map = {
    claude:   [hasC, 'api-status',      'tr-api-status',     'syn-c-status'],
    gemini:   [hasG, 'gemini-status',   'tr-gemini-status',  'syn-g-status'],
    openai:   [hasO, 'openai-status',   'tr-openai-status',  'syn-o-status'],
    deepseek: [hasD, 'deepseek-status', 'tr-deepseek-status','syn-d-status'],
    fable:    [hasF, 'fable-status']
  };
  Object.values(map).forEach(function(arr) {
    var has = arr[0];
    arr.slice(1).forEach(function(id) {
      var s = document.getElementById(id);
      if (s) { s.textContent = has ? '✓ 저장됨' : '키 필요'; s.className = 'pk-status' + (has ? ' ok' : ''); }
    });
  });
}

