    length: '길이',
    chunking: '청킹',
    interpretation: '해석 제공',
    transform: '어형 변형',
    start_word: '시작어',
    explanation: '해설 제공',
    subtype: '세부 유형',
    variant: '변형',
    grammarFormat: '어법 형식',
    underlineCount: '밑줄 보기 수',
