  if (r.modelDesign) rows.push('<div class="style-row"><b>출제 AI:</b> ' + _esc(r.modelDesign) + '</div>');
  if (r.modelProof) rows.push('<div class="style-row"><b>창작문 검수 AI:</b> ' + _esc(r.modelProof) + '</div>');
