var _CI_LAST = {}; // sticky defaults per CI type { '내용일치': {series, format, difficulty, vocabLevel, complexity, creativity}, ... }
function _ciOn(type, key, val, def) {
  var saved = (_CI_LAST[type] || {})[key];
  var target = (saved !== undefined) ? String(saved) : String(def);
  return target === String(val) ? ' on' : '';
}
