function _mainCleanBtnText(btn) {
  return (btn.textContent || '').replace(/\s+/g, ' ').trim();
}
function _mainProviderName(btn) {
  return btn.closest('.provider-keys')?.querySelector('.pk-name')?.textContent.trim() || '선택한 제공자';
}
function _typeRangeLabel(t) {
  const min = t.rw?.[0] ?? 0;
  const max = t.rw?.[1] ?? 999;
  if (min <= 0 && max >= 999) return '권장 단어 수: 제한 없음';
  if (min <= 0) return '권장 단어 수: ' + max + '단어 이하';
  if (max >= 999) return '권장 단어 수: 최소 ' + min + '단어';
  return '권장 단어 수: ' + min + '~' + max + '단어';
}
function _typeRangeNotice(t, wc) {
  const min = t.rw?.[0] ?? 0;
  const max = t.rw?.[1] ?? 999;
  if (wc <= 0) return _typeRangeLabel(t);
  if (wc < min) return '현재 ' + wc + '단어라 권장 범위보다 짧습니다. 최소 ' + min + '단어 권장.';
  if (wc > max) return '현재 ' + wc + '단어라 권장 범위보다 깁니다. 최대 ' + max + '단어 권장.';
  return '현재 ' + wc + '단어: 권장 범위에 맞습니다.';
}
function _mainCurrentWordCount() {
  const p = passages.find(x => x.id === selectedId);
  return countWords(p?.text || '');
}
function _mainTypeTip(t, wc) {
  return (t.tip || t.label) + '\n' + _typeRangeNotice(t, wc);
}
function _mainButtonTooltip(btn) {
  const txt = _mainCleanBtnText(btn);
  if (btn.classList.contains('tchip')) {
    const info = ALL_TYPES.find(t => t.type === btn.dataset.qtype || t.label === txt.replace(/\s+×\d+$/, ''));
    return info ? _mainTypeTip(info, _mainCurrentWordCount()) : (btn.dataset.tip || _MAIN_TYPE_TIPS[txt] || '이 출제유형을 현재 지문에 추가합니다.');
  }
  if (btn.classList.contains('cfg-del')) return '이 출제유형 설정을 현재 지문에서 삭제합니다.';
  if (btn.classList.contains('pq-del')) return '이 지문을 문제 출제 큐에서 삭제합니다.';
  if (btn.classList.contains('api-btn')) {
    const provider = _mainProviderName(btn);
    if (btn.classList.contains('del')) return provider + ' API 키를 이 브라우저 저장소에서 삭제합니다.';
    if (btn.classList.contains('check')) return provider + ' API 키로 연결 상태를 확인합니다.';
    return provider + ' API 키를 이 브라우저 저장소에 저장합니다.';
  }
  if (btn.classList.contains('ps')) {
    const grp = btn.closest('.btn-grp');
    const key = grp?.dataset.globalKey || grp?.dataset.key || '';
    if (key === 'vocab' || key === 'vocabLevel') return _MAIN_VOCAB_TIPS[txt] || '이 문제의 어휘 난이도를 설정합니다.';
    if (key === 'attr' || key === 'attractiveness') return _MAIN_ATTR_TIPS[txt] || '오답 선지의 매력도를 설정합니다.';
    if (key === 'choiceLength') return _MAIN_SETTING_TIPS['choiceLength']?.[txt] || '선지 길이 기준을 설정합니다.';
    const base = _MAIN_SETTING_TIPS[key]?.[txt] || '현재 출제유형의 세부 옵션을 설정합니다.';
    if (btn.classList.contains('disabled') && key === 'paraphraseCreativity') return base + '\n패러프레이즈가 원문이면 창의도는 적용되지 않습니다.';
    return btn.classList.contains('disabled') ? base + '\n현재 선택한 하위유형에서는 이 옵션을 변경할 수 없습니다.' : base;
  }
  if (btn.matches('[data-var-run]') || btn.id === 'var-run-btn') return '선택한 변형 방식과 어휘 수준으로 현재 지문을 새 지문으로 변형합니다.';
  if (btn.matches('[data-var-vocab]')) return _MAIN_VOCAB_TIPS[btn.dataset.varVocab || txt] || '지문 변형에 사용할 어휘 수준을 설정합니다.';
  if (btn.matches('[data-var-cat][data-var-val]')) return '지문 변형 유형을 선택합니다. 선택한 방식으로 새 출제용 지문을 만듭니다.';
  if (btn.id === 'run-btn') return '큐에 있는 모든 지문과 선택된 출제유형을 순서대로 생성합니다.';
  if (btn.id === 'stop-btn') return '현재 진행 중인 전체 출제를 중단 요청합니다.';
  if (btn.id === 'word-all-btn') return '완료된 모든 문제를 Word 파일로 내려받습니다.';
  if (btn.id === 'json-all-btn') return '완료된 모든 문제 데이터를 JSON 파일로 내려받습니다.';
  if (btn.id === 'json-view-btn') return '완료된 모든 문제 JSON을 화면에서 보고 전체 복사합니다.';
  if (btn.id === 'inspect-all-btn') return '생성된 전체 문제의 개선사항을 AI로 점검합니다.';
  if (btn.classList.contains('add-passage-btn')) return '새 영어 지문 입력 카드를 문제 출제 큐에 추가합니다.';
  return txt ? txt + ' 버튼입니다.' : '';
}
function _mainSelectTooltip(sel) {
  const role = sel.dataset.pvRole;
  const id = sel.id || '';
  if (role === 'design' || id === 'pv-design') return '문제 출제에 사용할 AI 모델을 선택합니다.';
  if (role === 'proof' || id === 'pv-proof') return 'AI가 새로 쓴 영어 지문, 문장, 선택지의 자연성을 검수할 모델을 선택합니다.';
  if (role === 'review' || id === 'pv-review') return '생성된 문제를 검수할 AI 모델을 선택합니다.';
  if (id === 'pv-analyze') return '지문을 분석하고 추천 유형을 계산할 AI 모델을 선택합니다.';
  return '이 단계에 사용할 AI 모델을 선택합니다.';
}
function _applyMainTooltips(root) {
  const scope = root || document.getElementById('tab-main');
  if (!scope) return;
  scope.querySelectorAll('button').forEach(btn => {
    const tip = _mainButtonTooltip(btn);
    if (tip) btn.dataset.tip = tip;
    if (btn.title) btn.removeAttribute('title');
  });
  scope.querySelectorAll('select.pv-sel').forEach(sel => {
    sel.dataset.tip = _mainSelectTooltip(sel);
    if (sel.title) sel.removeAttribute('title');
  });
}
function _updateTypeChipRangeTooltips(p) {
  const wc = countWords(p?.text || '');
  ALL_TYPES.forEach(t => {
    const chip = currentChips[t.type];
    if (!chip) return;
    chip.dataset.tip = _mainTypeTip(t, wc);
    const min = t.rw?.[0] ?? 0;
    const max = t.rw?.[1] ?? 999;
    chip.classList.toggle('out-range', wc > 0 && (wc < min || wc > max));
  });
}
const _TRAINING_TYPE_TIPS = {
  '문법': '문법: 준동사/정동사, 수일치, 수동태/능동태, 병렬구조, 관계사 중심의 기본기 문제를 냅니다.',
  '지문이해': '지문이해: 핵심 내용과 논리 흐름을 쉬운 한국어 질문으로 확인하는 훈련 문제를 냅니다.',
  '해석훈련': '해석훈련: 문장 구조와 청킹 기준으로 해석 연습 문제를 냅니다.'
};
const _TRAINING_OPTION_TIPS = {
  '원문': '원문: 입력한 지문을 그대로 사용해 출제합니다.',
  '패러': '패러: 원문과 다른 문장으로 재구성한 뒤 출제합니다.',
  '한단어': '한단어: 정답을 한 단어 단위로 요구합니다.',
  '여러단어': '여러단어: 정답을 여러 단어 또는 어구 단위로 요구합니다.',
  '기본': '기본: 더 짧고 직접적인 기준으로 훈련 문제를 냅니다.',
  '실전': '실전: 실제 내신에 가까운 기준으로 훈련 문제를 냅니다.',
  '심화': '심화: 더 복합적인 근거 판단을 요구합니다.'
};
function _trainingButtonTooltip(btn) {
  const txt = _mainCleanBtnText(btn).replace(/\s+×\d+$/, '');
  if (btn.classList.contains('api-btn')) {
    const provider = _mainProviderName(btn);
    if (btn.classList.contains('del')) return provider + ' API 키를 이 브라우저 저장소에서 삭제합니다.';
    if (btn.classList.contains('check')) return provider + ' API 키로 연결 상태를 확인합니다.';
    return provider + ' API 키를 이 브라우저 저장소에 저장합니다.';
  }
  if (btn.classList.contains('tchip')) return _TRAINING_TYPE_TIPS[txt] || '이 훈련 유형을 현재 지문에 추가합니다.';
  if (btn.classList.contains('tr-ip')) return _TRAINING_OPTION_TIPS[txt] || '현재 훈련 유형의 세부 옵션을 설정합니다.';
  if (btn.classList.contains('pq-del')) return '이 지문을 기본기 훈련 큐에서 삭제합니다.';
  if (btn.classList.contains('tr-inst-del')) return '이 훈련 유형 설정을 현재 지문에서 삭제합니다.';
  if (btn.classList.contains('add-passage-btn')) return '새 영어 지문 입력 카드를 기본기 훈련 큐에 추가합니다.';
  if (btn.id === 'tr-run-btn') return '기본기 훈련 큐에 있는 모든 지문을 순서대로 출제합니다.';
  if (btn.id === 'tr-stop-btn') return '현재 진행 중인 기본기 훈련 출제를 중단 요청합니다.';
  if (btn.id === 'tr-word-all-btn') return '완료된 기본기 훈련 결과를 Word 파일로 내려받습니다.';
  if (btn.id === 'tr-json-all-btn') return '완료된 기본기 훈련 데이터를 JSON 파일로 내려받습니다.';
  if (btn.id === 'tr-json-view-btn') return '완료된 기본기 훈련 JSON을 화면에서 보고 전체 복사합니다.';
  if (btn.id === 'tr-json-copy-all-btn') return '완료된 기본기 훈련 JSON을 바로 클립보드에 복사합니다.';
  if (btn.id === 'tr-inspect-btn') return '생성된 기본기 훈련 문제의 개선사항을 AI로 점검합니다.';
  if (btn.classList.contains('tr-key-btn')) return txt.includes('원문') ? '원문 지문 표시를 열고 닫습니다.' : '정답과 해설 표시를 열고 닫습니다.';
  if (btn.classList.contains('tr-word-dl-btn')) return '이 지문의 훈련 결과를 Word 파일로 내려받습니다.';
  if (txt.includes('JSON 보기')) return '이 결과의 JSON 데이터를 화면에 표시합니다.';
  if (txt.includes('JSON 다운로드')) return '이 결과의 JSON 데이터를 파일로 내려받습니다.';
  if (txt.includes('이 지문 출제')) return '현재 선택한 지문만 출제합니다.';
  return txt ? txt + ' 버튼입니다.' : '';
}
function _trainingSelectTooltip(sel) {
  const id = sel.id || '';
  if (id.includes('design')) return '기본기 훈련 문제 출제에 사용할 AI 모델을 선택합니다.';
  if (id.includes('review')) return '기본기 훈련 결과 검수에 사용할 AI 모델을 선택합니다.';
  return '이 단계에 사용할 AI 모델을 선택합니다.';
}
function _applyTrainingTooltips(root) {
  const scope = root || document.getElementById('tab-training');
  if (!scope) return;
  scope.querySelectorAll('button').forEach(btn => {
    const existing = btn.getAttribute('title');
    const tip = _trainingButtonTooltip(btn) || existing;
    if (tip) btn.dataset.tip = tip;
    if (existing) btn.removeAttribute('title');
  });
  scope.querySelectorAll('select.pv-sel').forEach(sel => {
    sel.dataset.tip = _trainingSelectTooltip(sel);
    if (sel.title) sel.removeAttribute('title');
  });
}
function _ensureUiTooltip() {
  let tip = document.getElementById('ui-tooltip');
  if (!tip) {
    tip = document.createElement('div');
    tip.id = 'ui-tooltip';
    tip.className = 'ui-tooltip';
    document.body.appendChild(tip);
  }
  return tip;
}
function _showUiTooltip(el) {
  const text = el?.dataset?.tip;
  if (!text) return;
  const tip = _ensureUiTooltip();
  tip.textContent = text;
  tip.classList.add('show');
  const r = el.getBoundingClientRect();
  const tr = tip.getBoundingClientRect();
  let left = r.left + r.width / 2 - tr.width / 2;
  left = Math.max(8, Math.min(left, window.innerWidth - tr.width - 8));
  let top = r.top - tr.height - 8;
  if (top < 8) top = r.bottom + 8;
  tip.style.left = left + 'px';
  tip.style.top = top + 'px';
}
function _hideUiTooltip() {
  const tip = document.getElementById('ui-tooltip');
  if (tip) tip.classList.remove('show');
}
document.addEventListener('pointerover', e => {
  const el = e.target.closest('[data-tip]');
  if (el) _showUiTooltip(el);
});
document.addEventListener('pointerout', e => {
  if (e.target.closest('[data-tip]')) _hideUiTooltip();
});
document.addEventListener('focusin', e => {
  const el = e.target.closest('[data-tip]');
  if (el) _showUiTooltip(el);
});
document.addEventListener('focusout', e => {
  if (e.target.closest('[data-tip]')) _hideUiTooltip();
});

/* ── 전역 상태 ── */
let gVocab = '03', gAttr = '중', gChoiceLen = '중';
let passages = [];
let _pid = 0, _iid = 0;
let selectedId = null;
let isRunning = false;
let currentChips = {}; // type → DOM (현재 렌더된 칩)

/* ── API 키 ── */
const getKey = () => localStorage.getItem('mp_key') || '';
function saveApiKey() {
  const k = document.getElementById('api-key-input').value.trim();
  if (!k) { showToast('API 키를 입력해주세요'); return; }
  localStorage.setItem('mp_key', k);
  document.getElementById('api-key-input').value = '';
  _refreshAllKeyStatus();
  showToast('Claude API 키 저장됨');
}
function clearApiKey() {
  localStorage.removeItem('mp_key');
  document.getElementById('api-key-input').value = '';
  _refreshAllKeyStatus();
  showToast('Claude API 키 삭제됨');
}


/* ── 글로벌 설정 클릭 위임 ── */
document.addEventListener('click', e => {
  const ps = e.target.closest('.ps');
  if (!ps || ps.classList.contains('disabled')) return;
  if (ps.closest('[data-wo-type]')) return;
  const grp = ps.closest('.btn-grp');
  if (!grp) return;
  const style = grp.dataset.style || '';
  grp.querySelectorAll('.ps').forEach(b => b.classList.remove('on','ona','onb'));
  ps.classList.add(style==='a'?'ona':style==='b'?'onb':'on');
  const gk = grp.dataset.globalKey;
  if (gk === 'vocab') { gVocab = ps.textContent.trim(); propagateGlobal(); }
  else if (gk === 'attr') { gAttr = ps.textContent.trim(); propagateGlobal(); }
  else if (gk === 'choiceLength') { gChoiceLen = ps.textContent.trim(); propagateGlobal(); }
});

function propagateGlobal() {
  document.querySelectorAll('.cfg-block').forEach(block => {
    const vg = block.querySelector('.btn-grp[data-key="vocabLevel"]');
    if (vg) {
      const s = vg.dataset.style||''; const c = s==='b'?'onb':s==='a'?'ona':'on';
      vg.querySelectorAll('.ps').forEach(b => { b.classList.remove('on','ona','onb'); if (b.textContent.trim()===gVocab) b.classList.add(c); });
    }
    const ag = block.querySelector('.btn-grp[data-key="attractiveness"]');
    if (ag) {
      const abtns = ag.querySelectorAll('.ps');
      const hasVal = [...abtns].some(b => b.textContent.trim()===gAttr);
      if (hasVal) { abtns.forEach(b => { b.classList.remove('on','ona','onb'); if (b.textContent.trim()===gAttr) b.classList.add('on'); }); }
    }
    const clg = block.querySelector('.btn-grp[data-key="choiceLength"]');
    if (clg) {
      clg.querySelectorAll('.ps').forEach(b => { b.classList.remove('on'); if (b.textContent.trim() === gChoiceLen) b.classList.add('on'); });
    }
  });
}

/* ── 지문 추가 / 삭제 ── */
function addPassage() {
  console.log('[addPassage] called');
  const p = { id: ++_pid, text: '', instances: [], results: [], status: 'idle', aiScores: null };
  passages.push(p);
  renderQueueItem(p);
  selectPassage(p.id);
  updateQueueStatus();
}

/* ── 지문 변형과 펼치기 — 상태 ── */
var _varCat = null, _varVal = null, _varVocab = '03';

function setVarSel(cat, val, el) {
  _varCat = cat; _varVal = val;
  document.querySelectorAll('.var-chip.para, .var-chip.trans').forEach(b => b.classList.remove('on'));
  if (el) el.classList.add('on');
}

function setVarVocab(val, el) {
  _varVocab = val;
  document.querySelectorAll('.var-chip.vocab').forEach(b => b.classList.remove('on'));
  if (el) el.classList.add('on');
}

document.addEventListener('click', function(e) {
  var runBtn = e.target.closest('[data-var-run]');
  if (runBtn) {
    runPassageVariant();
    return;
  }
  var selBtn = e.target.closest('[data-var-cat][data-var-val]');
  if (selBtn) {
    setVarSel(selBtn.dataset.varCat, selBtn.dataset.varVal, selBtn);
    return;
  }
  var vocabBtn = e.target.closest('[data-var-vocab]');
  if (vocabBtn) {
    setVarVocab(vocabBtn.dataset.varVocab, vocabBtn);
  }
});

async function runPassageVariant() {
  if (!_varCat || !_varVal) { showToast('유형을 먼저 선택해주세요'); return; }
  saveState();
  const currentP = passages.find(x => x.id === selectedId);
  if (!currentP || !currentP.text.trim()) { showToast('먼저 지문을 입력하세요'); return; }
  const key = getKey();
  if (!key) { showToast('Claude API 키가 필요합니다'); return; }

  const runBtn = document.getElementById('var-run-btn');
  if (runBtn) { runBtn.disabled = true; runBtn.textContent = '⟳ 생성 중…'; }

  const vocabNote = '\n\n[어휘 수준 제한]\n어휘 레벨 ' + _varVocab + ' 수준의 단어를 사용할 것 (원문에 이미 등장한 단어는 레벨 무관 사용 가능).';

  try {
    let sys, userMsg, label;

    if (_varCat === 'para') {
      const paraDesc = {
        '하': '문장 구조·순서·내용을 원문과 동일하게 유지. 핵심 동사·명사를 유의어로만 교체. 창의적 변형 없음. 원문 체감 70% 이상 유지.',
        '중': '유의어 교체 + 일부 문장 구조 변환(능동↔수동, 절→구 등). 내용은 원문에 충실하며 창의적 변형 최소. 원문 체감 40~70% 유지.',
        '상': '표현 전면 재작성 + 문장 구조 다수 변경 + 내용의 창의적 재해석 허용. 논지·핵심 주제는 반드시 유지하되 예시·서술 방식은 자유롭게 바꿀 것. 원문 체감 40% 미만.'
      };
      label = '패러프레이즈 ' + _varVal;
      sys = '당신은 영어 지문 패러프레이즈 전문가입니다.\n\n[강도 — ' + _varVal + ']\n' + (paraDesc[_varVal] || '') + vocabNote + '\n\n패러프레이즈된 지문 본문만 출력하세요. 설명·제목 없음.';
      userMsg = '[강도: ' + _varVal + ']\n[원지문]\n' + currentP.text + '\n\n위 지문을 강도 \'' + _varVal + '\'로 패러프레이즈해줘. 지문 본문만 출력.';

    } else {
      const transDesc = {
        'T-A': '원지문 논지의 반대 방향으로 전환. 원지문이 주장하는 것을 반박하는 방향으로 새 지문 작성.',
        'T-B': '원지문의 기본 개념을 심화. 개념 내부 메커니즘·조건·한계를 탐구하는 방향으로 작성.',
        'T-C': '개념 심화 + 다른 영역에 적용. 원지문 원리를 다른 분야(사회·과학·경제 등)에 적용하는 방향으로 작성.',
        'T-D': '원리를 제시하고 결론을 도출. 원지문에 나열된 현상들로부터 명확한 결론·원칙을 도출하는 방향으로 작성.',
        'T-all': '소재만 차용, 완전 신규 작성. 단, 새 지문 전체 단어 수 대비 원문 단어 20% 이상 재사용 필수.'
      };
      label = _varVal + ' 변형 지문';
      sys = '당신은 영어 지문 Transform 전문가입니다.\n\n[변형 방향 — ' + _varVal + ']\n' + (transDesc[_varVal] || '') + vocabNote + '\n\n[지시사항]\n- 원지문과 비슷한 분량 (±20%) 유지\n- 논리적 완결성 있는 지문 작성\n- 변형된 지문 본문만 출력 (설명·제목 없음)';
      userMsg = '[원지문]\n' + currentP.text + '\n\n위 지문을 ' + _varVal + ' 방식으로 변형해줘. 지문 본문만 출력.';
    }

    showToast(label + ' 생성 중…');
    const providers = getProviders();
    const designModel = providers.design || 'claude-sonnet-4-6';
    const proofModel = providers.proof || 'claude-sonnet-4-6';
    const result = await _callLLM(sys, userMsg, designModel, key, null, 'syn');
    const draft = result.trim();
    const proof = await _proofreadCreativeText(draft, proofModel, key, null, 'syn', label);
    const transformed = proof.text;

    const p = { id: ++_pid, text: transformed, instances: [], results: [], status: 'idle', aiScores: null, originalText: currentP.text, paraphraseLevel: _varVal, creativeProofreading: { applied: proofModel !== 'none', model: proofModel, passage: proof } };
    passages.push(p);
    renderQueueItem(p);
    refreshQueueItem(p);
    updateQueueStatus();
    const qEl = document.querySelector(`[data-pid="${p.id}"]`);
    if (qEl) qEl.scrollIntoView({ behavior: 'smooth', block: 'nearest' });
    showToast('큐에 추가 완료: ' + label);

  } catch(e) {
    showToast('변형 실패: ' + e.message);
  } finally {
    if (runBtn) { runBtn.disabled = false; runBtn.textContent = '⚡ 실행'; }
  }
}

function deletePassage(id, e) {
  e.stopPropagation();
  passages = passages.filter(p => p.id !== id);
  document.querySelector(`[data-pid="${id}"]`)?.remove();
  if (selectedId === id) { selectedId = null; renderRightEmpty(); }
  updateQueueStatus();
}

/* ── 큐 아이템 ── */
function renderQueueItem(p) {
  const el = document.createElement('div');
  el.className = 'passage-q-item';
  el.dataset.pid = p.id;
  el.onclick = () => selectPassage(p.id);
  el.innerHTML = `<div class="pq-head">
    <span class="pq-num">${passages.length}</span>
    <span class="pq-preview" id="pqp-${p.id}">지문 없음</span>
    <span class="pq-status idle" id="pqs-${p.id}">미설정</span>
    <button class="pq-del" onclick="deletePassage(${p.id},event)">×</button>
  </div>`;
  document.getElementById('passage-queue').appendChild(el);
}

function refreshQueueItem(p) {
  const el = document.querySelector(`[data-pid="${p.id}"]`);
  if (!el) return;
  const pre = document.getElementById(`pqp-${p.id}`);
  const sts = document.getElementById(`pqs-${p.id}`);
  if (pre) pre.textContent = p.text ? p.text.slice(0,38)+'…' : '지문 없음';
  if (sts) {
    const cnt = p.instances.length;
    const stMap = {idle:'미설정', processing:'출제 중', done:'완료', error:'오류'};
    const stKey = p.status === 'idle' && cnt > 0 ? 'ready' : p.status;
    const errCnt = p.errors && p.errors.length;
    sts.textContent = stKey === 'ready' ? `${cnt}문항 대기`
      : p.status === 'error' && errCnt ? `오류 (${errCnt}건)`
      : (stMap[p.status] || `${cnt}문항`);
    if (p.status === 'error' && errCnt) {
      sts.title = p.errors.map(e => `[${e.qType}] ${e.message}`).join('\n');
    } else {
      sts.title = '';
    }
    sts.className = `pq-status ${stKey}`;
  }
  el.className = `passage-q-item${selectedId===p.id?' active':''}${p.status==='done'?' st-done':p.status==='error'?' st-error':p.status==='processing'?' st-processing':''}`;
}

function updateQueueStatus() {
  const total = passages.length;
  const done  = passages.filter(p => p.status==='done').length;
  document.getElementById('queue-status').textContent = done > 0 ? `${done}/${total} 완료` : `${total}개`;
  const qCnt = passages.reduce((s,p) => s+p.instances.length, 0);
  document.getElementById('summary-line').textContent =
    total > 0 ? `지문 ${total}개 · 총 ${qCnt}문항${done>0?' · '+done+'개 완료':''}` : '';
  passages.forEach((p,i) => {
    const el = document.querySelector(`[data-pid="${p.id}"] .pq-num`);
    if (el) el.textContent = i+1;
  });
  const allBtn = document.getElementById('word-all-btn');
  if (allBtn) allBtn.style.display = done > 0 ? '' : 'none';
  const anyProcessed = passages.some(p => p.status === 'done' || p.status === 'error');
  const jsonAllBtn = document.getElementById('json-all-btn');
  if (jsonAllBtn) jsonAllBtn.style.display = anyProcessed ? '' : 'none';
  const jsonViewBtn = document.getElementById('json-view-btn');
  if (jsonViewBtn) jsonViewBtn.style.display = anyProcessed ? '' : 'none';
  const inspBtn = document.getElementById('inspect-all-btn');
  if (inspBtn) inspBtn.style.display = done > 0 ? '' : 'none';
}

/* ── 지문 선택 ── */
function selectPassage(id) {
  if (selectedId === id) return;
  if (selectedId != null) saveState();
  selectedId = id;
  document.querySelectorAll('.passage-q-item').forEach(el => el.classList.toggle('active', +el.dataset.pid === id));
  renderRightPanel(id);
}

function saveState() {
  const p = passages.find(x => x.id === selectedId);
  if (!p) return;
  const ta = document.getElementById('passage-ta');
  if (ta) p.text = ta.value;
  p.instances.forEach(inst => {
    const block = document.querySelector(`[data-cfg-id="${inst.id}"]`);
    if (block) inst.params = readCfgParams(block);
  });
}

/* ── 오른쪽 패널 ── */
function renderRightEmpty() {
  document.getElementById('right-panel').innerHTML = `<div class="card"><div class="empty-state"><div class="empty-icon">←</div><div>왼쪽에서 지문을 추가하거나 선택하세요</div></div></div>`;
}

function renderRightPanel(id) {
  const p = passages.find(x => x.id === id);
  if (!p) { renderRightEmpty(); return; }
  const idx = passages.indexOf(p) + 1;
  const rp = document.getElementById('right-panel');
  rp.innerHTML = `
    <div class="card">
      <div class="card-hd"><span>지문 ${idx}</span><span class="aux" id="word-cnt">0 단어</span></div>
      <div class="passage-body">
        <textarea id="passage-ta" placeholder="지문을 여기에 붙여넣으세요..." oninput="onPassageInput()">${escH(p.text)}</textarea>
        <div class="reco-loading" id="reco-loading"><span class="spin">⟳</span><span>AI 분석 중...</span></div>
        <div class="p-meta" id="reco-wrap" style="display:none">
          <span class="reco-label" id="reco-label">✦ 추천</span>
          <div class="reco-chips" id="reco-chips"></div>
          <div id="reco-tf-row" style="display:none;width:100%;align-items:center;gap:6px;margin-top:3px">
            <span class="reco-label" style="color:#0369A1;white-space:nowrap">⟲ 변형</span>
            <div class="reco-chips" id="reco-tf-chips"></div>
          </div>
        </div>
      </div>
    </div>
    <div class="card">
      <div class="card-hd"><span>지문 변형과 펼치기</span><button type="button" class="var-run-btn" id="var-run-btn" data-var-run="1">⚡ 실행</button></div>
      <div class="variant-body">
        <div class="var-row">
          <span class="var-label">패러프레이즈</span>
          <div class="var-chips">
            <button type="button" class="var-chip para${_varCat==='para'&&_varVal==='하'?' on':''}" data-var-cat="para" data-var-val="하">하</button>
            <button type="button" class="var-chip para${_varCat==='para'&&_varVal==='중'?' on':''}" data-var-cat="para" data-var-val="중">중</button>
            <button type="button" class="var-chip para${_varCat==='para'&&_varVal==='상'?' on':''}" data-var-cat="para" data-var-val="상">상</button>
          </div>
        </div>
        <div class="var-row">
          <span class="var-label">Transform</span>
          <div class="var-chips">
            <button type="button" class="var-chip trans${_varCat==='trans'&&_varVal==='T-A'?' on':''}" data-var-cat="trans" data-var-val="T-A">T-A 반대</button>
            <button type="button" class="var-chip trans${_varCat==='trans'&&_varVal==='T-B'?' on':''}" data-var-cat="trans" data-var-val="T-B">T-B 심화</button>
            <button type="button" class="var-chip trans${_varCat==='trans'&&_varVal==='T-C'?' on':''}" data-var-cat="trans" data-var-val="T-C">T-C 적용</button>
            <button type="button" class="var-chip trans${_varCat==='trans'&&_varVal==='T-D'?' on':''}" data-var-cat="trans" data-var-val="T-D">T-D 결론</button>
            <button type="button" class="var-chip trans${_varCat==='trans'&&_varVal==='T-all'?' on':''}" data-var-cat="trans" data-var-val="T-all">T-all 신규</button>
          </div>
        </div>
        <div class="var-row">
          <span class="var-label">어휘 수준</span>
          <div class="var-chips">
            <button type="button" class="var-chip vocab${_varVocab==='01'?' on':''}" data-var-vocab="01">01</button>
            <button type="button" class="var-chip vocab${_varVocab==='02'?' on':''}" data-var-vocab="02">02</button>
            <button type="button" class="var-chip vocab${_varVocab==='03'?' on':''}" data-var-vocab="03">03</button>
            <button type="button" class="var-chip vocab${_varVocab==='04'?' on':''}" data-var-vocab="04">04</button>
          </div>
        </div>
      </div>
    </div>
    <div class="card">
      <div class="card-hd"><span>유형 선택</span><span class="aux" id="sel-cnt">${p.instances.length}개 선택</span></div>
      <div class="type-body">
        <div class="sec-lbl">객관식</div><div class="type-grid" id="obj-grid"></div>
        <div class="sec-lbl">서답형</div><div class="type-grid" id="subj-grid"></div>
      </div>
    </div>
    <div class="card">
      <div class="card-hd"><span>출제 설정</span></div>
      <div class="cfg-empty" id="cfg-empty"${p.instances.length>0?' style="display:none"':''}>유형을 선택하면 설정이 표시됩니다</div>
      <div class="cfg-body" id="cfg-body"${p.instances.length===0?' style="display:none"':''}></div>
    </div>
    <div id="results-wrap" style="${p.results.length>0||p.status==='processing'?'':'display:none'}">
      <div class="card" style="margin-bottom:10px">
        <div class="card-hd"><span>진행 상황</span><span class="aux" id="prog-summary"></span></div>
        <div style="padding:8px 16px" id="progress-body"></div>
      </div>
      <div id="result-cards"></div>
      <div id="word-btn-wrap" style="display:none;text-align:center;padding:12px 0">
        <button id="word-dl-btn" onclick="downloadWord()"
          style="padding:12px 32px;border-radius:12px;background:#1D4ED8;color:#fff;font-size:13px;font-weight:600;border:none;cursor:pointer">
          📄 Word 다운로드
        </button>
        <button id="pdf-dl-btn" onclick="downloadPdf()"
          style="display:block;margin:8px auto 0;padding:12px 32px;border-radius:12px;background:#111827;color:#fff;font-size:13px;font-weight:600;border:none;cursor:pointer">
          🖨️ PDF로 저장
        </button>
        <div style="margin-top:6px;color:var(--mut);font-size:11px;line-height:1.5">
          PDF는 문제를 먼저, 정답 및 해설을 뒤쪽에 분리해 저장합니다.
        </div>
      </div>
    </div>`;

  currentChips = {};
  buildTypeChips(p);
  p.instances.forEach(inst => appendCfgBlock(inst));
  updateChipCounts(p);

  const wc = countWords(p.text);
  document.getElementById('word-cnt').textContent = wc + ' 단어';
  if (p.aiScores) applyAIScores(p.aiScores, p);
  else if (wc > 0) {
    const analyzeProvider = _detectProvider(getProviders().analyze);
    if (_getStoredProviderKey(analyzeProvider.type)) {
      clearTimeout(p._at);
      p._at = setTimeout(() => analyzeWithAI(p.text, p), 300);
    } else {
      updateRecoByWords(wc, p);
    }
  }

  if (p.results.length > 0) restoreResults(p);
}

function restoreResults(p) {
  const pb = document.getElementById('progress-body');
  const ps = document.getElementById('prog-summary');
  const rc = document.getElementById('result-cards');
  if (ps) ps.textContent = `${p.results.length}문항 완료`;
  p.results.forEach(r => {
    if (pb) {
      const el = document.createElement('div');
      el.className = 'prog-row';
      el.innerHTML = `<span class="prog-type">${SUBJ_LABELS[r.qType]??r.qType}</span><span class="prog-step prog-done">완료</span>`;
      pb.appendChild(el);
    }
    if (rc) rc.appendChild(buildResultCard(r.qType, _withResultParams(r.question, r), r.passage || p.text, r.originalText || p.originalText));
  });
  const wbw = document.getElementById('word-btn-wrap');
  if (wbw) wbw.style.display = '';
}

/* ── 타입 칩 ── */
function buildTypeChips(p) {
  const og = document.getElementById('obj-grid');
  const sg = document.getElementById('subj-grid');
  GRAMMAR_TYPES.forEach(t => {
    const b = document.createElement('button');
    b.className = 'tchip ' + (t.type === '어법서술' ? 'subj' : '');
    b.textContent = t.label;
    b.dataset.qtype = t.type;
    if (t.tip) b.dataset.tip = t.tip;
    b.onclick = () => addType(t.type, p);
    currentChips[t.type] = b;
    if (t.type === '어법' && og) og.appendChild(b);
    if (t.type === '어법서술' && sg) sg.appendChild(b);
  });
  OBJ_TYPES.forEach(t => {
    const b = document.createElement('button');
    b.className = 'tchip'; b.textContent = t.label;
    b.dataset.qtype = t.type;
    if (t.tip) b.dataset.tip = t.tip;
    b.onclick = () => addType(t.type, p);
    currentChips[t.type] = b; og.appendChild(b);
  });
  SUBJ_TYPES.forEach(t => {
    const b = document.createElement('button');
    b.className = 'tchip ' + (t.cls === 'wo' ? 'wo' : 'subj');
    b.textContent = t.label;
    b.dataset.qtype = t.type;
    if (t.tip) b.dataset.tip = t.tip;
    b.onclick = () => addType(t.type, p);
    currentChips[t.type] = b; sg.appendChild(b);
  });
  _updateTypeChipRangeTooltips(p);
  _applyMainTooltips();
}

function updateChipCounts(p) {
  ALL_TYPES.forEach(t => {
    const chip = currentChips[t.type]; if (!chip) return;
    const cnt = p.instances.filter(i => i.type === t.type).length;
    chip.querySelector('.chip-cnt')?.remove();
    if (cnt > 0) {
      chip.classList.add('on');
      const sp = document.createElement('span'); sp.className = 'chip-cnt'; sp.textContent = cnt;
      chip.appendChild(sp);
    } else { chip.classList.remove('on'); }
  });
  const sc = document.getElementById('sel-cnt');
  if (sc) sc.textContent = p.instances.length + '개 선택';
}

/* ── 유형 추가 / 삭제 ── */
function addType(type, p) {
  const inst = { id: ++_iid, type, params: {} };
  p.instances.push(inst);
  appendCfgBlock(inst);
  updateChipCounts(p);
  updateCfgVisibility(p);
  refreshQueueItem(p);
  updateQueueStatus();
}

function appendCfgBlock(inst) {
  const block = makeCfgBlock(inst.type, inst.id);
  document.getElementById('cfg-body').appendChild(block);
  if (inst.params && Object.keys(inst.params).length > 0)
    Object.entries(inst.params).forEach(([k,v]) => setBlockVal(block, k, v));
  syncHoPassageMode(block);
  syncParaphraseCreativity(block);
  /* 새 블록의 per-passage select에 전역 모델 기본값 주입 */
  const gDesign = document.getElementById('pv-design')?.value;
  const gProof = document.getElementById('pv-proof')?.value;
  const gReview = document.getElementById('pv-review')?.value;
  if (gDesign) { const s = block.querySelector('[data-pv-role="design"]'); if(s) s.value = gDesign; }
  if (gProof) { const s = block.querySelector('[data-pv-role="proof"]'); if(s) s.value = gProof; }
  if (gReview) { const s = block.querySelector('[data-pv-role="review"]'); if(s) s.value = gReview; }
  _applyMainTooltips(block);
}

function removeInstance(iid) {
  const p = passages.find(x => x.id === selectedId); if (!p) return;
  p.instances = p.instances.filter(i => i.id !== iid);
  document.querySelector(`[data-cfg-id="${iid}"]`)?.remove();
  updateChipCounts(p);
  updateCfgVisibility(p);
  refreshQueueItem(p);
  updateQueueStatus();
}

function updateCfgVisibility(p) {
  const has = p.instances.length > 0;
  const e = document.getElementById('cfg-empty');
  const b = document.getElementById('cfg-body');
  if (e) e.style.display = has ? 'none' : '';
  if (b) b.style.display = has ? '' : 'none';
}

/* ── 지문 입력 ── */
function onPassageInput() {
  const p = passages.find(x => x.id === selectedId); if (!p) return;
  const text = document.getElementById('passage-ta').value;
  if (p.text !== text) p.aiScores = null;
  p.text = text;
  const wc = countWords(text);
  document.getElementById('word-cnt').textContent = wc + ' 단어';
  const pre = document.getElementById(`pqp-${p.id}`);
  if (pre) pre.textContent = text ? text.slice(0,38)+'…' : '지문 없음';
  clearTimeout(p._rt); clearTimeout(p._at);
  const analyzeProvider = _detectProvider(getProviders().analyze);
  const hasKey = _getStoredProviderKey(analyzeProvider.type);
  _updateTypeChipRangeTooltips(p);
  if (hasKey) p._at = setTimeout(() => analyzeWithAI(text, p), 1200);
  else p._rt = setTimeout(() => updateRecoByWords(wc, p), 500);
}

function countWords(t) { return t.trim() ? t.trim().split(/\s+/).length : 0; }

function updateRecoByWords(wc, p) {
  const recoSet = new Set(ALL_TYPES.filter(t => wc >= t.rw[0] && wc <= t.rw[1]).map(t => t.type));
  ALL_TYPES.forEach(t => currentChips[t.type]?.classList.toggle('reco', recoSet.has(t.type)));
  _updateTypeChipRangeTooltips(p);
  const rw = document.getElementById('reco-wrap'); if (!rw) return;
  if (recoSet.size > 0) {
    document.getElementById('reco-label').textContent = '✦ 추천';
    document.getElementById('reco-chips').innerHTML =
      [...recoSet].map(t => { const i = ALL_TYPES.find(x => x.type===t); return `<span class="reco-chip">${i?.label??t}</span>`; }).join('');
    rw.style.display = 'flex';
  } else { rw.style.display = 'none'; }
}

/* ── AI 분석 ── */
const AI_PROMPT = `Analyze this English passage for Korean high school exam question suitability.
Output ONLY valid JSON (no markdown, no extra text). All scores 0-100.

{"obj":{"빈칸B형":0,"빈칸A-1형":0,"빈칸A형":0,"빈칸C형":0,"제목":0,"주제":0,"요지":0,"삽입A형":0,"삽입B형":0,"순서A형":0,"순서B형":0,"순서B-1형":0,"순서C형":0,"어법":0,"어휘":0,"무관한문장":0,"함축의미":0,"의미오지선다":0,"내용일치":0},"subj":{"summary_blank":0,"restatement_blank":0,"word_order_blank":0,"understanding_sm":0,"new_order_blank":0,"어법서술":0},"transform":{"T-A":0,"T-B":0,"T-C":0,"T-D":0,"T-all":0}}

Scoring guide:
빈칸B형: keyword blank. High(80+) if 130+w. 빈칸A-1형: Hidden Truth clause blank. High if 150+w counterintuitive.
빈칸A형: basic inference. High if 180+w. 빈칸C형: examiner writes para. High if <150w.
제목: High if paradox/metaphor. 주제: 60+ if clear argument. 요지: High if compressible to one sentence.
삽입A형: High if 160+w. 삽입B형: High if <160w. 순서A형: High if 180+w.
순서B형: High if 130-220w. 순서B-1형: High if <150w. 순서C형: High if 150+w.
어법(obj): High if 170+w 5+ grammar points; 단문형 if 5 standalone sentences possible. 어법서술(subj): High if 170+w clear error spots or 130+w target constructions present. 어휘: High if 150+w antonym-substitutable words.
무관한문장: High if 170+w. 함축의미: High if 150+w metaphor/paradox. 내용일치: High if 200+w 5+ facts.
summary_blank: High if 130+w 2-5 concepts. restatement_blank: High if 130+w synonymous keywords.
word_order_blank: High if 130+w common patterns.
understanding_sm: High if passage has clear abstract leap, personal experience change, or experiment contrast (9-type SM scoring).
Transform scoring (passage rewrite direction for new exam passage):
T-A(80+): passage has a strong invertible thesis — the argument can be flipped to its opposite (e.g., "X is harmful" → "X is beneficial").
T-B(80+): passage introduces a concept with room to deepen its mechanism, conditions, or limits.
T-C(80+): passage contains a principle easily applicable to a different domain (science↔social↔economics).
T-D(80+): passage lists phenomena or observations from which a clear conclusion or principle can be drawn.
T-all(80+): passage topic/setting is reusable but the content is so specific that a fully new passage is better.
Assign the highest score to the single best-fit type; others receive proportionally lower scores.

Passage:
`;

async function analyzeWithAI(text, p) {
  var wc = countWords(text);
  if (wc < 60) {
    updateRecoByWords(wc, p);
    return;
  }
  const analyzeModelId = getProviders().analyze;
  const analyzeProvider = _detectProvider(analyzeModelId);
  const ld = document.getElementById('reco-loading');
  const rw = document.getElementById('reco-wrap');
  if (rw) rw.style.display = 'none';
  if (ld) { ld.style.display = 'flex'; ld.innerHTML = '<span class="spin">⟳</span><span>AI 분석 중...</span>'; }
  try {
    const key = _getStoredProviderKey(analyzeProvider.type);
    if (!key) {
      if (ld) ld.innerHTML = '<span style="color:#EF4444;font-size:10px">✕ ' + _providerDisplayName(analyzeProvider.type) + ' API 키 없음</span>';
      updateRecoByWords(wc, p);
      return;
    }
    const rawText = await _callLLM('', AI_PROMPT + text, analyzeModelId, key, null, 'analyze');
    const result = _extractJson(rawText);
    if (!result || !result.obj || !result.subj) throw new Error('AI 분석 JSON 파싱 실패');
    p.aiScores = result;
    if (selectedId === p.id) applyAIScores(result, p);
  } catch(e) {
    if (ld) ld.innerHTML = `<span style="color:#EF4444;font-size:10px">✕ ${e.message}</span>`;
    updateRecoByWords(wc, p);
  }
}


const TF_LABEL = { 'T-A':'T-A 반대', 'T-B':'T-B 심화', 'T-C':'T-C 적용', 'T-D':'T-D 결론', 'T-all':'T-all 신규' };

function applyAIScores(result, p) {
  const ld = document.getElementById('reco-loading'); if (ld) ld.style.display = 'none';
  ALL_TYPES.forEach(t => { const c = currentChips[t.type]; if (c) { c.classList.remove('ai-top'); c.querySelector('.chip-score')?.remove(); } });
  const all = { ...result.obj, ...result.subj };
  ALL_TYPES.forEach(t => {
    const chip = currentChips[t.type]; if (!chip) return;
    const score = all[t.type];
    if (score !== undefined) { const sp = document.createElement('span'); sp.className='chip-score'; sp.textContent=score; chip.appendChild(sp); }
  });
  const topObj  = OBJ_TYPES.map(t => ({type:t.type,score:result.obj?.[t.type]||0})).sort((a,b)=>b.score-a.score).slice(0,4);
  const topSubj = SUBJ_TYPES.map(t => ({type:t.type,score:result.subj?.[t.type]||0})).sort((a,b)=>b.score-a.score).slice(0,2);
  [...topObj,...topSubj].forEach(({type}) => { const c = currentChips[type]; if (c) c.classList.add('ai-top'); });
  const rw = document.getElementById('reco-wrap'); if (!rw) return;
  document.getElementById('reco-label').textContent = '✦ AI 추천';
  document.getElementById('reco-chips').innerHTML = [
    ...topObj.map(e => { const i=ALL_TYPES.find(x=>x.type===e.type); return `<span class="reco-chip">${i?.label??e.type}<b>${e.score}</b></span>`; }),
    ...topSubj.map(e => { const i=ALL_TYPES.find(x=>x.type===e.type); return `<span class="reco-chip s">${i?.label??e.type}<b>${e.score}</b></span>`; })
  ].join('');

  /* ── Transform 추천 ── */
  const tfRow   = document.getElementById('reco-tf-row');
  const tfChips = document.getElementById('reco-tf-chips');
  const tfScores = result.transform || {};
  const topTf = Object.keys(TF_LABEL)
    .map(k => ({ type: k, score: tfScores[k] || 0 }))
    .sort((a, b) => b.score - a.score);
  if (tfChips && topTf.length > 0) {
    tfChips.innerHTML = topTf.map((e, i) => {
      const extra = i === 0 ? ' style="font-weight:700;border-color:#0369A1;color:#0369A1"' : '';
      return `<span class="reco-chip tf"${extra}>${TF_LABEL[e.type]}<b>${e.score}</b></span>`;
    }).join('');
    /* q-pt-card 에 추천 유형 자동 반영 */
    const bestTf = topTf[0];
    if (bestTf && bestTf.score > 0) _applyQPtRecommend(bestTf.type, topTf);
  }
  if (tfRow) tfRow.style.display = topTf.some(e => e.score > 0) ? 'flex' : 'none';

  rw.style.display = 'flex';
}

/* q-pt-card의 Transform 버튼에 점수 표시 및 추천 유형 하이라이트 */
function _applyQPtRecommend(bestType, ranked) {
  var idMap = { 'T-A':'TA','T-B':'TB','T-C':'TC','T-D':'TD','T-all':'Tall' };
  ranked.forEach(function(e) {
    var btn = document.getElementById('qpt-type-' + idMap[e.type]);
    if (!btn) return;
    /* 기존 점수 제거 */
    var old = btn.querySelector('.chip-score');
    if (old) old.remove();
    /* 점수 추가 */
    var sp = document.createElement('span');
    sp.className = 'chip-score';
    sp.style.cssText = e.type === bestType ? 'color:#0369A1;font-weight:700' : '';
    sp.textContent = e.score;
    btn.appendChild(sp);
    /* 최고 추천 강조 */
    btn.style.borderColor = e.type === bestType ? '#0369A1' : '';
    btn.style.color       = e.type === bestType ? '#0369A1' : '';
  });
  /* q-pt-card 섹션 제목에 추천 표시 */
  var card = document.getElementById('q-pt-card');
  if (card) {
    var lbl = card.querySelector('.card-hd span:first-child');
    if (lbl) lbl.textContent = '지문 변형  ✦ ' + bestType;
  }
}

/* ── 설정 블록 ── */
function vocabBtns(style) {
  const cls = style==='b'?'onb':style==='a'?'ona':'on';
  return `<div class="btn-grp" data-key="vocabLevel" data-style="${style||''}">
    ${['01','02','03','04'].map(v=>`<button class="ps${v===gVocab?' '+cls:''}">${v}</button>`).join('')}</div>`;
}
function attrBtns(type) {
  const levels = _supportsMaxAttractiveness(type) ? ['하','중','상','최상'] : ['하','중','상'];
  const active = levels.includes(gAttr) ? gAttr : '상';
  return `<div class="btn-grp" data-key="attractiveness">
    ${levels.map(v=>`<button class="ps${v===active?' on':''}">${v}</button>`).join('')}</div>`;
}
function choiceLenBtns() {
  return `<div class="btn-grp" data-key="choiceLength">
    ${['단','중','장'].map(v => `<button class="ps${v === gChoiceLen ? ' on' : ''}">${v}</button>`).join('')}
  </div>`;
}
function paraphraseControls() {
  return `<div class="p-divider"></div>
    <div class="p-row"><span class="p-lbl">패러프레이즈</span>
      <div class="btn-grp" data-key="paraphraseLevel">
        <button class="ps on">원문</button><button class="ps">하</button><button class="ps">중</button><button class="ps">상</button>
      </div></div>
    <div class="p-row"><span class="p-lbl">창의도</span>
      <div class="btn-grp" data-key="paraphraseCreativity">
        <button class="ps on disabled">보수</button><button class="ps disabled">중간</button><button class="ps disabled">창의</button>
      </div></div>`;
}

