document.addEventListener('click', e => {
  const btn = e.target.closest('.cfg-block .btn-grp[data-key="wordbank"] .ps');
  if (!btn) return;
  setTimeout(() => {
    const block = btn.closest('.cfg-block');
    const grp = btn.closest('.btn-grp');
    if (!block || !grp) return;
    const isWordbank = readBtnGrp(grp) === true;
    if (isWordbank) {
      setBlockVal(block, 'first_letter_hint', '미제공');
    } else {
      setBlockVal(block, 'wordbank_morph_mode', 'none');
    }
  }, 0);
});

function setWoSub(btn, mode) {
  btn.closest('.btn-grp').querySelectorAll('.ps').forEach(b => b.classList.remove('ona'));
  btn.classList.add('ona');
  const block = btn.closest('.cfg-block'); const isPure = mode === 'pure';
  block.querySelector('.wo-transform')?.querySelectorAll('.ps').forEach((b,i) => {
    if (isPure) { b.classList.remove('disabled'); }
    else { b.classList.add('disabled'); b.classList.remove('ona'); if (i===1) b.classList.add('ona'); }
  });
  block.querySelector('.wo-chunking')?.querySelectorAll('.ps').forEach(b => {
    if (isPure) b.classList.remove('disabled'); else b.classList.add('disabled');
  });
}

function readBtnGrp(grp) {
  const sel = grp.querySelector('.ps.on,.ps.ona,.ps.onb'); if (!sel) return null;
  const raw = sel.textContent.trim().split('\n')[0].trim();
  const ms = grp.dataset.map;
  if (ms) { try { const m = JSON.parse(ms); if (m[raw]!==undefined) return m[raw]; } catch {} }
  return raw;
}
function isActiveCfgParamGroup(grp) {
  const fmtRow = grp.closest('.fmt-row[data-fmt]');
  if (fmtRow && fmtRow.style.display === 'none') return false;
  const hoRow = grp.closest('.fmt-ho-row');
  if (hoRow && hoRow.style.display === 'none') return false;
  return true;
}
function readCfgParams(block) {
  const p = {};
  block.querySelectorAll('.btn-grp[data-key]').forEach(grp => {
    if (!isActiveCfgParamGroup(grp)) return;
    const v = readBtnGrp(grp);
    if (v !== null) p[grp.dataset.key] = v;
  });
  return p;
}
function setBlockVal(block, key, value) {
  const grp = block.querySelector(`.btn-grp[data-key="${key}"]`); if (!grp) return;
  const style = grp.dataset.style||''; const cls = style==='b'?'onb':style==='a'?'ona':'on';
  let tgt = String(value);
  const ms = grp.dataset.map;
  if (ms) { try { const m = JSON.parse(ms); for (const [l,v] of Object.entries(m)) { if (String(v)===String(value)) { tgt=l; break; } } } catch {} }
  grp.querySelectorAll('.ps').forEach(b => { b.classList.remove('on','ona','onb'); if (b.textContent.trim().split('\n')[0].trim()===tgt) b.classList.add(cls); });
}

/* ── JSON 빌드 ── */
function buildJson(p) {
  p.instances.forEach(inst => {
    const block = document.querySelector(`[data-cfg-id="${inst.id}"]`);
    if (!block) return;
    inst.params = readCfgParams(block);
    inst.pvDesign = (block.querySelector('[data-pv-role="design"]')?.value || '').trim();
    inst.pvProof = (block.querySelector('[data-pv-role="proof"]')?.value || '').trim();
    inst.pvReview = (block.querySelector('[data-pv-role="review"]')?.value || '').trim();
  });
  const questions = p.instances.map(({type, params, pvDesign, pvProof, pvReview}) => {
    const {vocabLevel='03', attractiveness='중', paraphraseLevel='원문', paraphraseCreativity='보수', ...rest} = params || {};
    const q = {type, vocabLevel};
    q.paraphraseLevel = paraphraseLevel || '원문';
    q.paraphraseCreativity = q.paraphraseLevel === '원문' ? '보수' : (paraphraseCreativity || '보수');
    if (type==='빈칸C형') { q.attractiveness=attractiveness; if (rest.structureType) q.params={structureType:rest.structureType}; }
    else if (type==='의미오지선다') {
      q.attractiveness = attractiveness;
      q.params = {
        passageMode: rest.passageMode || '원문 그대로',
        structureType: rest.structureType || '자동',
      };
    }
    else if (type==='understanding_sm') {
      const sub = rest.subtype;
      q.params = { subtype: (!sub || sub==='자동') ? null : sub.replace('형','') };
    }
    else if (type==='new_order_blank') {
      const v = rest.variant;
      q.params = { ...rest, variant: (!v || v==='자동') ? null : v };
    }
    else if (CI_SET.has(type)) {
      q.params = rest; // CI types pass all params (series, format, difficulty, complexity, creativity, concept_type)
      // save sticky defaults
      if (!_CI_LAST[type]) _CI_LAST[type] = {};
      Object.assign(_CI_LAST[type], rest, { vocabLevel });
    }
    else if (type === '네모박스(HO)') {
      q.params = {
        passageMode: rest.passageMode || '그대로 사용',
        structureType: rest.structureType || '자동',
        direction: rest.direction || '긍정',
        hoDifficulty: rest.hoDifficulty || '중',
      };
    }
    else if (type === '핵심어적절(HO)') {
      q.params = {
        passageMode: rest.passageMode || '원문 그대로',
        structureType: rest.structureType || '자동',
        level: rest.level || '기본',
        direction: rest.direction || '긍정',
        hoDifficulty: rest.hoDifficulty || '중',
      };
    }
    else if (type === '요약어휘(HO)') {
      q.params = {
        level: rest.level || '기본',
        passageMode: rest.passageMode || '그대로 사용',
        structureType: rest.structureType || '자동',
        direction: rest.direction || '부정',
        hoDifficulty: rest.hoDifficulty || '중',
      };
    }
    else if (type === '어법(HO)' || type === '어법(HO)(DC)') {
      q.params = {
        passageMode: '단락 추가',
        structureType: rest.structureType || '자동',
        level: rest.level || '기본',
        direction: rest.direction || '부정',
        underlineScope: rest.underlineScope || '한단어',
      };
    }
    else if (type === '어법') {
      const normalizedGrammar = _normalizeGrammarQuestionType({ type, params: rest });
      q.type = normalizedGrammar.type;
      if (normalizedGrammar.params && Object.keys(normalizedGrammar.params).length) q.params = normalizedGrammar.params;
    }
    else if (type === '어법서술') {
      const normalizedGrammar = _normalizeGrammarQuestionType({ type, params: rest });
      q.type = normalizedGrammar.type;
      const cleanGrammarParams = _normalizeGrammarSubjParams(q.type, normalizedGrammar.params || {});
      if (Object.keys(cleanGrammarParams).length) q.params = cleanGrammarParams;
    }
    else if (SUBJ_SET.has(type)) { q.params = _normalizeJookwanBlankParams(type, rest); }
    else if (['어법①','어법(A)','어법단문'].includes(type)) { if (Object.keys(rest).length) q.params=rest; }
    else {
      q.attractiveness=attractiveness;
      if (type === '요지' && Object.keys(rest).length) q.params = rest;
    }
    if (CHOICE_LEN_WORDS[type]) {
      q.choiceLength = params.choiceLength || '중';
    }
    if (pvDesign) q.pvDesign = pvDesign;
    if (pvProof) q.pvProof = pvProof;
    if (pvReview) q.pvReview = pvReview;
    return q;
  });
  return { passage: p.text, questions };
}

/* ── 전체 진행 상황 트래커 ── */
var _gpTotal = 0, _gpDone = 0, _gpStart = 0, _gpTimer = null;

function gpStart(total) {
  _gpTotal = total; _gpDone = 0; _gpStart = Date.now();
  _tokStats = {};
  const cost = document.getElementById('gp-cost'); if (cost) cost.innerHTML = '';
  const box = document.getElementById('gp-box');
  if (box) { box.style.display = 'flex'; box.classList.remove('done'); }
  gpRender();
  clearInterval(_gpTimer);
  _gpTimer = setInterval(function() {
    const el = document.getElementById('gp-time');
    if (!el) return;
    const s = Math.floor((Date.now() - _gpStart) / 1000);
    el.textContent = s < 60 ? s + '초' : Math.floor(s/60) + '분 ' + (s%60) + '초';
  }, 500);
}

function gpTick() {
  _gpDone++;
  gpRender();
}

function gpRender() {
  const pct = _gpTotal > 0 ? Math.round(_gpDone / _gpTotal * 100) : 0;
  const fill = document.getElementById('gp-fill');
  const count = document.getElementById('gp-count');
  const label = document.getElementById('gp-label');
  if (fill)  fill.style.width = pct + '%';
  if (count) count.textContent = _gpDone + ' / ' + _gpTotal + ' 문항';
  if (label) label.textContent = _gpDone < _gpTotal ? (_gpTotal - _gpDone) + '문항 남음 (' + pct + '%)' : '전체 완료!';
}

function gpFinish() {
  clearInterval(_gpTimer); _gpTimer = null;
  const s = Math.floor((Date.now() - _gpStart) / 1000);
  const el = document.getElementById('gp-time');
  if (el) el.textContent = (s < 60 ? s + '초' : Math.floor(s/60) + '분 ' + (s%60) + '초') + ' 소요';
  const box = document.getElementById('gp-box');
  if (box) box.classList.add('done');
  gpRender();
}

var _stopRequested = false;

function stopQueue() {
  _stopRequested = true;
  const stopBtn = document.getElementById('stop-btn');
  if (stopBtn) { stopBtn.disabled = true; stopBtn.textContent = '⏹ 중지 중...'; }
}

/* ── 순차 큐 실행 ── */
async function runQueue() {
  if (isRunning) { showToast('이미 출제 중입니다'); return; }
  const apiKey = getKey();
  if (!apiKey) { showToast('API 키를 먼저 저장해주세요'); return; }
  const _pvCheck = getProviders();
  const _pvModels = [_pvCheck.analyze, _pvCheck.design, _pvCheck.proof, _pvCheck.review].filter(m => m && m !== 'none');
  const _needsGemini = _pvModels.some(m => _detectProvider(m).type === 'gemini');
  const _needsOpenAI = _pvModels.some(m => _detectProvider(m).type === 'openai');
  if (_needsGemini && !getGeminiKey()) { showToast('Gemini API 키를 먼저 저장해주세요'); return; }
  if (_needsOpenAI && !getOpenAIKey()) { showToast('OpenAI API 키를 먼저 저장해주세요'); return; }
  saveState();
  const pending = passages.filter(p => p.text.trim() && p.instances.length > 0);
  pending.forEach(p => { p.status = 'idle'; p.results = []; });
  if (pending.length === 0) { showToast('출제할 지문이 없습니다 (지문+유형 확인)'); return; }

  isRunning = true;
  _stopRequested = false;
  const btn = document.getElementById('run-btn');
  const stopBtn = document.getElementById('stop-btn');
  btn.disabled = true; btn.textContent = '⏳ 출제 중...';
  if (stopBtn) { stopBtn.style.display = ''; stopBtn.disabled = false; stopBtn.textContent = '⏹ 출제 중지'; }

  const totalQ = pending.reduce((s, p) => s + p.instances.length, 0);
  gpStart(totalQ);

  for (const p of pending) {
    if (_stopRequested) {
      p.status = 'idle'; refreshQueueItem(p);
      continue;
    }
    p.status = 'processing';
    refreshQueueItem(p);
    selectPassage(p.id);
    await runPassage(p, apiKey);
    p.status = p.results.length > 0 ? 'done' : 'error';
    refreshQueueItem(p);
    updateQueueStatus();
  }

  isRunning = false;
  _stopRequested = false;
  btn.disabled = false; btn.textContent = '⚡ 전체 순차 출제';
  if (stopBtn) { stopBtn.style.display = 'none'; stopBtn.disabled = false; stopBtn.textContent = '⏹ 출제 중지'; }
  gpFinish();
  showToast(`✓ ${pending.length}개 지문 출제 완료`);

  const allDone = passages.filter(p => p.results.length > 0);
  if (allDone.length > 1) showCombinedResults(allDone);
}

async function runPassage(p, apiKey) {
  const json = buildJson(p);
  const rw = document.getElementById('results-wrap');
  const pb = document.getElementById('progress-body');
  const rc = document.getElementById('result-cards');
  if (rw) rw.style.display = '';
  if (pb) pb.innerHTML = '';
  if (rc) rc.innerHTML = '';
  p.results = [];
  p.errors = [];
  const progItems = {};

  try {
    const providers = getProviders();
    await generateClientSide(apiKey, json.passage, json.questions, function(ev) { handleEvent(ev, p, progItems); }, providers);
  } catch(e) {
    showToast('오류: ' + e.message);
  }
}

function handleEvent(ev, p, progItems) {
  const pb = document.getElementById('progress-body');
  const ps = document.getElementById('prog-summary');
  switch (ev.type) {
    case 'start':
      if (ps) ps.textContent = `총 ${ev.total}문항`; break;
    case 'progress': {
      if (!progItems[ev.qType] && pb) {
        const el = document.createElement('div'); el.className = 'prog-row';
        el.innerHTML = `<span class="prog-type">${SUBJ_LABELS[ev.qType]??ev.qType}</span><span class="prog-step prog-ing">대기 중</span>`;
        pb.appendChild(el); progItems[ev.qType] = el;
      }
      const sp = progItems[ev.qType]?.querySelector('.prog-step');
      if (sp) { sp.textContent = ev.step; sp.className = 'prog-step prog-ing'; }
      break; }
    case 'result': {
      const el = progItems[ev.qType];
      if (el) { const sp = el.querySelector('.prog-step'); if (sp) { sp.textContent='완료'; sp.className='prog-step prog-done'; } }
      p.results.push({qType:ev.qType, question:ev.question,
        params: ev.params || (ev.question && ev.question.params) || null,
        passage: ev.passageText || p.text,
        originalText: ev.originalText || p.originalText || null,
        paraphraseLevel: ev.paraphraseLevel || p.paraphraseLevel || '원문',
        paraphraseCreativity: ev.paraphraseCreativity || '보수',
        creativeProofreading: ev.creativeProofreading || null,
        vocabLevel:ev.vocabLevel, attractiveness:ev.attractiveness,
        modelDesign:ev.modelDesign, modelProof:ev.modelProof, modelReview:ev.modelReview});
      gpTick();
      const rc = document.getElementById('result-cards');
      if (rc) { const card = buildResultCard(ev.qType, _withResultParams(ev.question, ev), ev.passageText || p.text, ev.originalText || p.originalText); rc.appendChild(card); card.scrollIntoView({behavior:'smooth',block:'nearest'}); }
      break; }
    case 'error': {
      const el = progItems[ev.qType];
      if (el) { const sp = el.querySelector('.prog-step'); if (sp) { sp.textContent='오류: '+ev.message; sp.className='prog-step prog-err'; } }
      if (!p.errors) p.errors = [];
      p.errors.push({ qType: ev.qType, message: ev.message, timestamp: new Date().toISOString() });
      gpTick();
      break; }
    case 'done':
      if (ps) ps.textContent += ' · 완료';
      if (p.results.length > 0) { const w = document.getElementById('word-btn-wrap'); if (w) w.style.display=''; }
      break;
  }
}

/* ── Word 다운로드 ── */
async function downloadWord() {
  const p = passages.find(x => x.id === selectedId);
  if (!p || p.results.length === 0) { showToast('다운로드할 결과가 없습니다'); return; }
  const btn = document.getElementById('word-dl-btn');
  btn.disabled = true; btn.textContent = '⏳ 생성 중...';
  try {
    const blob = await buildWordDocBlob(p.text, p.results, new Date().toISOString().slice(0,10)); const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    const ts = new Date().toISOString().slice(0,19).replace(/[:.]/g,'-');
    a.href=url; a.download=`모의고사_${ts}.docx`;
    document.body.appendChild(a); a.click(); document.body.removeChild(a);
    setTimeout(() => URL.revokeObjectURL(url), 1000);
    showToast('✓ Word 파일 다운로드 완료');
  } catch(e) { showToast('오류: '+e.message); }
  finally { btn.disabled=false; btn.textContent='📄 Word 다운로드'; }
}

function _pdfEscape(value) {
  return String(value ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

function _pdfNl(value) {
  return _pdfEscape(value).replace(/\n/g, '<br>');
}

function _pdfResolveQuestion(rawQuestion) {
  var q = rawQuestion || {};
  if (q.raw) {
    try {
      var parsed = JSON.parse(q.raw);
      if (parsed && typeof parsed === 'object') q = parsed;
    } catch (_) {}
  }
  return q || {};
}

function _pdfText(value) {
  if (value == null) return '';
  if (typeof value === 'string' || typeof value === 'number' || typeof value === 'boolean') return String(value);
  if (typeof value === 'object') return String(value.text ?? value.label ?? value.choice ?? value.option ?? value.word ?? value.answer ?? JSON.stringify(value));
  return String(value);
}

function _pdfChoiceRows(q) {
  var choices = q.choices || q.options || q.answer_choices || q.output_choices;
  if (!Array.isArray(choices)) return '';
  return '<ol class="choices">' + choices.map(function(c) {
    return '<li>' + _pdfNl(_pdfText(c)) + '</li>';
  }).join('') + '</ol>';
}

function _pdfBogiRows(q) {
  var rows = q.bogi || q.marked_items;
  if (!Array.isArray(rows) || !rows.length) return '';
  return '<div class="subhead">&lt;보기&gt;</div><ol class="bogi">' + rows.map(function(row) {
    var label = row && typeof row === 'object' && row.id ? _pdfEscape(row.id) + '. ' : '';
    return '<li>' + label + _pdfNl(_pdfText(row)) + '</li>';
  }).join('') + '</ol>';
}

function _pdfWordList(q) {
  var rows = q.chunks_shuffled || q.chunking_items || q.hint_words || q.wordbank_items || q.word_bank;
  if (!Array.isArray(rows) || !rows.length) return '';
  var label = (q.bogi || q.marked_items) ? '제시어' : '&lt;보기&gt;';
  return '<div class="subhead">' + label + '</div><div class="wordbank">' + rows.map(_wordItemText).map(_pdfEscape).join(' / ') + '</div>';
}

function _pdfQuestionPassage(q, fallbackPassage) {
  return q.passage_displayed
    || q.passage_with_marks
    || q.passage_with_blanks
    || q.passage_with_blank
    || q.sentence_with_blank
    || q.display_sentence
    || q.blanks_text
    || q.passage
    || fallbackPassage
    || '';
}

function _pdfAnswerText(q) {
  var answer = q.answer_key ?? q.answer ?? q.correct_answer ?? q.answer_count;
  if (Array.isArray(answer)) return answer.map(_pdfText).join(', ');
  if (answer && typeof answer === 'object') {
    return Object.keys(answer).map(function(key) {
      return '(' + key + ') ' + _pdfText(answer[key]);
    }).join('   ');
  }
  return _pdfText(answer);
}

function _pdfExplanationText(q) {
  var parts = [];
  [
    q.explanation_logic,
    q.explanation_summary,
    q.explanation_correct,
    q.explanation,
    q.commentary,
    q.explanation_full_order,
    q.explanation_flow,
  ].forEach(function(v) { if (v) parts.push(_pdfText(v)); });
  if (Array.isArray(q.explanation_wrong) && q.explanation_wrong.length) {
    parts.push('오답 분석: ' + q.explanation_wrong.map(_pdfText).join(' / '));
  }
  if (Array.isArray(q.items) && q.items.length) {
    parts.push(q.items.map(function(item, idx) {
      if (!item || typeof item !== 'object') return '(' + (idx + 1) + ') ' + _pdfText(item);
      var id = item.id ?? item.number ?? idx + 1;
      var prompt = item.prompt ?? item.underlined ?? item.text ?? '';
      var ans = item.answer ?? item.answer_sentence ?? item.correction ?? '';
      var point = item.grammar_point ? ' [' + item.grammar_point + ']' : '';
      var reason = item.reason_ko ?? item.reason ?? '';
      if (!prompt && !ans && !point && !reason) return '';
      return '(' + id + ') ' + (prompt ? prompt + ' ' : '') + (ans ? '정답: ' + ans : '') + point + (reason ? ' - ' + reason : '');
    }).filter(Boolean).join('\n'));
  }
  if (Array.isArray(q.bogi) && q.bogi.length) {
    var bogiExpl = q.bogi.map(function(row) {
      if (!row || typeof row !== 'object') return '';
      var state = row.is_correct === true ? 'O' : row.is_correct === false ? 'X' : '';
      var reason = row.reason_ko || row.reason || '';
      if (!state && !reason) return '';
      return (row.id ? row.id + '. ' : '') + state + (reason ? ' - ' + reason : '');
    }).filter(Boolean).join('\n');
    if (bogiExpl) parts.push(bogiExpl);
  }
  if (q.passage_translation_ko) parts.push('〈해석〉\n' + _pdfText(q.passage_translation_ko));
  if (q.added_paragraph_translation_ko) parts.push('【추가 단락 해석】\n' + _pdfText(q.added_paragraph_translation_ko));
  if (Array.isArray(q.word_list) && q.word_list.length) {
    parts.push('〈어휘〉\n' + q.word_list.map(function(w) {
      if (!w || typeof w !== 'object') return _pdfText(w);
      var word = w.word || w.base_form || w.text || w.label || '';
      var meaning = w.meaning_ko || w.meaning || w.ko || w.definition || '';
      return word + (meaning ? ': ' + meaning : '');
    }).filter(Boolean).join('\n'));
  }
  if (Array.isArray(q.added_paragraph_word_list) && q.added_paragraph_word_list.length) {
    parts.push('【추가 단락 어휘】\n' + q.added_paragraph_word_list.map(function(w) {
      if (!w || typeof w !== 'object') return _pdfText(w);
      var word = w.word || w.base_form || w.text || w.label || '';
      var meaning = w.meaning_ko || w.meaning || w.ko || w.definition || '';
      return word + (meaning ? ': ' + meaning : '');
    }).filter(Boolean).join('\n'));
  }
  return parts.filter(Boolean).join('\n\n');
}

function _pdfProblemHtml(r, idx) {
  var q = _pdfResolveQuestion(r.question);
  var type = r.qType || r.type || q.type || '';
  var fallbackPassage = type === 'restatement_blank' ? '' : (r.passage || r.passageText || '');
  var passage = type === 'restatement_blank'
    ? (q.added_paragraph ? (r.passage || r.passageText || '') : '')
    : _pdfQuestionPassage(q, fallbackPassage);
  var bodyText = q.summary_text || q.restatement_text || '';
  var stem = q.question_stem || q.question || q.stem || q.instruction || '';
  var added = q.added_paragraph || '';
  var given = q.output_given_sentence || q.given_sentence || q.insertion_sentence || q.sentence_to_insert || q.givenSentence || '';
  var conditions = Array.isArray(q.conditions) ? q.conditions : [];
  return '<section class="problem">' +
    '<h2>' + idx + '. ' + _pdfEscape(type) + '</h2>' +
    (stem ? '<div class="stem">' + _pdfNl(stem) + '</div>' : '') +
    (given ? '<div class="subhead">주어진 문장</div><div class="passage">' + _pdfNl(given) + '</div>' : '') +
    (passage ? '<div class="passage">' + _pdfNl(passage) + '</div>' : '') +
    (bodyText ? '<div class="subhead">' + (q.summary_text ? '요약문' : '재진술문') + '</div><div class="passage">' + _pdfNl(bodyText) + '</div>' : '') +
    (added ? '<div class="subhead">추가 단락</div><div class="passage">' + _pdfNl(added) + '</div>' : '') +
    (conditions.length ? '<div class="subhead">조건</div><ol class="bogi">' + conditions.map(function(c) { return '<li>' + _pdfNl(c) + '</li>'; }).join('') + '</ol>' : '') +
    _pdfBogiRows(q) +
    _pdfWordList(q) +
    _pdfChoiceRows(q) +
  '</section>';
}

function _pdfAnswerHtml(r, idx) {
  var q = _pdfResolveQuestion(r.question);
  var type = r.qType || r.type || q.type || '';
  var answer = _pdfAnswerText(q);
  var explanation = _pdfExplanationText(q);
  return '<section class="answer">' +
    '<h2>' + idx + '. ' + _pdfEscape(type) + '</h2>' +
    (answer ? '<div class="answer-key">정답: ' + _pdfNl(answer) + '</div>' : '<div class="answer-key">정답: -</div>') +
    (explanation ? '<div class="explanation">' + _pdfNl(explanation) + '</div>' : '') +
  '</section>';
}

function _buildPdfDocumentHtml(title, results) {
  var safeTitle = _pdfEscape(title || '모의고사');
  var problems = results.map(function(r, i) { return _pdfProblemHtml(r, i + 1); }).join('\n');
  var answers = results.map(function(r, i) { return _pdfAnswerHtml(r, i + 1); }).join('\n');
  return '<!doctype html><html><head><meta charset="utf-8"><title>' + safeTitle + '</title>' +
    '<style>' +
    '@page{size:A4;margin:16mm 14mm}' +
    'body{font-family:"Malgun Gothic",Arial,sans-serif;color:#111827;line-height:1.58;font-size:12.5px}' +
    'h1{font-size:22px;text-align:center;margin:0 0 18px}' +
    'h2{font-size:15px;margin:18px 0 8px;color:#1f4e79}' +
    '.meta{text-align:center;color:#6b7280;margin-bottom:18px;font-size:11px}' +
    '.passage{font-family:"Times New Roman","Malgun Gothic",serif;background:#f7f7f7;border:1px solid #e5e7eb;padding:10px 12px;margin:8px 0 10px;white-space:normal}' +
    '.stem{font-weight:700;margin:6px 0 8px}.subhead{font-weight:700;margin:10px 0 4px}.wordbank{border:1px solid #d1d5db;padding:8px;margin:6px 0 10px}' +
    'ol{margin:6px 0 10px 24px;padding:0}.choices li,.bogi li{margin:5px 0}.problem{break-inside:avoid;page-break-inside:avoid;margin-bottom:14px}' +
    '.answers-start{break-before:page;page-break-before:always}.answer{break-inside:avoid;page-break-inside:avoid;border-bottom:1px solid #e5e7eb;padding-bottom:10px;margin-bottom:8px}' +
    '.answer-key{font-weight:800;color:#b91c1c;margin:4px 0 6px}.explanation{color:#166534;white-space:pre-wrap}' +
    '.print-note{display:none}@media screen{body{max-width:900px;margin:24px auto;padding:0 20px}.print-note{display:block;background:#eff6ff;border:1px solid #bfdbfe;color:#1d4ed8;padding:10px 12px;border-radius:8px;margin:0 0 16px}.actions{display:flex;gap:8px;justify-content:center;margin-bottom:16px}.actions button{padding:9px 16px;border:0;border-radius:8px;background:#111827;color:#fff;cursor:pointer}}' +
    '@media print{.print-note,.actions{display:none}}' +
    '</style></head><body>' +
    '<div class="print-note">인쇄 창에서 대상/프린터를 “PDF로 저장”으로 선택하면 파일로 저장됩니다.</div>' +
    '<div class="actions"><button onclick="window.__pdfPrintOpened=true;window.print()">PDF로 저장</button><button onclick="window.close()">닫기</button></div>' +
    '<h1>' + safeTitle + '</h1><div class="meta">문제</div>' +
    problems +
    '<div class="answers-start"><h1>' + safeTitle + '</h1><div class="meta">정답 및 해설</div>' +
    answers + '</div>' +
    '<script>window.addEventListener("load",function(){setTimeout(function(){if(!window.__pdfPrintOpened){window.__pdfPrintOpened=true;window.print();}},700);});<\/script>' +
    '</body></html>';
}

function _downloadPdfFromResults(title, results) {
  if (!results || !results.length) { showToast('PDF로 저장할 결과가 없습니다'); return; }
  var html = _buildPdfDocumentHtml(title, results);
  var blob = new Blob([html], { type: 'text/html;charset=utf-8' });
  var url = URL.createObjectURL(blob);
  var win = window.open(url, '_blank');
  if (!win) {
    var a = document.createElement('a');
    a.href = url;
    a.download = (title || '모의고사') + '_PDF저장용.html';
    document.body.appendChild(a); a.click(); document.body.removeChild(a);
    showToast('팝업이 차단되어 PDF 저장용 HTML을 내려받았습니다. 파일을 열고 인쇄→PDF로 저장하세요.');
  } else {
    try { win.opener = null; } catch (_) {}
    setTimeout(function(){ URL.revokeObjectURL(url); }, 5000);
    showToast('PDF 저장 창을 열었습니다');
  }
}

function downloadPdf() {
  var p = passages.find(function(x) { return x.id === selectedId; });
  if (!p || !p.results || p.results.length === 0) { showToast('PDF로 저장할 결과가 없습니다'); return; }
  var ts = new Date().toISOString().slice(0, 10);
  _downloadPdfFromResults('모의고사_' + ts, p.results.map(function(r) {
    return Object.assign({}, r, { passage: r.passage || p.text, passageText: r.passageText || p.text });
  }));
}

async function downloadAllWord() {
  const completed = passages.filter(p => p.results.length > 0);
  if (completed.length === 0) { showToast('다운로드할 결과가 없습니다'); return; }
  const allResults = [];
  completed.forEach(p => {
    const pIdx = passages.indexOf(p);
    p.results.forEach(r => allResults.push(Object.assign({}, r, { passageIdx: pIdx })));
  });
  const btn = document.getElementById('word-all-btn');
  btn.disabled = true; btn.textContent = '⏳ 생성 중...';
  try {
    const blob = await buildWordDocBlob('', allResults, new Date().toISOString().slice(0,10));
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    const ts = new Date().toISOString().slice(0,19).replace(/[:.]/g,'-');
    a.href=url; a.download=`모의고사_${ts}.docx`;
    document.body.appendChild(a); a.click(); document.body.removeChild(a);
    setTimeout(() => URL.revokeObjectURL(url), 1000);
    showToast(`✓ 전체 ${allResults.length}문항 Word 다운로드 완료`);
  } catch(e) { showToast('오류: '+e.message); }
  finally { btn.disabled=false; btn.textContent='📄 전체 Word 다운로드'; }
}

function downloadAllPdf() {
  const completed = passages.filter(p => p.results && p.results.length > 0);
  if (completed.length === 0) { showToast('PDF로 저장할 결과가 없습니다'); return; }
  const allResults = [];
  completed.forEach(p => {
    const pIdx = passages.indexOf(p) + 1;
    p.results.forEach(r => allResults.push(Object.assign({}, r, {
      qType: `지문 ${pIdx} · ${r.qType || r.type || ''}`,
      passage: r.passage || p.text,
      passageText: r.passageText || p.text,
    })));
  });
  const ts = new Date().toISOString().slice(0, 10);
  _downloadPdfFromResults(`전체_모의고사_${ts}`, allResults);
}

function _buildAllJsonData() {
  const processed = passages.filter(p => p.status === 'done' || p.status === 'error');
  if (processed.length === 0) return null;
  return processed.map((p, i) => ({
    passageIndex: i + 1,
    passageText: p.text,
    status: p.status,
    resultCount: (p.results || []).length,
    results: p.results || [],
    ...(p.status === 'error' ? { error: '모든 문항 출제 실패', errorDetails: p.errors || [] } : {})
  }));
}

function downloadAllJson() {
  const allResults = _buildAllJsonData();
  if (!allResults) { showToast('다운로드할 결과가 없습니다'); return; }
  const blob = new Blob([JSON.stringify(allResults, null, 2)], { type: 'application/json' });
  const url  = URL.createObjectURL(blob);
  const a    = document.createElement('a');
  const ts   = new Date().toISOString().slice(0, 19).replace(/[:.]/g, '-');
  a.href = url; a.download = '출제결과_' + ts + '.json';
  document.body.appendChild(a); a.click(); document.body.removeChild(a);
  setTimeout(() => URL.revokeObjectURL(url), 1000);
  const errCnt = allResults.filter(p => p.status === 'error').length;
  showToast('✓ JSON 다운로드 완료' + (errCnt > 0 ? ` (오류 ${errCnt}개 포함)` : ''));
}

function openJsonView() {
  const data = _buildAllJsonData();
  if (!data) { showToast('표시할 결과가 없습니다'); return; }
  const pre = document.getElementById('json-pre');
  const modal = document.getElementById('json-modal');
  if (pre) pre.textContent = JSON.stringify(data, null, 2);
  if (modal) modal.style.display = 'flex';
}

function closeJsonView() {
  const modal = document.getElementById('json-modal');
  if (modal) modal.style.display = 'none';
}

function copyAllJson() {
  const pre = document.getElementById('json-pre');
  if (!pre || !pre.textContent) return;
  navigator.clipboard.writeText(pre.textContent).then(function() {
    const btn = document.getElementById('json-copy-btn');
    if (btn) { btn.textContent = '✓ 복사됨'; setTimeout(function() { btn.textContent = '전체 복사'; }, 2000); }
    showToast('클립보드에 복사됨');
  }).catch(function() {
    const ta = document.createElement('textarea');
    ta.value = pre.textContent;
    document.body.appendChild(ta); ta.select(); document.execCommand('copy'); document.body.removeChild(ta);
    showToast('클립보드에 복사됨');
  });
}

/* ── 전체 완료 뷰 ── */
function showCombinedResults(donePasgs) {
  selectedId = null;
  const totalQ = donePasgs.reduce((s, p) => s + p.results.length, 0);
  const rp = document.getElementById('right-panel');
    rp.innerHTML = `
    <div class="card" style="border:2px solid var(--grn-bd)">
      <div class="card-hd" style="background:var(--grn-lt)">
        <span style="color:var(--grn);font-weight:700">✓ 전체 출제 완료</span>
        <span class="aux">${donePasgs.length}개 지문 · 총 ${totalQ}문항</span>
      </div>
      <div style="padding:12px 16px;display:flex;flex-direction:column;gap:8px;align-items:center">
        <button id="combined-dl-btn" onclick="downloadAllWord()"
          style="padding:12px 32px;border-radius:12px;background:var(--grn);color:#fff;font-size:13px;font-weight:600;border:none;cursor:pointer;width:100%">
          📄 전체 Word 다운로드 (${totalQ}문항)
        </button>
        <button id="combined-pdf-btn" onclick="downloadAllPdf()"
          style="padding:12px 32px;border-radius:12px;background:#111827;color:#fff;font-size:13px;font-weight:600;border:none;cursor:pointer;width:100%">
          🖨️ 전체 PDF로 저장 (${totalQ}문항)
        </button>
        <div style="margin-top:-2px;color:var(--mut);font-size:11px;line-height:1.5;text-align:center">
          PDF는 문제를 먼저, 정답 및 해설을 뒤쪽에 분리해 저장합니다.
        </div>
        <button onclick="openJsonView()"
          style="padding:10px 32px;border-radius:12px;background:#0F766E;color:#fff;font-size:13px;font-weight:600;border:none;cursor:pointer;width:100%">
          { } JSON 보기 · 전체 복사
        </button>
        <button onclick="openInspect()"
          style="padding:10px 32px;border-radius:12px;background:var(--purp);color:#fff;font-size:13px;font-weight:600;border:none;cursor:pointer;width:100%">
          🔍 개선사항 확인
        </button>
      </div>
    </div>
    <div id="combined-cards"></div>`;

  const container = document.getElementById('combined-cards');
  donePasgs.forEach(p => {
    const pHeader = document.createElement('div');
    pHeader.className = 'card';
    pHeader.style.cssText = 'margin-top:10px';
    pHeader.innerHTML = `<div class="card-hd"><span>지문 ${passages.indexOf(p)+1}</span><span class="aux">${p.results.length}문항</span></div>`;
    container.appendChild(pHeader);
    p.results.forEach(r => {
      const card = buildResultCard(r.qType, _withResultParams(r.question, r), r.passage || p.text, r.originalText || p.originalText);
      card.style.marginTop = '6px';
      container.appendChild(card);
    });
  });
}

/* ── 결과 카드 ── */
const _ORIG_PASSAGE_TYPES = new Set(['어휘', '빈칸A형', '빈칸A-1형']);
const _GRAMMAR_SUBJ_RENDER_TYPES = new Set(['어법수정', '어법수정(DC)', '어법재작성', '어법배열', '어법구문영작', '어법어형']);
function _renderGrammarSubjective(qType, q) {
  let html = '';
  // 발문(instruction)은 buildResultCard headStem(지문 위)에서 출력됨
  const markedPassage = q?.passage_with_marks ?? q?.passage_with_blanks;
  if (markedPassage) {
    const title = q?.passage_with_blanks ? '【빈칸 지문】' : '【문제 지문】';
    html += `<div style="font-size:11px;font-weight:600;color:#6B7280;margin-bottom:4px">${title}</div>`;
    html += `<div style="font-size:11px;line-height:1.8;white-space:pre-wrap;border:1px solid #E5E7EB;border-radius:8px;padding:10px 12px;margin-bottom:10px;font-family:'Times New Roman',serif">${escH(markedPassage)}</div>`;
  }
  if (Array.isArray(q?.items) && q.items.length) {
    html += `<div class="r-expl">정답 및 해설</div>`;
    html += `<div class="r-blanks">`;
    _normalizeGrammarSubjectiveItems(q.items, markedPassage).forEach(it => {
      html += `<div class="blank-item" style="display:block;line-height:1.65">`;
      html += `<div>(${escH(it.id)})`;
      if (it.prompt) html += ` <span style="color:#374151">${escH(it.prompt)}</span>`;
      if (it.isError === false) html += ` <span style="font-size:10px;color:#059669">올바름</span>`;
      html += `</div>`;
      if (it.wordBank.length) html += `<div style="margin-left:18px;color:#6B7280">보기: ${it.wordBank.map(x => escH(String(x))).join(' / ')}</div>`;
      if (it.requiredConstruction) html += `<div style="margin-left:18px;color:#6B7280">구문: ${escH(it.requiredConstruction)}</div>`;
      if (it.answer) html += `<div style="margin-left:18px"><strong style="color:#059669">정답:</strong> ${escH(it.answer)}</div>`;
      if (it.grammarPoint) html += `<div style="margin-left:18px;font-size:10px;color:#9CA3AF">[${escH(it.grammarPoint)}]</div>`;
      if (it.reason) html += `<div style="margin-left:18px;color:#4B5563">${escH(it.reason)}</div>`;
      html += `</div>`;
    });
    html += `</div>`;
  }
  if (!q?.instruction && !markedPassage && !q?.items) {
    html = `<div class="r-raw"><pre>${escH(JSON.stringify(q,null,2))}</pre></div>`;
  }
  return html;
}
function _escapeRegExpLiteral(text) {
  return String(text || '').replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}
function _startsWithBlankLabel(text, id) {
  var label = _escapeRegExpLiteral(id);
  return new RegExp('^\\s*(?:\\(' + label + '\\)|（' + label + '）|' + label + '(?:[\\).:]|번))').test(String(text || '').trim());
}
function _startsWithAnswerItemLabel(text, id) {
  var label = _escapeRegExpLiteral(id);
  return new RegExp('^\\s*' + label).test(String(text || '').trim());
}
function _wordOrderDisplayedPassage(question, passageText) {
  if (!passageText) return passageText;
  const blank = question?.blank_line || '______________________________________________';
  const range = String(question?.underline_range || '').trim();
  const sentence = String(question?.target_sentence || question?.source_sentence || '').trim();
  if (question?.passage_displayed) {
    // LLM이 range가 아닌 target_sentence 전체를 blank 처리했는지 검증
    // range가 존재하고 target_sentence의 부분 구간인 경우에만 검사
    if (range && sentence && range !== sentence.replace(/[.!?]\s*$/, '') && range !== sentence && sentence.includes(range)) {
      const outsideRange = sentence.replace(range, '').trim();
      const firstToken = outsideRange.split(/\s+/).find(function(w) { return w.replace(/[^a-zA-Z]/g, '').length > 2; });
      if (firstToken && !question.passage_displayed.includes(firstToken)) {
        // 과잉 blank 감지 — underline_range만 blank로 복구
        if (passageText.includes(range)) return passageText.replace(range, blank);
        if (passageText.includes(sentence)) return passageText.replace(sentence, sentence.replace(range, blank));
      }
    }
    return question.passage_displayed;
  }
  if (question?.passage_with_blank) return question.passage_with_blank;
  if (question?.passage_with_blanks) return question.passage_with_blanks;
  if (range && passageText.includes(range)) return passageText.replace(range, blank);
  if (!sentence) return passageText;
  const display = question?.display_sentence || question?.sentence_with_blank || question?.blanks_text;
  if (display && passageText.includes(sentence)) return passageText.replace(sentence, display);
  if (range && sentence.includes(range) && passageText.includes(sentence)) {
    return passageText.replace(sentence, sentence.replace(range, blank));
  }
  const sentenceNoPeriod = sentence.replace(/[.!?]\s*$/, '');
  if (sentenceNoPeriod && passageText.includes(sentenceNoPeriod)) return passageText.replace(sentenceNoPeriod, blank);
  return passageText.replace(new RegExp(_escapeRegExpLiteral(sentence)), blank);
}
function _withResultParams(question, result) {
  if (!question || typeof question !== 'object') return question;
  const params = Object.assign({}, (result && result.params) || {}, question.params || {});
  if (params.vocab_level == null && params.vocabLevel == null && result && result.vocabLevel != null) {
    params.vocab_level = result.vocabLevel;
    params.vocabLevel = result.vocabLevel;
  }
  return Object.assign({}, question, { params });
}

function buildResultCard(qType, question, passageText, originalText) {
  const rawQ = question || {};
  const normalizedType = _normalizeGrammarQuestionType({ type: qType, params: rawQ?.params });
  const renderType = normalizedType.type || qType;
  const q = _normalizeQuestionForOutput(renderType, rawQ, passageText, rawQ?.params || {});
  const isSubj = SUBJ_SET.has(renderType);
  const isCI = CI_SET.has(renderType);
  const label  = SUBJ_LABELS[renderType] ?? renderType;
  const bc = isSubj ? (renderType==='word_order_blank'||renderType==='new_order_blank' ? 'b-wo' : 'b-subj') : 'b-obj';
  const printable = _usesPrintableQuestion(renderType) ? _toPrintableQuestion(renderType, q, passageText, q?.params) : null;
  const passageParts = _buildOutputPassageParts(renderType, q, passageText, printable);
  const hasAddedPara = !!passageParts.addedParagraph;
  const showP = (renderType !== 'restatement_blank' || hasAddedPara) && (passageParts.passage || passageParts.addedParagraph);
  const passageLabel = (renderType === 'restatement_blank' && hasAddedPara) ? '원문' : '지문';
  const showOrig = originalText && originalText !== passageText;
  const displayedPassage = renderType === 'word_order_blank' ? _wordOrderDisplayedPassage(q, passageParts.passage) : passageParts.passage;
  // 발문은 지문 위에 출력 (어법 주관식 포함 — 헬퍼 내부 instruction 렌더는 제거됨)
  const _headStem = isCI ? ((q?.question || q)?.prompt_text)
    : isSubj ? q?.instruction
    : (q?.question_stem ?? q?.question ?? q?.stem);
  let inner = _headStem ? `<div class="r-stem">${escH(_headStem)}</div>` : '';
  if (passageParts.givenSentence) {
    inner += `<div style="font-size:11px;font-weight:600;color:#6B7280;margin-bottom:4px">【주어진 문장】</div>
       <div style="font-size:11px;line-height:1.8;white-space:pre-wrap;border:1px solid #E5E7EB;border-radius:8px;padding:10px 12px;margin-bottom:12px;font-family:'Times New Roman',serif">${escH(passageParts.givenSentence)}</div>`;
  }
  inner += showP
    ? `<div style="font-size:11px;font-weight:600;color:#6B7280;margin-bottom:4px">${passageLabel}</div>
       <div style="font-size:11px;line-height:1.8;white-space:pre-wrap;border:1px solid #E5E7EB;border-radius:8px;padding:10px 12px;margin-bottom:12px;font-family:'Times New Roman',serif">${escH(displayedPassage)}</div>` : '';
  const maxWarningText = _maxAttractivenessWarningText(q);
  if (maxWarningText) {
    inner += `<div style="font-size:11px;line-height:1.6;background:#FFFBEB;border:1px solid #F59E0B;border-radius:8px;padding:8px 10px;margin-bottom:12px;color:#92400E">최상 검증 경고 ${escH(maxWarningText)}</div>`;
  }
  const grammarWarningText = _grammarCatalogWarningText(q);
  if (grammarWarningText) {
    inner += `<div style="font-size:11px;line-height:1.6;background:#EFF6FF;border:1px solid #60A5FA;border-radius:8px;padding:8px 10px;margin-bottom:12px;color:#1D4ED8">어법 검수 경고 ${escH(grammarWarningText)}</div>`;
  }
  const vocabWarningText = _vocabAuditWarningText(q);
  if (vocabWarningText) {
    inner += `<div style="font-size:11px;line-height:1.6;background:#FEF2F2;border:1px solid #EF4444;border-radius:8px;padding:8px 10px;margin-bottom:12px;color:#B91C1C">어휘 수준 경고 ${escH(vocabWarningText)}</div>`;
  }
  if (showOrig) {
    inner += `<div style="font-size:11px;font-weight:600;color:#6B7280;margin-bottom:4px">원문</div>
      <div style="font-size:11px;line-height:1.8;white-space:pre-wrap;border:1px solid #E5E7EB;border-radius:8px;padding:10px 12px;margin-bottom:12px;font-family:'Times New Roman',serif">${escH(originalText)}</div>`;
  }
  let addedParaMeta = '';
  if (hasAddedPara) {
    inner += `<div style="font-size:11px;font-weight:600;color:#6B7280;margin-bottom:4px">추가 단락</div>
      <div style="font-size:11px;line-height:1.8;white-space:pre-wrap;border:1px solid #E5E7EB;border-radius:8px;padding:10px 12px;margin-bottom:12px;font-family:'Times New Roman',serif">${escH(passageParts.addedParagraph)}</div>`;
    const addedTranslationKo = printable?.addedParagraph?.translationKo ?? q.added_paragraph_translation_ko;
    if (addedTranslationKo) {
      addedParaMeta += `<div class="r-expl">【추가 단락 해석】</div><div class="r-expl-logic" style="white-space:pre-wrap">${escH(addedTranslationKo)}</div>`;
    }
  }
  let renderedWordList = false;
  if (q?.raw) { inner = `<div class="r-raw"><pre>${escH(JSON.stringify(q,null,2))}</pre></div>`; }
  else if (isCI) {
    const qd = q?.question || q; // nested question object
    const expl = q?.explanation || {};
    const CIRC5 = ['①','②','③','④','⑤'];
    if (qd.concept_name) inner += `<div style="font-size:11px;font-weight:700;color:#7C3AED;margin-bottom:6px">개념: ${escH(qd.concept_name)}</div>`;
    // 발문(prompt_text)은 지문 위에서 이미 출력됨

    // ── 추가 문장 표시 (지문확장 20%) ──
    const addedSents = qd.passage_added_sentences;
    if (Array.isArray(addedSents) && addedSents.length) {
      inner += `<div style="margin-bottom:10px">`;
      inner += `<div style="font-size:11px;font-weight:600;color:#7C3AED;margin-bottom:4px">【추가된 문장 (원문 대비 +20%)】</div>`;
      inner += `<div style="background:#F5F3FF;border:1px solid #DDD6FE;border-radius:8px;padding:10px 12px">`;
      addedSents.forEach((s, i) => {
        inner += `<div style="margin-bottom:${i < addedSents.length-1 ? '8px' : '0'}">`;
        inner += `<div style="font-size:11px;font-family:'Times New Roman',serif;line-height:1.7;color:#1F2937">${escH(s.en || '')}</div>`;
        if (s.ko) inner += `<div style="font-size:10px;color:#6B7280;margin-top:2px">→ ${escH(s.ko)}</div>`;
        inner += `</div>`;
      });
      inner += `</div></div>`;
    }

    const choices = qd.choices;
    if (Array.isArray(choices)) {
      inner += `<div class="r-choices">`;
      choices.forEach((c, i) => {
        const sym = c.sym || CIRC5[i] || (i+1);
        const txt = escH(_stripStudentPatternLabels(_objChoiceText(c)));
        const isAns = c.isAnswer === true;
        const isFromAdded = c.from_added === true;
        inner += `<div class="r-choice" style="${isAns ? 'font-weight:700;color:#059669' : ''}${isFromAdded ? ';border-left:2px solid #7C3AED;padding-left:6px' : ''}">`;
        inner += `${typeof sym==='number' ? CIRC5[sym-1]||sym : sym} ${txt}`;
        if (isFromAdded) inner += ` <span style="font-size:9px;color:#7C3AED;margin-left:4px">★추가</span>`;
        if (isAns) inner += ` ✓`;
        inner += `</div>`;
        // 추가 문장 기반 선지의 해설
        if (isFromAdded && c.added_explanation) {
          inner += `<div>${escH(_stripStudentPatternLabels(c.added_explanation))}</div>`;
        }
      });
      inner += `</div>`;
      // answer number
      const ansChoice = choices.find(c => c.isAnswer);
      if (ansChoice) {
        const ansNum = ansChoice.num != null ? (CIRC5[ansChoice.num-1] || ansChoice.num) : (ansChoice.sym || '');
        inner += `<div class="r-answer">정답: ${escH(String(ansNum))}</div>`;
      }
    }
    if (expl.structure) inner += `<div class="r-expl" style="margin-top:8px">지문 구조: ${escH(_stripStudentPatternLabels(expl.structure))}</div>`;
    if (expl.answer_reason) inner += `<div class="r-expl">정답 근거: ${escH(_stripStudentPatternLabels(expl.answer_reason))}</div>`;
    if (expl.wrong_choices?.length) {
      inner += `<div class="r-expl">오답 분석: `;
      expl.wrong_choices.forEach(wc => { inner += `<div style="margin-left:8px">${escH(String(wc.num||wc.sym||''))} ${escH(_stripStudentPatternLabels(wc.note||''))}</div>`; });
      inner += `</div>`;
    }
    if (!qd.prompt_text && !qd.choices) inner = `<div class="r-raw"><pre>${escH(JSON.stringify(q,null,2))}</pre></div>`;
  } else if (_GRAMMAR_SUBJ_RENDER_TYPES.has(renderType)) {
    inner += _renderGrammarSubjective(renderType, q);
  } else if (isSubj) {
    // 발문(instruction)은 지문 위에서 이미 출력됨
    if (q?.conditions?.length) { inner += `<div class="r-conditions">`; q.conditions.forEach((c,i) => inner+=`${i+1}. ${escH(c)}<br>`); inner+=`</div>`; }
    const bt = q?.summary_text ?? (renderType === 'restatement_blank' ? _restatementTextWithAddedParagraphBreak(q) : q?.restatement_text);
    if (bt) inner += `<div class="r-body">${escH(bt).replace(/\n\n+/g, '<br><br>').replace(/\n/g, '<br>')}</div>`;
    const bk = q?.chunks_shuffled ?? q?.chunking_items ?? q?.hint_words ?? (renderType === 'word_order_blank' ? q?.word_bank : null);
    if (bk?.length) inner += `<div class="r-wordbank">보기: ${bk.map(w=>escH(_wordItemText(w))).join(' / ')}</div>`;
    if (q?.wordbank_items?.length) inner += `<div class="r-wordbank">보기: ${q.wordbank_items.map(w=>escH(_wordItemText(w))).join(' / ')}</div>`;
    const answerGloss = printable?.answerGloss || q?.answer_gloss || q?.answer_translation_ko || '';
    if (q?.answer_key) inner+=`<div class="r-answer">${escH(_answerKeyText(q.answer_key))}${answerGloss ? ' (' + escH(answerGloss) + ')' : ''}</div>`;
    else if (q?.answer && typeof q.answer==='string') inner+=`<div class="r-answer">${escH(q.answer)}${answerGloss ? ' (' + escH(answerGloss) + ')' : ''}</div>`;
    const wantsWordOrderExplanation = (q?.params?.explanation !== false);
    const wordOrderExpl = wantsWordOrderExplanation && (renderType === 'word_order_blank' || renderType === 'new_order_blank') ? (printable?.explanation || q?.explanation_logic || q?.explanation) : null;
    if (wordOrderExpl) {
      const explanationMeta = printable?.explanationMeta || q?.explanation_meta || q?.explanationMeta || '';
      inner += `<div class="r-expl">[??]${explanationMeta ? ' ' + escH(explanationMeta) : ''}</div>`;
      const grammarPattern = printable?.grammarPattern || q.grammar_pattern;
      if (grammarPattern) inner += `<div class="r-expl">????: ${escH(grammarPattern)}</div>`;
      inner += `<div class="r-expl-logic">${escH(wordOrderExpl)}</div>`;
    }
    const hasDetailedBlankExplanationType = renderType === 'summary_blank' || renderType === 'restatement_blank';
    const blankExplanationIntro = hasDetailedBlankExplanationType ? (q?.explanation_summary || q?.explanation_logic || q?.explanation) : null;
    const hasDetailedBlankExplanations = hasDetailedBlankExplanationType && (blankExplanationIntro || q?.blanks?.some(b => b?.explanation));
    if (hasDetailedBlankExplanations) {
      inner += `<div class="r-expl">[??]</div>`;
      if (blankExplanationIntro) inner += `<div class="r-expl-logic">${escH(blankExplanationIntro)}</div>`;
      inner += `<div class="r-blanks">`;
      q.blanks?.forEach(b => {
        const detail = b.explanation || String(b.answer ?? '');
        const label = `(${String(b.id)})`;
        inner += `<div class="blank-item">${escH(_startsWithBlankLabel(detail, b.id) ? String(detail) : label + ' ' + String(detail))}</div>`;
      });
      inner += `</div>`;
    } else if (q?.blanks?.length) {
      inner += `<div class="r-blanks">`;
      q.blanks.forEach(b => { inner+=`<span class="blank-item">(${escH(String(b.id))}) ${escH(String(b.answer ?? ''))}</span>`; });
      inner += `</div>`;
    }
    if (renderType === 'understanding_sm' && q?.answer_items?.length) {
      inner += `<div class="r-blanks">`;
      q.answer_items.forEach(it => {
        inner += `<div class="blank-item">${escH(String(it.id||''))} [${escH(String(it.label||''))}] ${escH(String(it.model_answer||''))}`;
        if (it.char_limit) inner += ` (${it.char_limit}자)`;
        inner += `</div>`;
        if (it.alt_answers?.length) inner += `<div>대안: ${it.alt_answers.map(escH).join(' / ')}</div>`;
      });
      inner += `</div>`;
      const smExplanationIntro = q?.explanation_summary || q?.explanation_logic || q?.explanation;
      const hasSmExplanations = smExplanationIntro || q.answer_items.some(it => it?.explanation);
      if (hasSmExplanations) {
        inner += `<div class="r-expl">[??]</div>`;
        if (smExplanationIntro) inner += `<div class="r-expl-logic">${escH(smExplanationIntro)}</div>`;
        inner += `<div class="r-blanks">`;
        q.answer_items.forEach(it => {
          if (!it?.explanation) return;
          const detail = String(it.explanation);
          inner += `<div class="blank-item">${escH(_startsWithAnswerItemLabel(detail, it.id) ? detail : String(it.id || '') + ' ' + detail)}</div>`;
        });
        inner += `</div>`;
      }
      if (q.grading_criteria) {
        const gc = q.grading_criteria;
        if (gc.required_elements?.length) inner += `<div class="r-expl">필수: ${gc.required_elements.map(escH).join(' / ')}</div>`;
        if (gc.zero_score?.length) inner += `<div class="r-expl">0점: ${gc.zero_score.map(escH).join(' / ')}</div>`;
      }
    }
  } else {
    const stem = q?.question_stem ?? q?.question ?? q?.stem;
    if (printable?.keyword) inner += `<div style="font-size:11px;font-weight:600;color:#2563EB;margin-bottom:6px">핵심어: ${escH(printable.keyword)}</div>`;
    const direction = _printableDirectionLabel(printable?.direction);
    if (direction) inner += `<div style="font-size:11px;font-weight:600;color:#2563EB;margin-bottom:6px">방향: ${escH(direction)}</div>`;
    // 발문(stem)은 지문 위에서 이미 출력됨
    const summaryText = printable?.summaryText ?? q?.summary_text;
    if (summaryText) inner += `<div class="r-body">${escH(summaryText)}</div>`;
    if (printable?.markedItems?.length) {
      inner += `<div class="r-stem">표시 어휘</div><div class="r-choices">`;
      printable.markedItems.forEach(item => {
        const state = item.isAppropriate === true ? '적절' : item.isAppropriate === false ? '부적절' : '';
        const replacement = item.replacement ? ` → ${item.replacement}` : '';
        inner += `<div class="r-choice">${escH(String(item.id ?? ''))}. ${escH(String(item.word ?? ''))}${state ? ` (${escH(state)})` : ''}${escH(replacement)}</div>`;
      });
      inner += `</div>`;
    }
    const bogiRows = printable?.bogi ?? q?.bogi;
    if (bogiRows?.length) {
      inner += `<div class="r-stem">&lt;보기&gt;</div><div class="r-choices">`;
      bogiRows.forEach(item => {
      const grammarCase = printable && item.grammarCase ? ` (${escH(item.grammarCase)})` : '';
        inner += `<div class="r-choice">${escH(String(item.id ?? ''))}. ${escH(String(item.text ?? ''))}${grammarCase}</div>`;
      });
      inner += `</div>`;
    }
    const choices = _normalizeOutputChoices(renderType, q);
    if (Array.isArray(choices)) {
      inner += `<div class="r-choices">`;
      choices.forEach((c,i) => {
        const raw = _stripStudentPatternLabels(_objChoiceText(c));
        const s = escH(raw);
        inner += `<div class="r-choice">${/^[①②③④⑤]/.test(raw.trim()) ? s : CIRC[i]+' '+s}</div>`;
      });
      inner += `</div>`;
    }
    if (q?.answer != null) {
      const ans = typeof q.answer==='number' ? (CIRC[q.answer-1]??q.answer) : q.answer;
      const answerEn = q.explanation_correct_en || '';
      const answerKo = q.explanation_correct_ko || '';
      const answerInline = answerEn ? ` ${escH(answerEn)}${answerKo ? ` (${escH(answerKo)})` : ''}` : '';
      inner += `<div class="r-answer">[정답] ${escH(String(ans))}${answerInline}</div>`;
    }
    const answerCount = printable?.answerCount ?? null;
    if (answerCount != null) inner += `<div class="r-answer">정답 개수: ${escH(String(answerCount))}개</div>`;
    if (q?.passage_translation_ko) {
      inner += `<div class="r-expl">〈해석〉</div><div class="r-expl-logic" style="white-space:pre-wrap">${escH(q.passage_translation_ko)}</div>`;
    }
    // ── 풀패키지 해설 렌더링 ──
    const isFullPkg = q?.explanation_logic != null || q?.explanation_connections != null;
    if (isFullPkg) {
      if (q.explanation_logic) inner += `<div class="r-expl">해설</div><div class="r-expl-logic">${escH(_stripStudentPatternLabels(q.explanation_logic))}</div>`;
      // 순서 유형
      if (q.explanation_full_order) inner += `<div class="r-expl-order">순서: ${escH(q.explanation_full_order)}</div>`;
      if (q.explanation_flow) inner += `<div class="r-expl-flow">${escH(q.explanation_flow)}</div>`;
      if (Array.isArray(q.explanation_connections) && q.explanation_connections.length) {
        inner += `<div class="r-expl-connections">`;
        q.explanation_connections.forEach(conn => {
          inner += `<div class="r-conn-item"><span class="r-conn-from">${escH(conn.from??'')}</span><span class="r-conn-arrow">→</span><span class="r-conn-to">${escH(conn.to??'')}</span><span class="r-conn-reason">${escH(conn.reason??'')}</span></div>`;
        });
        inner += `</div>`;
      }
      // 삽입 / 무관한문장 유형: 문장 컨텍스트
      if (q.explanation_given_en || q.explanation_given_ko) {
        inner += `<div class="r-expl-ctx">주어진 문장: ${escH(q.explanation_given_en??'')} <span class="r-ctx-ko">${escH(q.explanation_given_ko??'')}</span></div>`;
      }
      if (q.explanation_prev_en || q.explanation_prev_ko) {
        inner += `<div class="r-expl-ctx">직전: ${escH(q.explanation_prev_en??'')} <span class="r-ctx-ko">${escH(q.explanation_prev_ko??'')}</span></div>`;
      }
      if (q.explanation_next_en != null && q.explanation_next_en !== '') {
        inner += `<div class="r-expl-ctx">직후: ${escH(q.explanation_next_en)} <span class="r-ctx-ko">${escH(q.explanation_next_ko??'')}</span></div>`;
      }
      if (q.explanation_target_en || q.explanation_target_ko) {
        inner += `<div class="r-expl-ctx r-expl-target">무관 문장: ${escH(q.explanation_target_en??'')} <span class="r-ctx-ko">${escH(q.explanation_target_ko??'')}</span></div>`;
      }
      if (q.explanation_caution) inner += `<div class="r-expl-caution">주의: ${escH(q.explanation_caution)}</div>`;
      // 정답 선지 영어/한국어 해석은 정답 바로 아래로 이동됨
      // 어휘 유형: 오답→정답 어휘
      if (q.explanation_wrong_word || q.explanation_correct_word) {
        inner += `<div class="r-expl-vocab"><span class="r-vocab-wrong">✗ ${escH(q.explanation_wrong_word??'')}</span> → <span class="r-vocab-correct">✓ ${escH(q.explanation_correct_word??'')}</span></div>`;
      }
      // 오답 분석 (토글)
      if (Array.isArray(q.explanation_wrong) && q.explanation_wrong.length) {
        const ewId = 'ew-' + Math.random().toString(36).slice(2,8);
        inner += `<button class="r-toggle-btn" onclick="var el=document.getElementById('${ewId}');el.classList.toggle('r-hidden');this.textContent=el.classList.contains('r-hidden')?'오답 분석 ▼':'오답 분석 ▲'">오답 분석 ▼</button>`;
        inner += `<div id="${ewId}" class="r-expl-wrong-list r-hidden">`;
        q.explanation_wrong.forEach(w => {
          const num = typeof w==='object' ? (w.num??'') : String(w).slice(0,1);
          const reason = typeof w==='object' ? (w.reason??'') : String(w).slice(1).trim();
          const cleanReason = _stripStudentPatternLabels(reason);
          const choicePrefix = _wrongAnalysisChoicePrefix(renderType, q, w, num, choices);
          const label = choicePrefix || String(num);
          inner += `<div class="r-wrong-item"><span class="r-wrong-num">${escH(label)}</span><span class="r-wrong-reason">${escH(cleanReason)}</span></div>`;
        });
        inner += `</div>`;
      }
      // 어휘 목록 (토글)
      const fullPackageWordList = _normalizeOutputWordList(q, printable);
      if (fullPackageWordList.length) {
        renderedWordList = true;
        const wlId = 'wl-' + Math.random().toString(36).slice(2,8);
        inner += `<button class="r-toggle-btn r-toggle-word" onclick="var el=document.getElementById('${wlId}');el.classList.toggle('r-hidden');this.textContent=el.classList.contains('r-hidden')?'단어 ▼':'단어 ▲'">단어 ▼</button>`;
        inner += `<div id="${wlId}" class="r-word-list r-hidden">`;
        fullPackageWordList.forEach(w => {
          inner += `<div class="r-word-item"><span class="r-word-en">${escH(w.word??'')}</span><span class="r-word-ko">${escH(w.meaning??'')}</span>`;
          const related = w.origin_word || w.related_word;
          if (related && w.relation) {
            const relLabel = w.relation === 'synonym' ? '유의어' : '반의어';
            inner += `<span class="r-word-syn">(${escH(related)}의 ${relLabel})</span>`;
          }
          inner += `</div>`;
        });
        inner += `</div>`;
      }
    } else {
      // 레거시 fallback (기존 데이터 호환)
      const expl = printable?.explanation ?? q?.explanation_correct ?? q?.explanation ?? q?.commentary ?? q?.reasoning ?? q?.explanation_summary;
      if (expl) inner += `<div class="r-expl">${escH(expl)}</div>`;
    }
    const explanationBogiRows = printable?.explanationBogi ?? q?.explanation_bogi;
    if (explanationBogiRows?.length) {
      inner += `<div class="r-expl">보기 해설</div>`;
      explanationBogiRows.forEach(item => { inner += `<div class="r-expl">${escH(String(item.id ?? ''))}. ${escH(String(item.reason ?? ''))}</div>`; });
    }
    const explanationChoiceRows = printable?.explanationChoices ?? null;
    if (explanationChoiceRows?.length) {
      inner += `<div class="r-expl">선지 해설</div>`;
      explanationChoiceRows.forEach(item => {
        const state = item.isCorrect === true ? '정답' : item.isCorrect === false ? '오답' : '';
        inner += `<div class="r-expl">${escH(String(item.num ?? ''))}. ${state ? `(${escH(state)}) ` : ''}${escH(String(item.reason ?? ''))}</div>`;
      });
    }
    if (!stem && !choices) inner = `<div class="r-raw"><pre>${escH(JSON.stringify(q,null,2))}</pre></div>`;
  }
  const finalWordList = _normalizeOutputWordList(q, printable);
  if (!renderedWordList && finalWordList.length) {
    inner += `<button class="r-toggle-btn r-toggle-word" onclick="var el=this.nextElementSibling;el.classList.toggle('r-hidden');this.textContent=el.classList.contains('r-hidden')?'단어 ▼':'단어 ▲'">단어 ▼</button>`;
    inner += `<div class="r-word-list r-hidden">`;
    finalWordList.forEach(w => {
      inner += `<div class="r-word-item"><span class="r-word-en">${escH(w.word??'')}</span><span class="r-word-ko">${escH(w.meaning??'')}</span>`;
      const related = w.origin_word || w.related_word;
      if (related && w.relation) {
        const relLabel = w.relation === 'synonym' ? '유의어' : '반의어';
        inner += `<span class="r-word-syn">(${escH(related)}의 ${relLabel})</span>`;
      }
      inner += `</div>`;
    });
    inner += `</div>`;
  }
  inner += addedParaMeta;
  const card = document.createElement('div');
  card.className = 'card'; card.style.marginBottom = '10px';
  card.innerHTML = `<div class="card-hd"><span>${label}</span><span class="badge ${bc}">${isSubj?'서답형':'객관식'}</span></div>
    <div style="padding:12px 16px">${inner}</div>`;
  return card;
}

function renderResultCard(qType, question, passageText) {
  const card = buildResultCard(qType, question, passageText);
  const rc = document.getElementById('result-cards');
  if (rc) { rc.appendChild(card); card.scrollIntoView({behavior:'smooth',block:'nearest'}); }
}

/* ── 유틸 ── */
function escH(s) { return String(s==null?'':s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;'); }
function _toPrintableQuestion(qType, question, passageText, params) {
  const q = _normalizeQuestionForOutput(qType, question || {}, passageText, params || (question && question.params) || {});
  const printableParams = params || q.params || {};
  const explanation = printableParams.explanation === false
    ? ''
    : (qType === 'word_order_blank' || qType === 'new_order_blank')
      ? _printableString(q.explanation_logic || q.explanation || q.explanation_correct || q.commentary || q.reasoning || q.explanation_summary)
      : _printableString(q.explanation ?? q.explanation_correct ?? q.explanation_summary);
  return {
    type: qType,
    passage: passageText || '',
    passageDisplayed: q.passage_displayed ?? passageText ?? '',
    prompt: q.prompt ?? q.question ?? q.stem ?? '',
    choices: _normalizePrintableChoices(q.output_suppress_choices === true ? [] : (q.output_choices ?? q.choices ?? q.options)),
    bogi: _normalizePrintableGrammarRows(q.bogi, qType),
    grammarMarks: _normalizePrintableGrammarRows(q.grammar_marks),
    summaryText: _printableString(q.summary_text),
    markedItems: _normalizePrintableMarkedItems(q.marked_items),
    direction: _printableString(q.direction),
    keyword: _printableString(q.keyword),
    level: _printableString(q.level),
    answer: q.answer ?? q.answer_key ?? q.answerKey ?? '',
    answerGloss: _printableString(q.answer_gloss ?? q.answer_translation_ko ?? q.korean_interpretation),
    answerCount: typeof q.answer_count === 'number' ? q.answer_count : null,
    explanation,
    explanationMeta: _wordOrderExplanationMeta(qType, q, printableParams) || _printableString(q.explanation_meta ?? q.explanationMeta),
    grammarPattern: _printableString(q.grammar_pattern),
    explanationBogi: _normalizePrintableExplanationRows(q.explanation_bogi),
    explanationChoices: _normalizePrintableExplanationChoices(q.explanation_choices),
    addedParagraph: {
      text: _printableString(q.added_paragraph),
      translationKo: _printableString(q.added_paragraph_translation_ko),
      wordList: _normalizePrintableWordList(q.added_paragraph_word_list),
    },
  };
}
function _wordOrderExplanationMeta(qType, q, params) {
  if (params && params.explanation === false) return '';
  if (qType !== 'word_order_blank' && qType !== 'new_order_blank') return '';
  const length = (params && params.length) ?? (q && q.params && q.params.length);
  const difficulty = _wordOrderExplanationDifficulty(length);
  const vocabLevel = (params && (params.vocab_level ?? params.vocabLevel)) ?? (q && q.params && (q.params.vocab_level ?? q.params.vocabLevel));
  const vocabLabel = _wordOrderExplanationVocabLevel(vocabLevel);
  const transformed = qType === 'new_order_blank'
    ? !!((params && params.morph_change) ?? (q && q.params && q.params.morph_change) ?? (q && q.morph_change))
    : !!((params && params.transform) ?? (params && params.morph_change) ?? (q && q.params && q.params.transform) ?? (q && q.params && q.params.morph_change) ?? (q && q.transform) ?? (q && q.morph_change));
  return '\uC5B4\uC21C\uBC30\uC5F4(' + difficulty + '), \uC5B4\uD718' + vocabLabel + ', ' + (transformed ? '\uC5B4\uD615\uBCC0\uD615' : '\uBCC0\uD615X');
}
function _wordOrderExplanationAnswerText(value) {
  if (value && typeof value === 'object') return Object.values(value).map(_printableString).join(' ');
  return _printableString(value);
}
function _wordOrderExplanationVocabLevel(vocabLevel) {
  const value = _printableString(vocabLevel).trim();
  if (value === '01' || value === '1' || value === '\uC26C\uC6C0') return '1';
  if (value === '02' || value === '2') return '2';
  if (value === '04' || value === '4' || value === '\uC5B4\uB824\uC6C0') return '4';
  return '3';
}
function _wordOrderExplanationDifficulty(length) {
  const value = _printableString(length).trim();
  if (value === '\uC9E7\uAC8C' || value === '\uC18C' || value === '\uC26C\uC6C0' || value === '\uD558') return '\uC26C\uC6C0';
  if (value === '\uAE38\uAC8C' || value === '\uB300' || value === '\uC5B4\uB824\uC6C0' || value === '\uC0C1') return '\uC5B4\uB824\uC6C0';
  return '\uC911\uAC04';
}
function _normalizePrintableChoices(choices) {
  if (!Array.isArray(choices)) return [];
  return choices.map(function(choice, index) {
    if (choice && typeof choice === 'object') {
      return {
        key: _printableString(choice.key ?? choice.label ?? choice.num ?? index + 1),
        text: _printableString(_printableTextValue(choice.text) ?? choice.choice ?? choice.option),
      };
    }
    return { key: String(index + 1), text: _printableString(choice) };
  });
}
function _normalizePrintableGrammarRows(rows, qType) {
  if (!Array.isArray(rows)) return [];
  return rows.map(function(row, index) {
    if (row && typeof row === 'object') {
      return {
        id: _printableString(row.id ?? row.label ?? index + 1),
        text: _printableString(_printableTextValue(row.text) ?? row.underlined ?? row.choice ?? row.word),
        grammarCase: _printableString(row.grammar_case ?? row.grammarCase ?? (qType === '네모박스(HO)' ? row.type : undefined)),
        isCorrect: typeof row.is_correct === 'boolean' ? row.is_correct : null,
        reason: _printableString(row.reason_ko ?? row.reason),
      };
    }
    return {
      id: String(index + 1),
      text: _printableString(row),
      grammarCase: '',
      isCorrect: null,
      reason: '',
    };
  });
}
function _normalizePrintableExplanationRows(rows) {
  if (!Array.isArray(rows)) return [];
  return rows.map(function(row, index) {
    if (row && typeof row === 'object') {
      return {
        id: _printableString(row.id ?? row.label ?? index + 1),
        isCorrect: typeof row.is_correct === 'boolean' ? row.is_correct : null,
        reason: _printableString(row.reason_ko ?? row.reason),
      };
    }
    return { id: String(index + 1), isCorrect: null, reason: _printableString(row) };
  });
}
function _normalizePrintableExplanationChoices(rows) {
  if (!Array.isArray(rows)) return [];
  return rows.map(function(row, index) {
    if (row && typeof row === 'object') {
      return {
        num: String(row.num ?? row.id ?? index + 1),
        isCorrect: typeof row.is_correct === 'boolean' ? row.is_correct : null,
        reason: _printableString(row.reason_ko ?? row.reason),
      };
    }
    return { num: String(index + 1), isCorrect: null, reason: _printableString(row) };
  });
}
function _normalizePrintableMarkedItems(items) {
  if (!Array.isArray(items)) return [];
  return items.map(function(item, index) {
    if (item && typeof item === 'object') {
      return {
        id: _printableString(item.id ?? item.label ?? index + 1),
        word: _printableString(item.word ?? item.text),
        isAppropriate: typeof item.is_appropriate === 'boolean' ? item.is_appropriate : null,
        replacement: _printableString(item.replacement),
      };
    }
    return {
      id: String(index + 1),
      word: _printableString(item),
      isAppropriate: null,
      replacement: '',
    };
  });
}
function _normalizePrintableWordList(wordList) {
  if (!Array.isArray(wordList)) return [];
  return wordList.map(function(item) {
    if (item && typeof item === 'object') {
      return {
        word: _printableString(item.word),
        meaning: _printableString(item.meaning ?? item.definition),
      };
    }
    return { word: _printableString(item), meaning: '' };
  });
}
function _printableTextValue(value) {
  if (value && typeof value === 'object') return value.underlined ?? value.text ?? value.choice ?? value.word ?? value;
  return value;
}
function _printableString(value) {
  if (value == null) return '';
  if (typeof value === 'string') return value;
  if (typeof value === 'number' || typeof value === 'boolean') return String(value);
  return JSON.stringify(value);
}
function _normalizeGrammarSubjectiveItems(items, markText) {
  if (markText) items = _normalizeGrammarSubjectiveItemsForOutput(items, markText);
  if (!Array.isArray(items)) return [];
  return items.map(function(item, index) {
    if (item && typeof item === 'object') {
      return {
        id: String(item.id != null ? item.id : (item.number != null ? item.number : index + 1)),
        prompt: _printableString(item.underlined ?? item.prompt_sentence ?? item.korean_prompt ?? item.hint_word),
        isError: typeof item.is_error === 'boolean' ? item.is_error : null,
        wordBank: Array.isArray(item.word_bank) ? item.word_bank : [],
        requiredConstruction: _printableString(item.required_construction),
        answer: _printableString(item.answer ?? item.answer_sentence ?? item.correction),
        grammarPoint: _printableString(item.grammar_point),
        reason: _printableString(item.reason_ko ?? item.reason),
      };
    }
    return { id: String(index + 1), prompt: _printableString(item), isError: null, wordBank: [], requiredConstruction: '', answer: '', grammarPoint: '', reason: '' };
  });
}
function _printableDirectionLabel(direction) {
  const value = String(direction ?? '').trim().toLowerCase();
  if (!value) return '';
  if (value === 'pos' || value === 'positive' || value === '긍정') return '긍정';
  if (value === 'neg' || value === 'negative' || value === '부정') return '부정';
  return String(direction);
}
function _objChoiceText(c) {
  if (c && typeof c === 'object') return String(c.text ?? c.label ?? c.choice ?? c.option ?? '');
  return String(c ?? '');
}
function _wordItemText(w) {
  if (w && typeof w === 'object') return String(w.word ?? w.base_form ?? w.text ?? w.label ?? w.choice ?? '');
  return String(w ?? '');
}
function _answerKeyText(answerKey) {
  if (answerKey == null) return '';
  if (typeof answerKey === 'string' || typeof answerKey === 'number') return String(answerKey);
  if (Array.isArray(answerKey)) return answerKey.map(_wordItemText).join(' / ');
  if (typeof answerKey === 'object') {
    return Object.entries(answerKey).map(function(e) {
      var v = e[1];
      return '(' + e[0] + ') ' + (Array.isArray(v) ? v.map(_wordItemText).join(' / ') : _wordItemText(v));
    }).join('   ');
  }
  return String(answerKey);
}
function showToast(msg) {
  const t = document.getElementById('toast'); t.textContent=msg; t.classList.add('show');
  clearTimeout(t._t); t._t = setTimeout(()=>t.classList.remove('show'), 2400);
}

