(function init() {
  if (getKey()) document.getElementById('api-status').textContent = '✓ 저장됨';
  if (getGeminiKey()) { const s = document.getElementById('gemini-status'); if(s){s.textContent='✓ 저장됨';s.className='pk-status ok';} }
  if (getOpenAIKey()) { const s = document.getElementById('openai-status'); if(s){s.textContent='✓ 저장됨';s.className='pk-status ok';} }

  // 저장된 모델 기본값 복원
  ['pv-analyze','pv-design','pv-proof','pv-review'].forEach(function(id) {
    var saved = localStorage.getItem('mp_' + id);
    if (saved) {
      var el = document.getElementById(id);
      if (el) el.value = saved;
    }
  });

  // 드롭다운 변경 시 자동 저장
  ['pv-analyze','pv-design','pv-proof','pv-review'].forEach(function(id) {
    var el = document.getElementById(id);
    if (el) el.addEventListener('change', function() {
      localStorage.setItem('mp_' + id, this.value);
    });
  });

  addPassage();
  _applyMainTooltips();
  _applyTrainingTooltips();
})();

