function openInspect() {
  var panel = document.getElementById('inspect-panel');
  panel.style.display = 'flex';

  // 결과 수집
  var allResults = [];
  passages.filter(function(p){ return p.results.length > 0; }).forEach(function(p){
    p.results.forEach(function(r){
      // 지문은 앞 600자만 — 전체 포함 시 입력이 너무 커져 속도 저하
      var passageSnip = r.passage ? r.passage.slice(0, 600) + (r.passage.length > 600 ? '...(생략)' : '') : '';
      allResults.push({ qType:r.qType, question:r.question, passage:passageSnip,
        vocabLevel:r.vocabLevel, attractiveness:r.attractiveness });
    });
  });

  if (!allResults.length) {
    document.getElementById('inspect-body').innerHTML =
      '<div class="isp-loading">점검할 결과가 없습니다. 먼저 출제를 완료하세요.</div>';
    return;
  }

  var apiKey = getKey();
  if (!apiKey) { showToast('API 키를 먼저 입력해주세요'); return; }

  document.getElementById('inspect-body').innerHTML =
    '<div class="isp-loading"><div style="font-size:28px;margin-bottom:10px">🔍</div>' +
    '<div style="font-size:13px;font-weight:600;margin-bottom:6px">AI가 문제를 분석하고 있습니다</div>' +
    '<div style="font-size:11px;color:#9CA3AF">약 10~20초 소요됩니다...</div></div>';

  // 사용된 유형의 스킬 파일 내용 수집 (임베드된 JS 변수에서)
  var types = [];
  allResults.forEach(function(r){ if(types.indexOf(r.qType)<0) types.push(r.qType); });

  var skillFilesContent = '';
  var loadedVars = [];
  types.forEach(function(type) {
    var info = _INSPECT_SKILL_MAP[type];
    if (!info || loadedVars.indexOf(info.v) >= 0) return;
    var content = window[info.v];
    if (content) {
      skillFilesContent += '=== 파일: ' + info.f + ' ===\n' + content + '\n\n---\n\n';
      loadedVars.push(info.v);
    }
  });
  // 오답 매력도 파일 (객관식 있을 때)
  var hasObj = types.some(function(t){ return !_SUBJECTIVE_TYPES.has(t); });
  if (hasObj && window._SF_OBJ_DISTRACTOR) {
    skillFilesContent += '=== 파일: skills/english-question-design/references/distractor-attractiveness.md ===\n' + _SF_OBJ_DISTRACTOR;
  }

  var inspectorSystem = '당신은 수능 영어 문제 출제 시스템의 코드 품질 검수 전문가입니다.\n\n' +
    '## 역할\n생성된 문제 결과물을 분석하여:\n' +
    '1. 각 문제의 품질을 평가한다\n' +
    '2. 반복 패턴을 찾아 원인이 되는 스킬 파일을 특정한다\n' +
    '3. 스킬 파일의 어느 섹션에 무엇을 추가/수정하면 되는지 구체적인 텍스트로 제안한다\n\n' +
    '## 평가 기준\n### 객관식 공통\n' +
    '- 오답 구조: "앞부분 본문 일치 + 뒷부분 1~2단어 오류" 구조\n' +
    '- 본문 어휘 포함: 각 오답에 본문 단어(어형변화 포함) 1개 이상\n' +
    '- Half-Right Trap(HRT), Keyword Lure(KL) 각 1개 이상. Stealth Distractor(SD)는 안전 유형에서만 사용하고, 제목/함축의미/의미오지선다는 오답 패턴 사용 금지, 빈칸A-1은 직접 대입 테스트와 본문 반박 문장 확인 통과 시에만 허용\n' +
    '- 극단어(only/purely/solely/always/regardless of) 미포함, 정면 배반 없음\n\n' +
    '### 주관식 공통\n' +
    '- 빈칸 정답의 패러프레이즈 방법 다양성\n' +
    '- 첫 글자 힌트 일관성\n' +
    '- 빈칸 난이도 분포\n\n' +
    '## 현재 스킬 파일 내용 (이 파일들을 수정 대상으로만 사용)\n' + skillFilesContent + '\n\n' +
    '## 출력 형식 (JSON만, 다른 텍스트 없음)\n' +
    '{\n  "summary": "전체 평가 2~3줄",\n  "overall_score": 0~10,\n' +
    '  "question_reviews": [{"idx":0,"type":"유형","score":0~10,"issues":["..."],"strengths":["..."]}],\n' +
    '  "code_improvements": [{\n' +
    '    "id": 1,\n    "severity": "high|medium|low",\n    "pattern": "패턴 1줄 요약",\n' +
    '    "affected_q_indices": [0,2],\n    "file": "skills/.../xxx.md",\n    "section": "섹션명",\n' +
    '    "change_type": "추가|수정|삭제",\n    "current_text": null,\n    "proposed_text": "정확한 마크다운 텍스트",\n' +
    '    "rationale": "이유 — 생성 결과 증거 포함"\n  }]\n}';

  var _ispStartTime = Date.now();

  fetch('https://api.anthropic.com/v1/messages', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'x-api-key': apiKey,
      'anthropic-version': '2023-06-01',
      'anthropic-dangerous-direct-browser-access': 'true',
    },
    body: JSON.stringify({
      model: 'claude-haiku-4-5-20251001',
      max_tokens: 3500,
      system: [{ type: 'text', text: inspectorSystem, cache_control: { type: 'ephemeral' } }],
      messages: [{ role: 'user', content: '다음 출제 결과를 분석하고 코드 개선 제안을 JSON으로 반환하세요:\n' + JSON.stringify(allResults, null, 2) }],
    }),
  }).then(function(r){ return r.json(); }).then(function(data) {
    var elapsed = ((Date.now() - _ispStartTime) / 1000).toFixed(1);
    var usage = data.usage || {};
    var tokIn  = (usage.input_tokens  || 0).toLocaleString();
    var tokOut = (usage.output_tokens || 0).toLocaleString();
    var tokCache = usage.cache_read_input_tokens ? ' · 캐시 ' + usage.cache_read_input_tokens.toLocaleString() : '';
    var statBar = '<div style="font-size:10px;color:#9CA3AF;text-align:right;margin-bottom:8px;padding:4px 2px">' +
      '⏱ ' + elapsed + '초 · 입력 ' + tokIn + ' · 출력 ' + tokOut + tokCache + ' tokens</div>';

    var text = (data.content && data.content[0] && data.content[0].text) || '';
    var result = _extractJson(text);
    if (result) {
      _inspectionData = result;
      renderInspection(result, statBar);
    } else {
      document.getElementById('inspect-body').innerHTML =
        statBar + '<div class="isp-loading">분석 결과 파싱 실패.<br><small>' + escH(text.slice(0,200)) + '</small></div>';
    }
  }).catch(function(e) {
    document.getElementById('inspect-body').innerHTML =
      '<div class="isp-loading">API 오류: ' + escH(e.message) + '</div>';
  });
}

function renderInspection(data, statBar) {
  var html = statBar || '';

  // 종합 점수 카드
  var scoreColor = data.overall_score >= 8 ? 'var(--grn)' : data.overall_score >= 6 ? 'var(--ambr)' : '#EF4444';
  var scoreBg   = data.overall_score >= 8 ? 'var(--grn-lt)'  : data.overall_score >= 6 ? 'var(--ambr-lt)' : '#FEF2F2';
  var scoreBd   = data.overall_score >= 8 ? 'var(--grn-bd)'  : data.overall_score >= 6 ? 'var(--ambr-bd)' : '#FCA5A5';
  html += '<div style="background:'+scoreBg+';border:1px solid '+scoreBd+';border-radius:10px;padding:12px 14px">' +
    '<div style="display:flex;align-items:center;gap:8px">' +
    '<span style="font-size:26px;font-weight:800;color:'+scoreColor+'">' + data.overall_score + '</span>' +
    '<span style="font-size:10px;color:'+scoreColor+';font-weight:600">/10 종합점수</span></div>' +
    '<div style="font-size:11px;color:#374151;line-height:1.65;margin-top:6px">' + escH(data.summary) + '</div></div>';

  // 문항별 점수
  if (data.question_reviews && data.question_reviews.length) {
    html += '<div class="isp-section-lbl">문항별 평가</div>';
    html += '<div style="display:flex;flex-direction:column;gap:4px">';
    data.question_reviews.forEach(function(qr) {
      var sc = qr.score || 0;
      var cl = sc >= 8 ? '#059669' : sc >= 6 ? '#D97706' : '#DC2626';
      html += '<div style="display:flex;align-items:flex-start;gap:8px;padding:7px 10px;background:var(--bg);border:1px solid var(--bdr);border-radius:8px">' +
        '<span style="font-size:11px;font-weight:700;color:'+cl+';min-width:28px">'+sc+'</span>' +
        '<div style="flex:1"><div style="font-size:10px;font-weight:600;color:#374151">#'+(qr.idx+1)+' '+escH(qr.type)+'</div>' +
        (qr.issues && qr.issues.length ? '<div style="font-size:9px;color:#EF4444;margin-top:2px">⚠ '+qr.issues.map(escH).join(' / ')+'</div>' : '') +
        (qr.strengths && qr.strengths.length ? '<div style="font-size:9px;color:var(--grn);margin-top:1px">✓ '+qr.strengths.map(escH).join(' / ')+'</div>' : '') +
        '</div></div>';
    });
    html += '</div>';
  }

  // 코드 개선 제안
  if (data.code_improvements && data.code_improvements.length) {
    html += '<div class="isp-section-lbl">코드 개선 제안 ('+data.code_improvements.length+'건)</div>';
    data.code_improvements.forEach(function(imp) {
      var sevCls = imp.severity || 'medium';
      var sevLabel = {high:'긴급',medium:'권장',low:'선택'}[imp.severity] || imp.severity;
      html += '<div class="imp-card">' +
        '<div class="imp-head">' +
        '<span class="imp-sev '+sevCls+'">'+escH(sevLabel)+'</span>' +
        '<span class="imp-pattern">'+escH(imp.pattern)+'</span></div>' +
        '<div class="imp-body">' +
        '<div class="imp-meta">' +
        '<b>파일:</b> '+escH(imp.file)+'<br>' +
        (imp.section ? '<b>섹션:</b> '+escH(imp.section)+'<br>' : '') +
        '<b>변경:</b> '+escH(imp.change_type||'') +
        (imp.affected_q_indices&&imp.affected_q_indices.length ? ' · 문항 '+imp.affected_q_indices.map(function(i){return '#'+(i+1);}).join(', ') : '') +
        '</div>' +
        '<div class="imp-code">'+escH(imp.proposed_text||'')+'</div>' +
        '<div class="imp-rationale">'+escH(imp.rationale||'')+'</div>' +
        '<button class="imp-apply-btn" id="apply-btn-'+imp.id+'" onclick="applyImprovement('+imp.id+')">📋 복사</button>' +
        '</div></div>';
    });
  } else {
    html += '<div style="text-align:center;padding:20px;color:#9CA3AF;font-size:12px">개선 제안이 없습니다.</div>';
  }

  document.getElementById('inspect-body').innerHTML = html;
}

function applyImprovement(id) {
  if (!_inspectionData) return;
  var imp = (_inspectionData.code_improvements || []).find(function(x){ return x.id === id; });
  if (!imp) return;

  var btn = document.getElementById('apply-btn-'+id);
  if (!btn || btn.disabled) return;

  var lines = [
    '다음 개선사항을 스킬 파일에 반영해 주세요.',
    '',
    '파일: ' + (imp.file || ''),
    imp.section ? '섹션: ' + imp.section : '',
    '변경 유형: ' + (imp.change_type || ''),
    '심각도: ' + ({high:'긴급',medium:'권장',low:'선택'}[imp.severity] || imp.severity || ''),
    '패턴: ' + (imp.pattern || ''),
    '',
    '【현재 텍스트】',
    imp.current_text || '(없음)',
    '',
    '【제안 텍스트】',
    imp.proposed_text || '',
    '',
    '【근거】',
    imp.rationale || '',
  ].filter(function(l){ return l !== null && l !== undefined; }).join('\n');

  btn.disabled = true;
  btn.textContent = '복사 중...';

  navigator.clipboard.writeText(lines).then(function() {
    btn.textContent = '✓ 복사됨';
    btn.style.background = '#10B981';
    btn.style.color = '#fff';
    showToast('클립보드에 복사됨 — 이 대화에 붙여넣으면 반영됩니다');
  }).catch(function(e) {
    // fallback: textarea select
    var ta = document.createElement('textarea');
    ta.value = lines;
    ta.style.position = 'fixed';
    ta.style.opacity = '0';
    document.body.appendChild(ta);
    ta.select();
    try { document.execCommand('copy'); btn.textContent = '✓ 복사됨'; btn.style.background = '#10B981'; btn.style.color = '#fff'; showToast('클립보드에 복사됨 — 이 대화에 붙여넣으면 반영됩니다'); }
    catch(e2) { btn.textContent = '오류'; btn.disabled = false; showToast('복사 실패: ' + e2.message); }
    document.body.removeChild(ta);
  });
}

function closeInspect() {
  document.getElementById('inspect-panel').style.display = 'none';
}

/* ═══════════════════════════════════════════════════════════════════
   기본기 훈련 모듈  (v2 — 지문 전체 표시 + 번호 밑줄)
   ═══════════════════════════════════════════════════════════════════ */

/* ── JSON 안전 파싱 (코드블록·전후 텍스트 제거 + 흔한 쉼표 누락 보정) ── */
function _repairLikelyJson(text) {
  return String(text || '')
    .replace(/^\uFEFF/, '')
    .replace(/,\s*([}\]])/g, '$1')
    .replace(/}\s*{/g, '},{')
    .replace(/]\s*{/g, '],{')
    .replace(/}\s*"/g, '},"')
    .replace(/]\s*"/g, '],"')
    .replace(/("[^"\\]*(?:\\.[^"\\]*)*"\s*:\s*(?:"[^"\\]*(?:\\.[^"\\]*)*"|-?\d+(?:\.\d+)?|true|false|null))\s+("[-A-Za-z0-9_$가-힣]+"\s*:)/g, '$1,$2');
}

function _safeParseJSON(raw) {
  var s = String(raw || '').trim();
  var candidates = [];
  candidates.push(s);

  var fenceRe = /```(?:json)?\s*([\s\S]*?)\s*```/gi;
  var m;
  while ((m = fenceRe.exec(s)) !== null) candidates.push(m[1].trim());

  var objStart = s.indexOf('{');
  var objEnd   = s.lastIndexOf('}');
  if (objStart !== -1 && objEnd > objStart) candidates.push(s.slice(objStart, objEnd + 1));

  var arrStart = s.indexOf('[');
  var arrEnd   = s.lastIndexOf(']');
  if (arrStart !== -1 && arrEnd > arrStart) candidates.push(s.slice(arrStart, arrEnd + 1));

  if (typeof _extractJson === 'function') {
    var extracted = _extractJson(s);
    if (extracted) return extracted;
  }

  for (var i = 0; i < candidates.length; i++) {
    var c = candidates[i];
    try { return JSON.parse(c); } catch(e1) {}
    try { return JSON.parse(_repairLikelyJson(c)); } catch(e2) {}
  }
  return null;
}

function _parseTrainingJsonOrThrow(raw, label) {
  var parsed = _safeParseJSON(raw);
  if (!parsed || typeof parsed !== 'object') {
    var preview = String(raw || '').replace(/\s+/g, ' ').slice(0, 220);
    throw new Error((label || '응답') + ' JSON 파싱 실패: ' + preview);
  }
  return parsed;
}

/* ── 설정 상태 ── */
var _trWordMode = 'single'; // fallback default

/* ── 동적 시스템 프롬프트 조립 ── */
/* ── 기본기 훈련 문법 포인트 정의 (공통) ── */
var _TR_GRAMMAR_POINTS =
'## 기본기 훈련 문법 포인트\n\n' +
'### ① 준동사/정동사 (단원 01~02)\n' +
'[출제 금지]\n' +
'- 전치사 바로 뒤 동명사 자리(by ~ing, in ~ing, after ~ing, from ~ing, of ~ing, without ~ing 등)는 출제하지 않음\n' +
'- look forward to ~ing, be used to ~ing, prevent A from ~ing 같은 전치사+동명사 암기형 금지\n' +
'- 짧고 단순한 문장에서 to부정사/동명사만 고르는 문제 금지\n' +
'- 조동사 바로 뒤 첫 동사의 원형 여부만 묻는 포인트 금지: "will keeping", "can to do", "should doing"처럼 조동사 뒤를 준동사/정동사 판별 포인트로 삼지 않는다\n\n' +
'[출제 허용 — 아래 두 케이스만]\n' +
'- 케이스 A: 수식어구(관계절/분사구/전치사구)가 주어와 동사 사이에 삽입되어 이 자리가 동사 자리인지 판단하기 어려운 문장\n' +
'  → 오류 삽입: 정동사 ↔ 준동사 교체\n' +
'- 케이스 B: 주절(주어+동사)이 등장한 이후, 수식어구가 사이에 끼면서 추가 준동사 구조가 나오는 복합 문장\n' +
'  → 오류 삽입: to부정사 ↔ 동명사, 또는 준동사 ↔ 정동사 교체\n\n' +
'[공통 원칙]\n' +
'- 문장 구조가 단순하면 무조건 스킵 (짧고 수식어 없는 문장 금지)\n' +
'- 지문에 케이스 A/B가 자연스럽게 없으면 ① 포인트 전체 스킵\n' +
'- 예) The evidence collected from several independent studies shows that the effect is real.\n\n' +
'### ② 수의 일치 (단원 03~04)\n' +
'- 수식어구로 주어-동사가 멀어진 경우, 도치, 명사구/명사절 주어처럼 학생이 주어를 착각할 만한 경우만 출제\n' +
'- 출제 금지: 주어와 동사가 바로 붙어 있는 단순 구조. 예) ostriches bury, investors avoid처럼 주어 바로 뒤 동사는 수의 일치 문항으로 내지 않음\n' +
'- 오류 삽입: 단수↔복수 동사\n' +
'- 예) The number of students has → have\n\n' +
'### ③ 수동태/능동태 (단원 07~09)\n' +
'- 타동사 문장에서만 적용 (자동사 스킵)\n' +
'- 오류 삽입: 능동형/준동사형을 수동 의미에 맞게 p.p.로 고치게 함. 예) is heavily influencing by our diet → is heavily influenced by our diet\n' +
'- 수동태 문제 의도가 있으면 원형 influence처럼 단순 오탈자 느낌으로 만들지 말고, influencing → influenced처럼 능동/수동 대비가 드러나는 형태를 우선 사용\n\n' +
'### ⑥ 병렬구조 (단원 05~06)\n' +
'- and / but / or / both~and / not only~but also 로 연결된 구조\n' +
'- 오류 삽입: 동일 품사/형태로 맞춰야 하는 자리에 다른 형태 삽입\n' +
'- 밑줄 위치 원칙: 앞에 병렬 기준이 먼저 나오고 뒤에 병렬되는 대상이 나올 때, 학생이 맞춰야 할 **뒤쪽 병렬 대상**에 밑줄을 긋는다. 예) fail to monitor ... or check ... 에서는 monitor가 아니라 check 쪽을 밑줄 대상으로 삼음\n' +
'- 예) to read and writing → to read and write\n\n' +
'### ⑦ 관계사 (단원 10~13)\n' +
'- 관계대명사 뒤 절의 완전성 판단: 주격/목적격 관계대명사 뒤에는 필요한 성분이 빠져야 함\n' +
'- who / whom / which / that 선택, 선행사와 관계사절의 실제 연결 관계 판단\n' +
'- 관계부사 where / when / why 와 전치사+관계대명사(in which 등) 혼동\n' +
'- that의 역할 구별: 관계대명사 / 접속사 / 동격, 콤마 뒤·전치사 뒤 that 사용 불가\n' +
'- 예) the place which he lives → the place where he lives / the place in which he lives\n';

function _trBuildSystem(wordMode, passageMode, questionMode) {
  var wm = wordMode || 'single';
  var pm = passageMode || 'original';
  var qm = questionMode || 'underline';

  if (qm === 'choice') {
    return _trBuildChoiceSystem(wm, pm);
  }

  var wordBlock = wm === 'single'
    ? '## 밑줄 범위\n' +
      '각 밑줄은 반드시 **단일 단어(1개)** 만 포함합니다.\n' +
      '예) [[1:have]], [[2:written]], [[3:which]]\n' +
      '구나 절 전체를 묶지 않습니다. 딱 한 단어만 [[N:word]] 안에 넣으세요.\n'
    : '## 밑줄 범위\n' +
      '각 밑줄은 **2단어 이상의 구(phrase)** 를 포함합니다.\n' +
      '예) [[1:have been]], [[2:written by students]], [[3:which makes]]\n' +
      '문법 판단에 필요한 최소 범위를 기준으로 묶으세요 (단, 문장 전체는 묶지 않습니다).\n';

  if (pm === 'paraphrase') {
    return _trBuildParaphraseSystem(wordBlock);
  }

  /* ── 원문 그대로 모드 ── */
  var countBlock =
    '## 밑줄 개수 및 오류 규칙\n' +
    '- 밑줄은 **5~8개** 삽입합니다.\n' +
    '- 오류(is_error: true)는 전체 밑줄의 약 80%, 올바름(is_error: false)은 약 20%로 구성합니다.\n' +
    '- 출제 포인트가 풍부하면 오류를 더 넣어도 됩니다.\n';

  var verifyBlock =
    '## 출력 전 자체 검증 (2회 실시)\n\n' +
    '### 1차 검증 — 문항별 점검\n' +
    '각 밑줄 항목에 대해 순서대로 확인합니다:\n' +
    '- 이 어구가 실제로 해당 문법 포인트에 해당하는가?\n' +
    '- is_error 값이 지문 내 실제 형태(오류 여부)와 일치하는가?\n' +
    '- correction 값이 문법적으로 올바른가? (is_error: false이면 correction 불필요)\n' +
    '- ① 준동사/정동사 문항이 전치사+동명사 자리를 출제하고 있지 않은가?\n' +
    '- ① 문항의 해당 문장이 케이스 A 또는 B의 조건을 실제로 충족하는가?\n' +
    '- ② 수의 일치 문항이 주어+동사가 바로 붙은 단순 구조를 출제하고 있지 않은가?\n' +
    '- ③ 수동태/능동태 문항이 단순 원형 오탈자처럼 보이지 않고 능동/수동 대비를 실제로 묻고 있는가?\n' +
    '- ⑥ 병렬구조 문항은 앞쪽 기준 표현이 아니라 뒤쪽 병렬 대상에 밑줄을 그었는가?\n' +
    '오류 발견 시 즉시 수정합니다.\n\n' +
    '### 2차 검증 — 전체 정합성 점검\n' +
    '- 밑줄 개수가 5~8개 범위인가?\n' +
    '- is_error: true 비율이 전체의 70% 이상인가?\n' +
    '- 억지로 삽입된 포인트(지문에 자연스럽지 않은 것)는 없는가?\n' +
    '불만족 항목이 있으면 해당 항목을 수정 후 최종 출력합니다.\n';

  return '당신은 한국 고등학교 영어 교사입니다. 영어 지문을 분석하여 문법 훈련용 밑줄 문제를 출제합니다.\n\n' +
    '## 출제 목표\n지문에서 아래 기본기 훈련 문법 포인트에 해당하는 어구를 찾아 번호 밑줄을 삽입합니다.\n' +
    '밑줄은 지문 원문 안에 [[번호:어구]] 형태로 표시합니다.\n\n' +
    _TR_GRAMMAR_POINTS + '\n' +
    '## 출제 규칙\n' +
    '1. 포인트당 기본 1문항. 아래 목록에 없는 문법 포인트는 출제하지 않습니다. 관계사는 ⑦ 포인트 범위 안에서 적극 출제합니다.\n' +
    '2. 지문에 해당 포인트가 자연스럽게 없으면 그 포인트 스킵 (억지 삽입 금지).\n' +
    '3. 오류는 반드시 지문의 어구를 변형. 새 문장 창작 금지.\n' +
    '4. 밑줄 번호는 지문 등장 순서대로 1, 2, 3 … 부여.\n\n' +
    wordBlock + '\n' +
    countBlock + '\n' +
    verifyBlock + '\n' +
    '## 출력 형식 (순수 JSON만, 코드블록 없이)\n' +
    '{\n' +
    '  "passage_with_marks": "지문 전체. 밑줄 위치에 [[번호:어구]] 삽입.",\n' +
    '  "items": [\n' +
    '    {\n' +
    '      "number": 1,\n' +
    '      "point_number": 1,\n' +
    '      "point_name": "준동사/정동사",\n' +
    '      "underlined": "wrote",\n' +
    '      "is_error": true,\n' +
    '      "correction": "written",\n' +
    '      "reason_ko": "해설",\n' +
    '      "catalog_ref": "단원 01~02"\n' +
    '    }\n' +
    '  ]\n' +
    '}';
}

/* ── 선택형 문법 훈련 시스템 프롬프트 ── */
function _trBuildChoiceSystem(wordMode, passageMode) {
  var wm = wordMode || 'single';
  var pm = passageMode || 'original';
  var unitBlock = wm === 'single'
    ? '각 선택지는 되도록 단일 단어로 구성합니다. 예) [[1:A:who|B:whom]], [[2:A:allow|B:allows]]\n'
    : '각 선택지는 문법 판단에 필요한 최소 어구로 구성할 수 있습니다. 예) [[1:A:in which|B:which]], [[2:A:that would help|B:where would help]]\n';
  var passageBlock = pm === 'paraphrase'
    ? '원문 지문의 주제·논리·예시는 유지하되 문장을 패러프레이즈한 뒤 선택형 문법 문제를 만듭니다. "original_passage"에는 원문을 그대로 넣습니다.\n'
    : '원문 지문 안의 자연스러운 위치를 활용해 선택형 문법 문제를 만듭니다. 새 문장 창작은 금지합니다.\n';

  return '당신은 한국 고등학교 영어 교사입니다. 영어 지문을 분석하여 문법 훈련용 선택형 문제를 출제합니다.\n\n' +
    _TR_GRAMMAR_POINTS + '\n' +
    '## 출제 목표\n' +
    passageBlock +
    '지문에는 반드시 [[번호:A:선택지A|B:선택지B]] 형식으로 선택지를 삽입합니다.\n' +
    unitBlock + '\n' +
    '## 출제 규칙\n' +
    '1. 문항은 5~8개 출제합니다.\n' +
    '2. 각 문항의 선택지는 정확히 A/B 두 개입니다.\n' +
    '3. 정답은 반드시 A 또는 B 중 하나로 유일해야 합니다. A/B 둘 다 가능한 선택지는 금지합니다.\n' +
    '4. 오답은 표면상 그럴듯하지만 해당 문맥·구조에서는 문법적으로 틀려야 합니다.\n' +
    '5. 관계사는 ⑦ 포인트 범위 안에서 우선적으로 포함하되, 지문에 자연스럽게 있는 ①②③⑥도 함께 활용할 수 있습니다.\n' +
    '6. 지문 등장 순서대로 번호를 부여합니다.\n\n' +
    '## 출력 전 자체 검증\n' +
    '- passage_with_choices의 모든 마커가 [[번호:A:...|B:...]] 형식인가?\n' +
    '- items[].choice_A, choice_B, answer, answer_text가 마커와 정확히 일치하는가?\n' +
    '- answer는 A 또는 B 하나뿐인가?\n' +
    '- reason_ko가 정답이 맞는 이유와 오답이 안 되는 이유를 모두 설명하는가?\n\n' +
    '- ① 준동사/정동사 문항이 전치사+동명사 자리를 출제하고 있지 않은가?\n' +
    '- ① 문항의 해당 문장이 케이스 A 또는 B의 조건을 실제로 충족하는가?\n\n' +
    '- ② 수의 일치 문항이 주어+동사가 바로 붙은 단순 구조를 출제하고 있지 않은가?\n' +
    '- ③ 수동태/능동태 문항이 능동/수동 대비를 실제로 묻는 선택지인가?\n' +
    '- ⑥ 병렬구조 문항은 뒤쪽 병렬 대상에 선택지를 배치했는가?\n\n' +
    '## 출력 형식 (순수 JSON만, 코드블록 없이)\n' +
    '{\n' +
    '  "original_passage": "' + (pm === 'paraphrase' ? '원문 지문 전체' : '') + '",\n' +
    '  "passage_with_choices": "지문 전체. 선택지 위치에 [[번호:A:선택지A|B:선택지B]] 삽입.",\n' +
    '  "items": [\n' +
    '    {\n' +
    '      "number": 1,\n' +
    '      "point_number": 7,\n' +
    '      "point_name": "관계사",\n' +
    '      "choice_A": "that",\n' +
    '      "choice_B": "where",\n' +
    '      "answer": "A",\n' +
    '      "answer_text": "that",\n' +
    '      "reason_ko": "해설",\n' +
    '      "catalog_ref": "단원 10~13"\n' +
    '    }\n' +
    '  ]\n' +
    '}';
}

/* ── 패러프레이즈 모드 전용 시스템 프롬프트 ── */
function _trBuildParaphraseSystem(wordBlock) {
  return '당신은 한국 고등학교 영어 교사입니다. 아래 6단계 절차를 순서대로 수행하여 패러프레이즈 문법 훈련 문제를 출제합니다.\n\n' +
    _TR_GRAMMAR_POINTS + '\n' +
    '---\n\n' +
    '## [1단계] 원문 분석\n' +
    '원문 지문을 읽고, 위 기본기 훈련 문법 포인트 중 원문에 이미 자연스럽게 존재하는 포인트를 파악합니다.\n' +
    '(이 분석은 출력하지 않습니다. 내부 작업용입니다.)\n\n' +
    '## [2단계] 출제 포인트 선정\n' +
    '원문에서 확인한 포인트와 **최대한 겹치지 않는** 포인트를 5~8개 선정합니다.\n' +
    '선정 원칙:\n' +
    '- 원문에 ③수동태가 많으면 → 패러프레이즈에서 ③은 출제하지 않고 다른 포인트로 대체\n' +
    '- 원문에 관계사 구조가 자연스럽게 있으면 → ⑦ 관계사를 우선 후보로 검토\n' +
    '- 위 목록 중 원문에 없던 포인트를 우선적으로 선정합니다\n' +
    '- 단, 원문에 없더라도 패러프레이즈 문장에 자연스럽게 넣기 어려운 포인트는 스킵합니다\n\n' +
    '## [3단계] 패러프레이즈 작성\n' +
    '원문의 주제·논리·예시는 유지하되, 아래를 모두 다르게 씁니다:\n' +
    '- 어휘: 동의어·상위어·하위어로 교체 (고유명사·핵심 전문용어 제외)\n' +
    '- 문장 구조: 능동↔수동, 절의 순서·배치, 수식어 위치를 바꿉니다\n' +
    '- **2단계에서 선정한 문법 포인트가 문장 안에 자연스럽게 포함되도록 구성합니다**\n' +
    '- 원문과 동일한 단어·구절이 3개 이상 연속으로 등장하지 않도록 합니다\n\n' +
    '## [4단계] 밑줄 삽입\n' +
    '패러프레이즈된 지문에 [[번호:어구]] 형식으로 밑줄을 삽입합니다.\n' +
    '- 각 밑줄은 2단계에서 선정한 포인트를 기준으로 배치합니다\n' +
    '- 밑줄 번호는 지문 등장 순서대로 1, 2, 3 … 부여\n' +
    '- 오류(is_error: true) 약 80%, 올바름(is_error: false) 약 20%\n\n' +
    wordBlock + '\n' +
    '## [5단계] 1차 검증 — 문항별 점검\n' +
    '각 밑줄 항목을 하나씩 확인합니다:\n' +
    '□ 이 어구가 실제로 해당 문법 포인트를 포함하는가?\n' +
    '□ is_error 판정이 패러프레이즈 문장 내 실제 형태와 일치하는가?\n' +
    '□ correction 값이 문법적으로 올바른가?\n' +
    '□ 밑줄 어구가 [[번호:어구]] 형식으로 정확히 삽입되었는가?\n' +
    '□ ① 준동사/정동사 문항이 전치사+동명사 자리를 출제하고 있지 않은가?\n' +
    '□ ①/② 문항이 주어+동사가 바로 붙은 단순 구조를 출제하고 있지 않은가?\n' +
    '□ ③ 수동태/능동태 문항이 단순 원형 오탈자가 아니라 능동/수동 대비를 묻고 있는가?\n' +
    '□ ⑥ 병렬구조 문항은 앞쪽 기준 표현이 아니라 뒤쪽 병렬 대상에 밑줄을 그었는가?\n' +
    '□ ① 문항의 해당 문장이 케이스 A 또는 B의 조건을 실제로 충족하는가?\n' +
    '오류 발견 시 즉시 수정합니다.\n\n' +
    '## [6단계] 2차 검증 — 전체 정합성 점검\n' +
    '□ 패러프레이즈 지문이 원문과 어휘·구조 면에서 충분히 다른가? (같은 단어 3개 이상 연속 없는가?)\n' +
    '□ 출제된 문법 포인트가 원문의 포인트와 최대한 다른가? (겹치는 포인트가 전체의 50% 미만인가?)\n' +
    '□ is_error: true 비율이 전체 밑줄의 70% 이상인가?\n' +
    '□ 밑줄 개수가 5~8개 범위인가?\n' +
    '불만족 항목이 있으면 해당 부분을 수정 후 최종 출력합니다.\n\n' +
    '---\n\n' +
    '## 최종 출력 형식 (순수 JSON만, 코드블록 없이)\n' +
    '{\n' +
    '  "original_passage": "원문 지문 전체 (수정 없이 그대로)",\n' +
    '  "passage_with_marks": "패러프레이즈된 지문 전체. 밑줄 위치에 [[번호:어구]] 삽입.",\n' +
    '  "items": [\n' +
    '    {\n' +
    '      "number": 1,\n' +
    '      "point_number": 2,\n' +
    '      "point_name": "수의 일치",\n' +
    '      "underlined": "have",\n' +
    '      "is_error": true,\n' +
    '      "correction": "has",\n' +
    '      "reason_ko": "해설",\n' +
    '      "catalog_ref": "단원 03~04"\n' +
    '    }\n' +
    '  ]\n' +
    '}';
}

/* ── 상태 ── */
var _trPassages   = [];   // { id, text, status, types:[], results:{grammar,logic}, wordMode, lgLevel }
var _trIdCounter  = 0;
var _trSelectedId = null;
var _trRunning    = false;
var _trJsonCache  = {};   // key: pid+'-'+tid → result 객체

/* ── 지문 추가 / 삭제 ── */
function _trEnsureInitialPassage() {
  if (_trPassages.length > 0) return;
  var id = ++_trIdCounter;
  _trPassages.push({ id: id, text: '', status: 'idle', typeInstances: [], results: {}, _tidCounter: 0 });
  _trSelectedId = id;
}

function trAddPassage() {
  var id = ++_trIdCounter;
  /* 새 지문은 유형 선택을 비워서 시작 — 각 지문이 독립적으로 유형 설정 */
  _trPassages.push({ id: id, text: '', status: 'idle', typeInstances: [], results: {}, _tidCounter: 0 });
  /* _trRenderQueue는 trSelectPassage 내부에서 호출되므로 중복 호출 제거 */
  trSelectPassage(id);
  setTimeout(function() {
    var ta = document.getElementById('tr-edit-ta');
    if (ta) ta.focus();
  }, 60);
}

function trDelPassage(id) {
  _trPassages = _trPassages.filter(function(p) { return p.id !== id; });
  if (_trSelectedId === id) {
    _trSelectedId = _trPassages.length ? _trPassages[_trPassages.length - 1].id : null;
  }
  _trRenderQueue();
  _trRenderRight();
}

function _trSaveEditText() {
  var ta = document.getElementById('tr-edit-ta');
  if (!ta) return;
  var p = _trPassages.find(function(x) { return x.id === _trSelectedId; });
  if (p) p.text = ta.value;
}

/* ── 선택 ── */
function trSelectPassage(id) {
  _trSaveEditText();
  _trSelectedId = id;
  _trRenderQueue();
  _trRenderRight();
}

/* ── 큐 렌더 (클릭형) ── */
function _trRenderQueue() {
  var container = document.getElementById('tr-passage-queue');
  var statusEl  = document.getElementById('tr-queue-status');
  if (statusEl) statusEl.textContent = _trPassages.length + '개';
  if (_trPassages.length === 0) {
    container.innerHTML = '<div style="font-size:11px;color:#D1D5DB;text-align:center;padding:12px 0">오른쪽에서 지문을 추가하세요 →</div>';
    _applyTrainingTooltips(container);
    return;
  }
  var _ST_LABEL = { idle:'대기', processing:'출제 중', done:'완료', error:'오류' };
  var _ST_CLS   = { idle:'idle', processing:'processing', done:'done', error:'error' };
  var html = '';
  _trPassages.forEach(function(p, i) {
    var isActive = (p.id === _trSelectedId);
    var preview  = p.text.trim().replace(/\s+/g,' ').slice(0, 28) || '(비어 있음)';
    var stCls    = _ST_CLS[p.status]  || 'idle';
    var stLbl    = _ST_LABEL[p.status] || '대기';
    var itemCls  = 'passage-q-item' +
      (isActive ? ' active' : '') +
      (p.status === 'done'       ? ' st-done'       : '') +
      (p.status === 'error'      ? ' st-error'      : '') +
      (p.status === 'processing' ? ' st-processing' : '');
    var typeTag = '';
    var _tCnt = {};
    (p.typeInstances || []).forEach(function(ti) { _tCnt[ti.key] = (_tCnt[ti.key] || 0) + 1; });
    if (_tCnt.grammar) typeTag += '<span style="font-size:8px;padding:1px 5px;border-radius:99px;background:#F5F3FF;color:#7C3AED;border:1px solid #DDD6FE;margin-right:2px">문법' + (_tCnt.grammar > 1 ? '×'+_tCnt.grammar : '') + '</span>';
    if (_tCnt.logic)   typeTag += '<span style="font-size:8px;padding:1px 5px;border-radius:99px;background:#EFF6FF;color:#2563EB;border:1px solid #BFDBFE;margin-right:2px">이해' + (_tCnt.logic > 1 ? '×'+_tCnt.logic : '') + '</span>';
    if (_tCnt.chunk)   typeTag += '<span style="font-size:8px;padding:1px 5px;border-radius:99px;background:#ECFDF5;color:#059669;border:1px solid #6EE7B7;margin-right:2px">해석' + (_tCnt.chunk > 1 ? '×'+_tCnt.chunk : '') + '</span>';
    html +=
      '<div class="' + itemCls + '" onclick="trSelectPassage(' + p.id + ')" data-tpid="' + p.id + '">' +
        '<div class="pq-head">' +
          '<span class="pq-num">' + (i + 1) + '</span>' +
          typeTag +
          '<span class="pq-preview">' + escH(preview) + '</span>' +
          '<span class="pq-status ' + stCls + '">' + stLbl + '</span>' +
          '<button class="pq-del" onclick="event.stopPropagation();trDelPassage(' + p.id + ')">✕</button>' +
        '</div>' +
      '</div>';
  });
  container.innerHTML = html;
  _applyTrainingTooltips(container);
}

/* ── 오른쪽 패널 렌더 ── */
function _trRenderRight() {
  var rp = document.getElementById('tr-right-panel');
  if (_trSelectedId === null || _trPassages.length === 0) {
    rp.innerHTML =
      '<div class="card"><div class="empty-state">' +
        '<div class="empty-icon">📄</div>' +
        '<div>왼쪽에서 지문을 추가하거나 선택하세요</div>' +
      '</div></div>';
    _applyTrainingTooltips(rp);
    return;
  }
  var p   = _trPassages.find(function(x) { return x.id === _trSelectedId; });
  var idx = _trPassages.indexOf(p) + 1;
  if (!p) { rp.innerHTML = ''; return; }

  var insts = p.typeInstances || [];

  if (p.status === 'processing') {
    rp.innerHTML =
      '<div class="card">' +
        '<div class="card-hd"><span>지문 ' + idx + ' · 출제 중</span></div>' +
        '<div style="padding:32px 16px;text-align:center;color:#6B7280;font-size:12px">' +
          '<div class="spin" style="font-size:20px;display:block;margin-bottom:8px">⟳</div>AI가 문제를 생성하고 있습니다…' +
        '</div>' +
      '</div>';
    _applyTrainingTooltips(rp);
    return;
  }

  /* ── 카드 1: 지문 편집 ── */
  var errHtml = p.status === 'error'
    ? '<div style="margin-bottom:8px;padding:6px 10px;border-radius:7px;background:#FEF2F2;border:1px solid #FCA5A5;font-size:11px;color:#EF4444">⚠ 일부 유형 출제 실패 — 아래 결과 확인 후 재출제 가능</div>'
    : '';

  var html =
    '<div class="card">' +
      '<div class="card-hd"><span>지문 ' + idx + '</span></div>' +
      '<div style="padding:12px 16px 14px">' +
        errHtml +
        '<textarea id="tr-edit-ta" style="min-height:160px;font-size:12px" ' +
          'placeholder="영어 지문을 붙여넣으세요..." ' +
          'oninput="_trLivePreview()">' + escH(p.text) + '</textarea>' +
      '</div>' +
    '</div>';

  /* ── 카드 2: 유형 선택 + 설정 (통합 컴팩트) ── */
  var TYPE_LABELS = { grammar:'문법', logic:'지문이해', chunk:'해석훈련' };
  var typeCounts = {};
  insts.forEach(function(ti) { typeCounts[ti.key] = (typeCounts[ti.key] || 0) + 1; });

  var chips = [
    { key:'grammar', label:'문법',    cls:'tchip subj' },
    { key:'logic',   label:'지문이해', cls:'tchip' },
    { key:'chunk',   label:'해석훈련', cls:'tchip green' },
  ].map(function(t) {
    var cnt = typeCounts[t.key] || 0;
    var onCls = cnt > 0 ? ' on' : '';
    var badge = cnt > 0 ? ' <span style="background:rgba(255,255,255,.3);border-radius:99px;padding:0 5px;font-size:9px">×' + cnt + '</span>' : '';
    return '<button class="' + t.cls + onCls + '" onclick="trAddType(\'' + t.key + '\')">' + t.label + badge + '</button>';
  }).join('');

  /* 컴팩트 인스턴스 행 */
  var seenCount = {};
  var instRows = insts.map(function(ti) {
    seenCount[ti.key] = (seenCount[ti.key] || 0) + 1;
    var instNum   = seenCount[ti.key];
    var totalKey  = typeCounts[ti.key] || 1;
    var label     = TYPE_LABELS[ti.key] + (totalKey > 1 ? ' #' + instNum : '');
    var dotColor  = ti.key === 'grammar' ? '#7C3AED' : ti.key === 'chunk' ? '#059669' : '#2563EB';
    var onCls     = ti.key === 'grammar' ? 'on-purp' : ti.key === 'chunk' ? 'on-grn' : 'on-blue';
    var pills = '';

    if (ti.key === 'grammar') {
      var pmO = (ti.passageMode||'original') === 'original';
      var pmP = (ti.passageMode||'original') === 'paraphrase';
      var wmS = ti.wordMode !== 'multi';
      var wmM = ti.wordMode === 'multi';
      var qmU = (ti.questionMode||'underline') !== 'choice';
      var qmC = ti.questionMode === 'choice';
      pills =
        '<button class="tr-ip' + (qmU ? ' ' + onCls : '') + '" onclick="trSetInstanceProp(' + ti.tid + ',\'questionMode\',\'underline\')" title="밑줄 표시 후 고친 표현과 이유 작성">밑줄</button>' +
        '<button class="tr-ip' + (qmC ? ' ' + onCls : '') + '" onclick="trSetInstanceProp(' + ti.tid + ',\'questionMode\',\'choice\')" title="A/B 선택 후 이유 작성">선택</button>' +
        '<span class="tr-inst-sep">│</span>' +
        '<button class="tr-ip' + (pmO ? ' ' + onCls : '') + '" onclick="trSetInstanceProp(' + ti.tid + ',\'passageMode\',\'original\')" title="원문 그대로">원문</button>' +
        '<button class="tr-ip' + (pmP ? ' ' + onCls : '') + '" onclick="trSetInstanceProp(' + ti.tid + ',\'passageMode\',\'paraphrase\')" title="완전히 다른 문장으로 재구성">패러</button>' +
        '<span class="tr-inst-sep">│</span>' +
        '<button class="tr-ip' + (wmS ? ' ' + onCls : '') + '" onclick="trSetInstanceProp(' + ti.tid + ',\'wordMode\',\'single\')" title="한 단어">한단어</button>' +
        '<button class="tr-ip' + (wmM ? ' ' + onCls : '') + '" onclick="trSetInstanceProp(' + ti.tid + ',\'wordMode\',\'multi\')" title="여러 단어">여러단어</button>';
    } else if (ti.key === 'logic') {
      var lvMap = { basic:'기본', standard:'실전', advanced:'심화' };
      pills = Object.keys(lvMap).map(function(k) {
        return '<button class="tr-ip' + ((ti.lgLevel||'standard') === k ? ' ' + onCls : '') + '" onclick="trSetInstanceProp(' + ti.tid + ',\'lgLevel\',\'' + k + '\')">' + lvMap[k] + '</button>';
      }).join('');
    } else if (ti.key === 'chunk') {
      var clB = (ti.chunkLevel||'standard') === 'basic';
      var clS = (ti.chunkLevel||'standard') === 'standard';
      var cmO = (ti.chunkMode||'original') === 'original';
      var cmP = (ti.chunkMode||'original') === 'paraphrase';
      pills =
        '<button class="tr-ip' + (clB ? ' ' + onCls : '') + '" onclick="trSetInstanceProp(' + ti.tid + ',\'chunkLevel\',\'basic\')" title="주어 3~5단어 기준">기본</button>' +
        '<button class="tr-ip' + (clS ? ' ' + onCls : '') + '" onclick="trSetInstanceProp(' + ti.tid + ',\'chunkLevel\',\'standard\')" title="주어 6+단어 기준">실전</button>' +
        '<span class="tr-inst-sep">│</span>' +
        '<button class="tr-ip' + (cmO ? ' ' + onCls : '') + '" onclick="trSetInstanceProp(' + ti.tid + ',\'chunkMode\',\'original\')" title="원문에 직접 밑줄 출제">원문</button>' +
        '<button class="tr-ip' + (cmP ? ' ' + onCls : '') + '" onclick="trSetInstanceProp(' + ti.tid + ',\'chunkMode\',\'paraphrase\')" title="구문 포인트 최대 2개 교체">패러</button>';
    }

    return '<div class="tr-inst-row">' +
      '<span class="tr-inst-lbl"><span style="color:' + dotColor + ';margin-right:3px">●</span>' + label + '</span>' +
      '<div class="tr-inst-pills">' + pills + '</div>' +
      '<button class="tr-inst-del" onclick="trRemoveTypeInstance(' + ti.tid + ')" title="삭제">✕</button>' +
    '</div>';
  }).join('');

  var noInstMsg = insts.length === 0
    ? '<div style="font-size:11px;color:#9CA3AF;text-align:center;padding:6px 0">유형을 클릭해 추가하세요</div>'
    : '';

  html +=
    '<div class="card">' +
      '<div class="card-hd"><span>유형 · 설정</span><span class="aux">클릭으로 추가</span></div>' +
      '<div style="padding:10px 14px 4px"><div class="type-grid">' + chips + '</div></div>' +
      '<div style="padding:0 14px ' + (insts.length > 0 ? '2' : '10') + 'px">' +
        (insts.length > 0 ? instRows : noInstMsg) +
      '</div>' +
      '<div style="padding:6px 14px 12px"><button class="submit-btn" style="background:#7C3AED;padding:8px' + (insts.length === 0 ? ';opacity:.55;cursor:not-allowed' : '') + '" ' +
        (insts.length === 0 ? 'disabled title="문법 · 지문이해 · 해석훈련 중 하나를 먼저 선택하세요"' : 'onclick="trRunSingle()"') + '>' +
        (insts.length === 0 ? '유형 선택 후 출제' : '⚡ 이 지문 출제') +
      '</button></div>' +
    '</div>';

  /* ── 결과 카드(들) ── */
  if (p.status === 'done' || p.status === 'error') {
    var resSeenCount = {};
    insts.forEach(function(ti) {
      resSeenCount[ti.key] = (resSeenCount[ti.key] || 0) + 1;
      var res = p.results && p.results[ti.tid];
      var instLabel = TYPE_LABELS[ti.key] + (typeCounts[ti.key] > 1 ? ' #' + resSeenCount[ti.key] : '');
      if (res) {
        var tmpDiv = document.createElement('div');
        if      (ti.key === 'grammar') _trRenderResultCard(p, idx, tmpDiv, ti.tid, instLabel);
        else if (ti.key === 'logic')   _lgRenderResultCard(p, idx, tmpDiv, ti.tid, instLabel);
        else if (ti.key === 'chunk')   _chunRenderResultCard(p, idx, tmpDiv, ti.tid, instLabel);
        html += tmpDiv.innerHTML;
      } else if (p.status === 'error') {
        html += '<div class="card"><div style="padding:12px 16px;font-size:11px;color:#EF4444">' + instLabel + ' 출제 실패</div></div>';
      }
    });
  }

  rp.innerHTML = html;
  _applyTrainingTooltips(rp);
}

/* ── 유형 인스턴스 관리 ── */
function trAddType(key) {
  _trSaveEditText();
  var p = _trPassages.find(function(x) { return x.id === _trSelectedId; });
  if (!p) return;
  if (!p.typeInstances) p.typeInstances = [];
  if (!p._tidCounter) p._tidCounter = 0;
  var tid = ++p._tidCounter;
  var defaults = key === 'grammar' ? { questionMode: 'underline', wordMode: 'single', passageMode: 'original' }
               : key === 'logic'   ? { lgLevel: 'standard' }
               :                     { chunkMode: 'original', chunkLevel: 'standard' };
  p.typeInstances.push(Object.assign({ tid: tid, key: key }, defaults));
  _trRenderQueue();
  _trRenderRight();
}

function trRemoveTypeInstance(tid) {
  var p = _trPassages.find(function(x) { return x.id === _trSelectedId; });
  if (!p) return;
  p.typeInstances = (p.typeInstances || []).filter(function(ti) { return ti.tid !== tid; });
  if (p.results) delete p.results[tid];
  _trRenderQueue();
  _trRenderRight();
}

function trSetInstanceProp(tid, prop, val) {
  var p = _trPassages.find(function(x) { return x.id === _trSelectedId; });
  if (!p) return;
  var ti = (p.typeInstances || []).find(function(t) { return t.tid === tid; });
  if (ti) ti[prop] = val;
  _trRenderRight();
}

/* ── 단일 지문 출제 (선택된 모든 유형) ── */
async function trRunSingle() {
  _trSaveEditText();
  var p = _trPassages.find(function(x) { return x.id === _trSelectedId; });
  if (!p || !p.text.trim()) { showToast('지문을 입력하세요'); return; }
  if (!p.typeInstances || p.typeInstances.length === 0) { showToast('유형을 선택하세요'); return; }
  if (_trRunning) { showToast('이미 출제 중입니다'); return; }

  _trRunning = true;
  _trTokStats = {};
  p.status = 'processing';
  p.results = {};
  _trRenderQueue(); _trRenderRight();

  /* gp-box 표시 및 타이머 시작 */
  var gpBox   = document.getElementById('tr-gp-box');
  var gpCount = document.getElementById('tr-gp-count');
  var gpFill  = document.getElementById('tr-gp-fill');
  var gpLabel = document.getElementById('tr-gp-label');
  var gpTime  = document.getElementById('tr-gp-time');
  var total   = p.typeInstances.length;
  if (gpBox)   { gpBox.style.display = 'flex'; gpBox.classList.remove('done'); }
  if (gpCount) gpCount.textContent = '0 / ' + total;
  if (gpFill)  gpFill.style.width  = '0%';
  if (gpTime)  gpTime.textContent  = '0초';

  var startTime = Date.now();
  var timerInterval = setInterval(function() {
    var sec = Math.round((Date.now() - startTime) / 1000);
    if (gpTime) gpTime.textContent = sec + '초';
  }, 500);

  var modelId = (document.getElementById('tr-pv-design') || document.getElementById('tr-pv-model') || {}).value || 'claude-sonnet-4-6';
  var anyError = false;
  var callsDone = 0;

  for (var i = 0; i < p.typeInstances.length; i++) {
    var inst = p.typeInstances[i];
    var key  = inst.key;
    var tid  = inst.tid;
    callsDone++;
    if (gpCount) gpCount.textContent = callsDone + ' / ' + total;
    if (gpFill)  gpFill.style.width  = Math.round((callsDone / total) * 100) + '%';
    if (gpLabel) gpLabel.textContent = (key === 'grammar' ? '문법' : key === 'chunk' ? '해석훈련' : '지문이해') + ' 출제 중…';
    try {
      var system  = key === 'grammar' ? _trBuildSystem(inst.wordMode, inst.passageMode, inst.questionMode)
                  : key === 'chunk'   ? _chunBuildSystem(inst.chunkMode, inst.chunkLevel)
                  :                     _lgBuildSystem(inst.lgLevel);
      var userMsg = key === 'grammar'
        ? ((inst.questionMode === 'choice')
            ? ((inst.passageMode === 'paraphrase')
                ? '다음 영어 원문 지문을 패러프레이즈하여 새로운 문장으로 재구성한 뒤, 문법 훈련 A/B 선택형 문제를 출제해 주세요:\n\n' + p.text.trim()
                : '다음 영어 지문으로 기본기 훈련 A/B 선택형 문제를 출제해 주세요:\n\n' + p.text.trim())
            : (inst.passageMode === 'paraphrase')
            ? '다음 영어 원문 지문을 패러프레이즈하여 새로운 문장으로 재구성한 뒤, 문법 훈련 밑줄 문제를 출제해 주세요. 원문과 겹치지 않는 새로운 문법 포인트를 중심으로 출제하세요:\n\n' + p.text.trim()
            : '다음 영어 지문으로 기본기 훈련 문제를 출제해 주세요:\n\n' + p.text.trim())
        : key === 'chunk'
        ? ((inst.chunkMode === 'paraphrase')
            ? '다음 영어 원문 지문의 구문 포인트를 최대 2개만 교체하여 패러프레이즈한 뒤, 끊어읽기 워크시트를 출제해 주세요:\n\n' + p.text.trim()
            : '다음 영어 지문으로 끊어읽기 워크시트를 출제해 주세요:\n\n' + p.text.trim())
        : '다음 영어 지문으로 지문이해 확인 문제를 출제해 주세요:\n\n' + p.text.trim();
      var raw    = await _trAPICall(system, userMsg, modelId);
      var parsed = _parseTrainingJsonOrThrow(raw, key);

      /* ── 주관식 2차 검수 ── */
      if (key === 'logic' && parsed) {
        if (gpLabel) gpLabel.textContent = '지문이해 검수 중…';
        try {
          var verifyMsg = '[영어 지문]\n' + p.text.trim() +
            '\n\n[1차 출제 결과]\n' + JSON.stringify(parsed, null, 2);
          var raw2    = await _trAPICall(_lgBuildVerifySystem(inst.lgLevel), verifyMsg, modelId);
          var parsed2 = _parseTrainingJsonOrThrow(raw2, 'logic verify');
          if (parsed2 && (parsed2.content_questions || parsed2.contentQuestions || parsed2.advanced_questions || parsed2.advancedQuestions)) parsed = parsed2;
        } catch(ve) { /* 검수 실패 시 1차 결과 사용 */ }
      }

      if (key === 'grammar') {
        p.results[tid] = {
          questionMode: inst.questionMode || 'underline',
          passageText: p.text.trim(),
          originalPassage: parsed.original_passage || '',
          passageWithMarks: parsed.passage_with_marks || '',
          passageWithChoices: parsed.passage_with_choices || '',
          items: parsed.items || [],
          modelId: modelId
        };
      } else if (key === 'chunk') {
        p.results[tid] = { passageText: p.text.trim(), originalPassage: parsed.original_passage || '', passageUsed: parsed.passage_text || p.text.trim(), items: parsed.items || [], modelId: modelId };
      } else {
        p.results[tid] = { passageText: p.text.trim(), passageStructure: parsed.passage_structure || parsed.passageStructure || '', verificationNotes: parsed.verification_notes || parsed.verificationNotes || '', contentQuestions: parsed.content_questions || parsed.contentQuestions || [], advancedQuestions: parsed.advanced_questions || parsed.advancedQuestions || [], modelId: modelId };
      }
    } catch(e) {
      anyError = true;
      p.results[tid] = null;
      p.errors = p.errors || {};
      p.errors[tid] = e.message;
      console.error('[TR grammar] tid=' + tid + ' error:', e);
    }
  }

  clearInterval(timerInterval);
  var elapsedSec = Math.round((Date.now() - startTime) / 1000);
  if (gpBox)   { gpBox.classList.add('done'); }
  if (gpCount) gpCount.textContent = total + ' / ' + total;
  if (gpFill)  gpFill.style.width  = '100%';
  if (gpLabel) gpLabel.textContent = anyError ? '일부 출제 실패' : '완료! (' + elapsedSec + '초)';
  if (gpTime)  gpTime.textContent  = elapsedSec + '초';
  var wordAllBtn = document.getElementById('tr-word-all-btn');
  if (wordAllBtn) wordAllBtn.style.display = '';
  ['tr-json-all-btn','tr-json-view-btn','tr-json-copy-all-btn'].forEach(function(id) {
    var el = document.getElementById(id); if (el) el.style.display = '';
  });

  var successCount = Object.keys(p.results || {}).filter(function(k) { return !!p.results[k]; }).length;
  p.status = successCount > 0 ? 'done' : 'error';
  _trRunning = false;
  _trRenderQueue(); _trRenderRight();
}

function _trLivePreview() {
  var ta = document.getElementById('tr-edit-ta');
  var p  = _trPassages.find(function(x) { return x.id === _trSelectedId; });
  if (ta && p) p.text = ta.value;
}

var _TR_POINT_CLASS  = ['p1','p2','p3','p4','p5','p6','p7'];
var _TR_POINT_CIRCLE = ['①','②','③','④','⑤','⑥','⑦'];

/* ── 토큰 추적 (기본기 훈련 탭 전용) ── */
var _trTokStats = {};
var _trStopFlag = false;

function _trAddTokens(modelId, inputTok, outputTok) {
  var price = _PRICING[modelId] || { input: 5.00, output: 15.00 };
  if (!_trTokStats[modelId]) _trTokStats[modelId] = { input: 0, output: 0, costUSD: 0 };
  _trTokStats[modelId].input   += inputTok;
  _trTokStats[modelId].output  += outputTok;
  _trTokStats[modelId].costUSD += (inputTok * price.input + outputTok * price.output) / 1e6;
  _trRenderCost();
}

function _trRenderCost() {
  var el = document.getElementById('tr-gp-cost');
  if (!el) return;
  var models = Object.keys(_trTokStats);
  if (models.length === 0) { el.innerHTML = ''; return; }
  var totalIn = 0, totalOut = 0, totalUSD = 0;
  var rows = models.map(function(m) {
    var s = _trTokStats[m];
    totalIn += s.input; totalOut += s.output; totalUSD += s.costUSD;
    var inTok  = s.input.toLocaleString();
    var outTok = s.output.toLocaleString();
    var usd    = '$' + s.costUSD.toFixed(4);
    var label  = m.replace('claude-','').replace('gemini-','Gemini ').replace('gpt-','GPT-').replace('-preview','');
    return '<div class="gp-cost-row">' +
      '<span class="gp-cost-model" title="' + m + '">' + label + '</span>' +
      '<span class="gp-cost-val" style="font-size:9px">' +
        '<span style="color:#3B82F6" title="입력">↑' + inTok + '</span>' +
        ' <span style="color:#059669" title="출력">↓' + outTok + '</span>' +
        ' · ' + usd +
      '</span>' +
    '</div>';
  });
  var totalTok = (totalIn + totalOut).toLocaleString();
  var totalUSD2 = '$' + totalUSD.toFixed(4);
  var totalKRW  = '≈ ₩' + Math.round(totalUSD * 1380).toLocaleString();
  rows.push('<div class="gp-cost-total">' +
    '<span>합계 ' + totalTok + ' tok</span>' +
    '<span class="gp-cost-val">' + totalUSD2 + ' ' + totalKRW + '</span>' +
  '</div>');
  el.innerHTML = rows.join('');
}

/* _callAPI 래퍼: 훈련 탭 전용 토큰 추적 */
async function _trAPICall(system, userMsg, modelId) {
  var cfg = _detectProvider(modelId);
  var snapBefore = {};
  Object.keys(_tokStats).forEach(function(m) { snapBefore[m] = Object.assign({}, _tokStats[m]); });

  var raw;
  if (cfg.type === 'gemini') {
    raw = await _callGemini(system, userMsg, cfg.model, null, 'training');
  } else if (cfg.type === 'openai') {
    raw = await _callOpenAI(system, userMsg, cfg.model, null, 'training');
  } else {
    var apiKey = (cfg.type === 'fable' && getFableKey()) || getKey();
    if (!apiKey) throw new Error('Claude API 키가 필요합니다 (문제 출제 탭에서 저장)');
    raw = await _callAPI(system, userMsg, apiKey, 3, null, 'training', cfg.model);
  }

  /* 델타 계산 → 훈련 탭 통계에 반영 */
  Object.keys(_tokStats).forEach(function(m) {
    var before = snapBefore[m] || { input: 0, output: 0, costUSD: 0 };
    var after  = _tokStats[m];
    var dIn  = after.input   - before.input;
    var dOut = after.output  - before.output;
    var dCost= after.costUSD - before.costUSD;
    if (dIn > 0 || dOut > 0) {
      if (!_trTokStats[m]) _trTokStats[m] = { input: 0, output: 0, costUSD: 0 };
      _trTokStats[m].input   += dIn;
      _trTokStats[m].output  += dOut;
      _trTokStats[m].costUSD += dCost;
    }
  });
  _trRenderCost();
  return raw;
}

/* ── 전체 순차 출제 ── */
async function runTraining() {
  if (_trRunning) return;
  _trSaveEditText();
  var toRun = _trPassages.filter(function(p) { return p.text.trim().length > 0 && p.typeInstances && p.typeInstances.length > 0; });
  if (toRun.length === 0) { showToast('지문을 입력하고 유형을 선택하세요'); return; }

  /* 총 API 호출 수 = 각 지문의 인스턴스 수 합산 */
  var totalCalls = toRun.reduce(function(sum, p) { return sum + (p.typeInstances || []).length; }, 0);

  _trRunning = true;
  _trStopFlag = false;
  _trTokStats = {};

  var runBtn  = document.getElementById('tr-run-btn');
  var stopBtn = document.getElementById('tr-stop-btn');
  var gpBox   = document.getElementById('tr-gp-box');
  var gpCount = document.getElementById('tr-gp-count');
  var gpFill  = document.getElementById('tr-gp-fill');
  var gpLabel = document.getElementById('tr-gp-label');
  var gpTime  = document.getElementById('tr-gp-time');
  var inspBtn = document.getElementById('tr-inspect-btn');
  var sumLine = document.getElementById('tr-summary-line');

  runBtn.disabled = true;
  if (stopBtn) { stopBtn.style.display = ''; stopBtn.textContent = '⏹ 출제 중지'; }
  if (gpBox)   { gpBox.style.display = 'flex'; gpBox.classList.remove('done'); }
  if (inspBtn) inspBtn.style.display = 'none';

  var startTime = Date.now();
  var timerInterval = setInterval(function() {
    var sec = Math.round((Date.now() - startTime) / 1000);
    if (gpTime) gpTime.textContent = sec + '초';
  }, 500);

  var modelId = (document.getElementById('tr-pv-design') || document.getElementById('tr-pv-model') || {}).value || 'claude-sonnet-4-6';
  var callsDone = 0;

  for (var i = 0; i < toRun.length; i++) {
    if (_trStopFlag) break;
    var p = toRun[i];
    p.status = 'processing';
    p.results = {};
    _trRenderQueue();
    if (_trSelectedId === p.id) _trRenderRight();

    var anyError = false;
    for (var j = 0; j < p.typeInstances.length; j++) {
      if (_trStopFlag) break;
      var inst = p.typeInstances[j];
      var key  = inst.key;
      var tid  = inst.tid;
      callsDone++;
      if (gpCount) gpCount.textContent = callsDone + ' / ' + totalCalls;
      if (gpFill)  gpFill.style.width  = Math.round((callsDone / totalCalls) * 100) + '%';
      if (gpLabel) gpLabel.textContent = '지문 ' + (i + 1) + ' · ' + (key === 'grammar' ? '문법' : key === 'chunk' ? '해석훈련' : '지문이해') + ' 출제 중…';

      try {
        var system  = key === 'grammar' ? _trBuildSystem(inst.wordMode, inst.passageMode, inst.questionMode)
                    : key === 'chunk'   ? _chunBuildSystem(inst.chunkMode, inst.chunkLevel)
                    :                     _lgBuildSystem(inst.lgLevel);
        var userMsg = key === 'grammar'
          ? ((inst.questionMode === 'choice')
              ? ((inst.passageMode === 'paraphrase')
                  ? '다음 영어 원문 지문을 패러프레이즈하여 새로운 문장으로 재구성한 뒤, 문법 훈련 A/B 선택형 문제를 출제해 주세요:\n\n' + p.text.trim()
                  : '다음 영어 지문으로 기본기 훈련 A/B 선택형 문제를 출제해 주세요:\n\n' + p.text.trim())
              : (inst.passageMode === 'paraphrase')
              ? '다음 영어 원문 지문을 패러프레이즈하여 새로운 문장으로 재구성한 뒤, 문법 훈련 밑줄 문제를 출제해 주세요. 원문과 겹치지 않는 새로운 문법 포인트를 중심으로 출제하세요:\n\n' + p.text.trim()
              : '다음 영어 지문으로 기본기 훈련 문제를 출제해 주세요:\n\n' + p.text.trim())
          : key === 'chunk'
          ? ((inst.chunkMode === 'paraphrase')
              ? '다음 영어 원문 지문의 구문 포인트를 최대 2개만 교체하여 패러프레이즈한 뒤, 끊어읽기 워크시트를 출제해 주세요:\n\n' + p.text.trim()
              : '다음 영어 지문으로 끊어읽기 워크시트를 출제해 주세요:\n\n' + p.text.trim())
          : '다음 영어 지문으로 지문이해 확인 문제를 출제해 주세요:\n\n' + p.text.trim();
        var raw    = await _trAPICall(system, userMsg, modelId);
        var parsed = _parseTrainingJsonOrThrow(raw, key);

        /* ── 주관식 2차 검수 ── */
        if (key === 'logic' && parsed && !_trStopFlag) {
          if (gpLabel) gpLabel.textContent = '지문 ' + (i + 1) + ' · 지문이해 검수 중…';
          try {
            var verifyMsg2 = '[영어 지문]\n' + p.text.trim() +
              '\n\n[1차 출제 결과]\n' + JSON.stringify(parsed, null, 2);
            var raw2b    = await _trAPICall(_lgBuildVerifySystem(inst.lgLevel), verifyMsg2, modelId);
            var parsed2b = _parseTrainingJsonOrThrow(raw2b, 'logic verify');
            if (parsed2b && (parsed2b.content_questions || parsed2b.contentQuestions || parsed2b.advanced_questions || parsed2b.advancedQuestions)) parsed = parsed2b;
          } catch(ve2) { /* 검수 실패 시 1차 결과 사용 */ }
        }

        if (key === 'grammar') {
          p.results[tid] = {
            questionMode: inst.questionMode || 'underline',
            passageText: p.text.trim(),
            originalPassage: parsed.original_passage || '',
            passageWithMarks: parsed.passage_with_marks || '',
            passageWithChoices: parsed.passage_with_choices || '',
            items: parsed.items || [],
            modelId: modelId
          };
        } else if (key === 'chunk') {
          p.results[tid] = { passageText: p.text.trim(), originalPassage: parsed.original_passage || '', passageUsed: parsed.passage_text || p.text.trim(), items: parsed.items || [], modelId: modelId };
        } else {
          p.results[tid] = { passageText: p.text.trim(), passageStructure: parsed.passage_structure || parsed.passageStructure || '', verificationNotes: parsed.verification_notes || parsed.verificationNotes || '', contentQuestions: parsed.content_questions || parsed.contentQuestions || [], advancedQuestions: parsed.advanced_questions || parsed.advancedQuestions || [], modelId: modelId };
        }
      } catch (e) {
        anyError = true;
        p.results[tid] = null;
        p.errors = p.errors || {};
        p.errors[tid] = e.message;
        console.error('[TR runTraining] tid=' + tid + ' error:', e);
      }
    }

    var successCount = Object.keys(p.results || {}).filter(function(k) { return !!p.results[k]; }).length;
    p.status = successCount > 0 ? 'done' : 'error';
    _trRenderQueue();
    if (_trSelectedId === p.id) _trRenderRight();
    if (_trSelectedId === null) { _trSelectedId = p.id; _trRenderQueue(); _trRenderRight(); }
  }

  clearInterval(timerInterval);
  _trRunning = false;
  runBtn.disabled = false;
  if (stopBtn) stopBtn.style.display = 'none';

  var doneCnt = _trPassages.filter(function(p) { return p.status === 'done'; }).length;
  var errCnt  = _trPassages.filter(function(p) { return p.status === 'error'; }).length;

  var elapsedSec2 = Math.round((Date.now() - startTime) / 1000);
  if (gpBox)   { gpBox.classList.add('done'); }
  if (gpCount) gpCount.textContent = doneCnt + ' / ' + toRun.length;
  if (gpFill)  gpFill.style.width  = '100%';
  if (gpLabel) gpLabel.textContent = _trStopFlag ? '출제 중지됨' : (errCnt > 0 ? errCnt + '개 오류 발생' : '완료! (' + elapsedSec2 + '초)');
  if (gpTime)  gpTime.textContent  = elapsedSec2 + '초';
  if (sumLine) sumLine.textContent = doneCnt + '개 완료' + (errCnt > 0 ? ' · 오류 ' + errCnt + '개' : '');
  if (inspBtn && doneCnt > 0) inspBtn.style.display = '';
  var wordAllBtn2 = document.getElementById('tr-word-all-btn');
  if (wordAllBtn2 && doneCnt > 0) wordAllBtn2.style.display = '';
  if (doneCnt > 0) {
    ['tr-json-all-btn','tr-json-view-btn','tr-json-copy-all-btn'].forEach(function(id) {
      var el = document.getElementById(id); if (el) el.style.display = '';
    });
  }

  if (!_trPassages.find(function(p) { return p.id === _trSelectedId && p.status === 'done'; })) {
    var firstDone = _trPassages.find(function(p) { return p.status === 'done'; });
    if (firstDone) { _trSelectedId = firstDone.id; _trRenderQueue(); _trRenderRight(); }
  }

  /* 완료 시 자동 Word 다운로드 */
  if (doneCnt > 0 && !_trStopFlag) trDownloadAllWord();
}

function stopTraining() {
  _trStopFlag = true;
  var stopBtn = document.getElementById('tr-stop-btn');
  if (stopBtn) stopBtn.textContent = '중지 중...';
}

function openTrInspect() {
  /* 완료된 기본기 훈련 결과 요약을 inspect 패널에 표시 */
  var panel = document.getElementById('inspect-panel');
  if (!panel) return;
  panel.style.display = 'flex';
  var body = document.getElementById('inspect-body');
  if (!body) return;

  var done = _trPassages.filter(function(p) { return p.status === 'done'; });
  if (done.length === 0) { body.innerHTML = '<div class="isp-loading">완료된 지문이 없습니다.</div>'; return; }

  var html = '';
  done.forEach(function(p) {
    var idx = _trPassages.indexOf(p) + 1;
    var seenCount = {};
    (p.typeInstances || []).forEach(function(ti) {
      seenCount[ti.key] = (seenCount[ti.key] || 0) + 1;
      var res = p.results && p.results[ti.tid];
      if (!res) return;
      var typeCnt = (p.typeInstances || []).filter(function(t) { return t.key === ti.key; }).length;
      var typeKr  = ti.key === 'grammar' ? '문법' : ti.key === 'chunk' ? '해석훈련' : '지문이해';
      var instLabel = typeKr + (typeCnt > 1 ? ' #' + seenCount[ti.key] : '');
      if (ti.key === 'grammar') {
        var errCnt = (res.items || []).filter(function(it) { return it.is_error; }).length;
        html += '<div class="imp-card" style="margin-bottom:8px"><div class="imp-head">' +
          '<span class="imp-sev medium">' + instLabel + '</span>' +
          '<span class="imp-pattern">지문 ' + idx + ' · 밑줄 ' + (res.items||[]).length + '개 · 오류 ' + errCnt + '개</span>' +
          '</div><div class="imp-body"><div class="imp-meta">문장: ' +
          ((ti.passageMode||'original') === 'paraphrase' ? '패러프레이즈' : '원문') +
          ' · 범위: ' + (ti.wordMode === 'multi' ? '여러 단어' : '한 단어') +
          '</div></div></div>';
      } else if (ti.key === 'logic') {
        var cq = (res.contentQuestions || []).length;
        var aq = (res.advancedQuestions || []).length;
        html += '<div class="imp-card" style="margin-bottom:8px"><div class="imp-head">' +
          '<span class="imp-sev low">' + instLabel + '</span>' +
          '<span class="imp-pattern">지문 ' + idx + ' · 내용확인 ' + cq + '문항 · 심화 ' + aq + '문항</span>' +
          '</div><div class="imp-body"><div class="imp-meta">레벨: ' +
          ({'basic':'기본','standard':'실전','advanced':'심화'}[ti.lgLevel||'standard'] || '실전') +
          (res.passageStructure ? ' · 구조: ' + res.passageStructure : '') +
          '</div></div></div>';
      } else if (ti.key === 'chunk') {
        html += '<div class="imp-card" style="margin-bottom:8px"><div class="imp-head">' +
          '<span class="imp-sev low">' + instLabel + '</span>' +
          '<span class="imp-pattern">지문 ' + idx + ' · 문항 ' + (res.items||[]).length + '개</span>' +
          '</div><div class="imp-body"><div class="imp-meta">난이도: ' +
          (ti.chunkLevel === 'basic' ? '기본' : '실전') +
          ' · 문장: ' + ((ti.chunkMode||'original') === 'paraphrase' ? '패러프레이즈' : '원문') +
          '</div></div></div>';
      }
    });
  });
  body.innerHTML = html || '<div class="isp-loading">분석할 결과가 없습니다.</div>';
}

/* [[N:word]] → <sup>①</sup><span class="tr-ul-word">word</span> 변환 */
function _trParsePassage(raw, items) {
  // items: 번호별 is_error 룩업
  var errorMap = {};
  if (items) items.forEach(function(it) { errorMap[it.number] = !!it.is_error; });

  return escH(raw).replace(/\[\[(\d+):([^\]]+)\]\]/g, function(_, num, word) {
    var n = parseInt(num, 10);
    var circle = ['①','②','③','④','⑤','⑥','⑦','⑧','⑨','⑩'][n - 1] || ('(' + n + ')');
    var isErr = (errorMap[n] !== undefined) ? errorMap[n] : true;
    var ulClass = isErr ? 'tr-ul-word' : 'tr-ul-word correct';
    return '<sup class="tr-ul-num">' + circle + '</sup><span class="' + ulClass + '">' + escH(word) + '</span>';
  });
}

/* [[N:A:foo|B:bar]] → ① [(A) foo / (B) bar] 변환 */
function _trParseChoicePassage(raw) {
  return escH(raw).replace(/\[\[(\d+):A:([^|\]]+)\|B:([^\]]+)\]\]/g, function(_, num, a, b) {
    var n = parseInt(num, 10);
    var circle = ['①','②','③','④','⑤','⑥','⑦','⑧','⑨','⑩'][n - 1] || ('(' + n + ')');
    return '<sup class="tr-ul-num">' + circle + '</sup>' +
      '<span class="tr-choice-inline">[(A) <b>' + escH(a) + '</b> / (B) <b>' + escH(b) + '</b>]</span>';
  });
}

function _trChoiceAnswerText(item) {
  var ans = String(item.answer || '').trim().toUpperCase().replace(/[^AB]/g, '');
  if (ans !== 'A' && ans !== 'B') {
    var answerText = String(item.answer_text || '').trim();
    if (answerText && answerText === String(item.choice_B || '').trim()) ans = 'B';
    else ans = 'A';
  }
  var text = item.answer_text || (ans === 'B' ? item.choice_B : item.choice_A) || '';
  return { label: ans, text: text };
}

function _trSelectChoiceAnswer(btn) {
  var wrap = btn && btn.parentElement;
  if (!wrap) return;
  Array.prototype.forEach.call(wrap.querySelectorAll('.tr-ip'), function(b) {
    b.classList.remove('on-purp');
  });
  btn.classList.add('on-purp');
}

function _trRenderChoiceResultCard(p, idx, rp, tid, instLabel) {
  var result = p.results && p.results[tid];
  var inst = (p.typeInstances || []).find(function(t) { return t.tid === tid; }) || {};
  var isPara = !!(result && result.originalPassage);
  var modeLabel = isPara ? '패러프레이즈 · 선택' : '원문 · 선택';
  var cardTitle = instLabel ? ('지문 ' + idx + ' · ' + instLabel) : ('지문 ' + idx + ' · 기본기 훈련');
  var html = '<div class="card">';
  html += '<div class="card-hd"><span>' + cardTitle + '</span><span class="aux" style="color:#7C3AED;font-weight:600">' + modeLabel + '</span></div>';

  if (!result || !result.items || result.items.length === 0) {
    html += '<div style="padding:12px 16px;font-size:11px;color:#9CA3AF">해당 지문에서 출제 가능한 문항이 없습니다.</div></div>';
    rp.innerHTML = html;
    return;
  }

  var pid = p.id;
  if (isPara && result.originalPassage) {
    var origId = 'tr-orig-' + pid + '-' + tid;
    html += '<div style="padding:8px 16px 0">' +
      '<button class="tr-key-btn" id="' + origId + '-btn" onclick="_trToggleOrig(\'' + origId + '\')" style="font-size:10px;padding:3px 10px">원문 보기</button>' +
      '</div>' +
      '<div class="tr-key-block" id="' + origId + '-key" style="margin:6px 16px 0;border-radius:7px;background:#F9FAFB;border:1px solid var(--bdr);padding:10px 12px;font-size:11px;line-height:1.7;color:#374151">' +
        escH(result.originalPassage) +
      '</div>';
  }

  html += '<div style="padding:12px 16px 10px">' +
    '<div style="font-size:10px;font-weight:600;color:#9CA3AF;text-transform:uppercase;letter-spacing:.06em;margin-bottom:7px">' +
      (isPara ? '패러프레이즈 지문' : '지문') +
    '</div>' +
    '<div class="tr-passage-display">' +
      _trParseChoicePassage(result.passageWithChoices || result.passageText) +
    '</div>' +
  '</div>';

  html += '<div style="padding:4px 16px 8px;font-size:11px;color:#374151">각 번호의 A/B 중 알맞은 표현을 고르고, 그 이유를 적으세요.</div>';
  html += '<div class="tr-answer-table">';
  html += '<div class="tr-at-header">' +
    '<div class="tr-at-num">번호</div>' +
    '<div class="tr-at-point">어법 포인트</div>' +
    '<div class="tr-at-fix">선택</div>' +
    '<div class="tr-at-reason">이 유</div>' +
  '</div>';
  result.items.forEach(function(item) {
    var n = item.number || 1;
    var pNum = ((item.point_number || 1) - 1);
    var pClass = _TR_POINT_CLASS[Math.min(pNum, 6)];
    var circle = ['①','②','③','④','⑤','⑥','⑦','⑧','⑨','⑩'][n - 1] || ('(' + n + ')');
    html += '<div class="tr-at-row">' +
      '<div class="tr-at-num"><span class="tr-ul-num-badge">' + circle + '</span></div>' +
      '<div class="tr-at-point">' +
        '<span class="tr-ex-point ' + pClass + '" style="font-size:9px">' + escH(item.point_name || '') + '</span>' +
        (item.catalog_ref ? '<br><span style="font-size:9px;color:#9CA3AF">' + escH(item.catalog_ref) + '</span>' : '') +
      '</div>' +
      '<div class="tr-at-fix">' +
        '<button type="button" class="tr-ip" onclick="_trSelectChoiceAnswer(this)" style="margin-right:4px">(A)</button>' +
        '<button type="button" class="tr-ip" onclick="_trSelectChoiceAnswer(this)">(B)</button>' +
      '</div>' +
      '<div class="tr-at-reason"><input class="tr-answer-input" type="text" placeholder="이유 작성"></div>' +
    '</div>';
  });
  html += '</div>';

  var keyId = 'trkey-' + pid + '-' + tid;
  html += '<div style="padding:10px 16px 4px;display:flex;justify-content:flex-end">' +
    '<button class="tr-key-btn" id="' + keyId + '-btn" onclick="_trToggleKey(\'' + keyId + '\')">정답 확인</button>' +
  '</div>';

  html += '<div class="tr-key-block" id="' + keyId + '-key">';
  result.items.forEach(function(item) {
    var n = item.number || 1;
    var circle = ['①','②','③','④','⑤','⑥','⑦','⑧','⑨','⑩'][n - 1] || ('(' + n + ')');
    var ans = _trChoiceAnswerText(item);
    html += '<div class="tr-key-row is-correct">' +
      '<span class="tr-key-circle">' + circle + '</span>' +
      '<div class="tr-key-content">' +
        '<span class="tr-key-verdict ok">✓ ' + escH(ans.label) + '</span> — <b>' + escH(ans.text) + '</b>' +
        '<div style="font-size:10px;color:#374151;margin-top:3px;line-height:1.55">' + escH(item.reason_ko || '') + '</div>' +
      '</div>' +
    '</div>';
  });
  html += '</div>';

  var jkey = pid + '-' + tid;
  var jfilename = '문법선택_지문' + idx + '_tid' + tid;
  _trJsonCache[jkey] = _trBuildInstanceJson(pid, tid);
  var _jbtnStyle = 'font-size:10px;padding:4px 10px;border:1px solid #D1D5DB;border-radius:5px;background:#F9FAFB;color:#374151;cursor:pointer';
  html += '<div style="padding:10px 16px 14px;display:flex;gap:8px;flex-wrap:wrap;align-items:center">' +
    '<button class="tr-word-dl-btn" onclick="_trDownloadWordById(' + pid + ',' + tid + ')">📄 Word 다운로드</button>' +
    '<button id="tr-json-btn-' + jkey + '" onclick="_trToggleJson(\'' + jkey + '\')" style="' + _jbtnStyle + '">{ } JSON 보기</button>' +
    '<button onclick="_trDownloadJson(\'' + jkey + '\',\'' + jfilename + '\')" style="' + _jbtnStyle + '">⬇ JSON 다운로드</button>' +
  '</div>' +
  '<pre id="tr-json-' + jkey + '" style="display:none;margin:0 16px 14px;padding:10px 12px;background:#1E293B;color:#7DD3FC;font-size:10px;line-height:1.6;border-radius:7px;overflow-x:auto;white-space:pre-wrap;word-break:break-all"></pre>';

  html += '</div>';
  rp.innerHTML = html;
}

/* ── 결과 카드 렌더 (단일 지문) ── */
function _trRenderResultCard(p, idx, rp, tid, instLabel) {
  var result     = p.results && p.results[tid];
  if (result && (result.questionMode === 'choice' || result.passageWithChoices)) {
    _trRenderChoiceResultCard(p, idx, rp, tid, instLabel);
    return;
  }
  var inst       = (p.typeInstances || []).find(function(t) { return t.tid === tid; }) || {};
  var isPara     = !!(result && result.originalPassage);
  var modeLabel  = isPara ? '패러프레이즈' : '원문';
  var cardTitle  = instLabel ? ('지문 ' + idx + ' · ' + instLabel) : ('지문 ' + idx + ' · 기본기 훈련');
  var html       = '<div class="card">';
  html += '<div class="card-hd"><span>' + cardTitle + '</span>' +
    '<span class="aux" style="' + (isPara ? 'color:#7C3AED;font-weight:600' : '') + '">' + modeLabel + '</span>' +
  '</div>';

  /* ── 메타 정보 ── */
  if (result) {
    var wordModeLabel = (inst.wordMode === 'multi') ? '다단어' : '한단어';
    var metaModel = result.modelId || 'claude-sonnet-4-6';
    html +=
      '<div style="padding:6px 16px 8px;display:flex;flex-wrap:wrap;gap:6px;font-size:10px;color:#374151">' +
        '<span style="background:#EFF6FF;border:1px solid #BFDBFE;border-radius:5px;padding:2px 8px">📝 밑줄: ' + wordModeLabel + '</span>' +
        '<span style="background:#EFF6FF;border:1px solid #BFDBFE;border-radius:5px;padding:2px 8px">📄 지문: ' + modeLabel + '</span>' +
        '<span style="background:#F0FDF4;border:1px solid #BBF7D0;border-radius:5px;padding:2px 8px">🤖 출제 AI: ' + escH(metaModel) + '</span>' +
      '</div>';
  }

  if (!result || !result.items || result.items.length === 0) {
    html += '<div style="padding:12px 16px;font-size:11px;color:#9CA3AF">해당 지문에서 출제 가능한 문항이 없습니다.</div></div>';
    rp.innerHTML = html;
    return;
  }

  var total    = result.items.length;
  var errCount = result.items.filter(function(it) { return it.is_error; }).length;
  var okCount  = total - errCount;
  var pid      = p.id;

  /* 원문 접기 (패러프레이즈 모드일 때만) */
  if (isPara && result.originalPassage) {
    var origId = 'tr-orig-' + pid + '-' + tid;
    html +=
      '<div style="padding:8px 16px 0">' +
        '<button class="tr-key-btn" id="' + origId + '-btn" onclick="_trToggleOrig(\'' + origId + '\')" ' +
          'style="font-size:10px;padding:3px 10px">원문 보기</button>' +
      '</div>' +
      '<div class="tr-key-block" id="' + origId + '-key" style="margin:6px 16px 0;border-radius:7px;background:#F9FAFB;border:1px solid var(--bdr);padding:10px 12px;font-size:11px;line-height:1.7;color:#374151">' +
        escH(result.originalPassage) +
      '</div>';
  }

  /* 지문 (패러프레이즈된 지문 또는 원문) */
  html += '<div style="padding:12px 16px 10px">' +
    '<div style="font-size:10px;font-weight:600;color:#9CA3AF;text-transform:uppercase;letter-spacing:.06em;margin-bottom:7px">' +
      (isPara ? '패러프레이즈 지문' : '지문') +
    '</div>' +
    '<div class="tr-passage-display">' +
      _trParsePassage(result.passageWithMarks || result.passageText, result.items) +
    '</div>' +
  '</div>';

  /* 지시문 + 통계 */
  html += '<div style="padding:4px 16px 8px;display:flex;align-items:center;gap:8px;flex-wrap:wrap">' +
    '<span style="font-size:11px;color:#374151;flex:1">위 지문에서 밑줄 친 부분을 고치고, 그 이유를 올바르게 적으세요.</span>' +
    '<span class="tr-stat-badge err">오류 ' + errCount + '개</span>' +
    '<span class="tr-stat-badge ok">올바름 ' + okCount + '개</span>' +
  '</div>';

  /* 답안 표 */
  html += '<div class="tr-answer-table">';
  html += '<div class="tr-at-header">' +
    '<div class="tr-at-num">번호</div>' +
    '<div class="tr-at-point">어법 포인트</div>' +
    '<div class="tr-at-fix">고친 표현</div>' +
    '<div class="tr-at-reason">이 유</div>' +
  '</div>';

  result.items.forEach(function(item) {
    var n      = item.number || 1;
    var pNum   = ((item.point_number || 1) - 1);
    var pClass = _TR_POINT_CLASS[Math.min(pNum, 6)];
    var circle = ['①','②','③','④','⑤','⑥','⑦','⑧','⑨','⑩'][n - 1] || ('(' + n + ')');

    html += '<div class="tr-at-row">' +
      '<div class="tr-at-num"><span class="tr-ul-num-badge">' + circle + '</span></div>' +
      '<div class="tr-at-point">' +
        '<span class="tr-ex-point ' + pClass + '" style="font-size:9px">' + escH(item.point_name || '') + '</span>' +
        (item.catalog_ref ? '<br><span style="font-size:9px;color:#9CA3AF">' + escH(item.catalog_ref) + '</span>' : '') +
      '</div>' +
      '<div class="tr-at-fix"><input class="tr-answer-input" type="text" placeholder="올바른 표현 or \'올바름\'"></div>' +
      '<div class="tr-at-reason"><input class="tr-answer-input" type="text" placeholder="이유 작성"></div>' +
    '</div>';
  });
  html += '</div>';

  /* 정답 확인 */
  var keyId = 'trkey-' + pid + '-' + tid;
  html += '<div style="padding:10px 16px 4px;display:flex;justify-content:flex-end">' +
    '<button class="tr-key-btn" id="' + keyId + '-btn" onclick="_trToggleKey(\'' + keyId + '\')">정답 확인</button>' +
  '</div>';

  html += '<div class="tr-key-block" id="' + keyId + '-key">';
  result.items.forEach(function(item) {
    var n      = item.number || 1;
    var circle = ['①','②','③','④','⑤','⑥','⑦','⑧','⑨','⑩'][n - 1] || ('(' + n + ')');
    var isErr  = !!item.is_error;
    html += '<div class="tr-key-row' + (isErr ? '' : ' is-correct') + '">' +
      '<span class="tr-key-circle">' + circle + '</span>' +
      '<div class="tr-key-content">' +
        (isErr
          ? '<span class="tr-key-verdict err">✗ 오류</span> → <b>' + escH(item.correction || '') + '</b>'
          : '<span class="tr-key-verdict ok">✓ 올바름</span> — 수정 불필요'
        ) +
        '<div style="font-size:10px;color:#374151;margin-top:3px;line-height:1.55">' + escH(item.reason_ko || '') + '</div>' +
      '</div>' +
    '</div>';
  });
  html += '</div>';

  /* Word 다운로드 + JSON */
  var jkey = pid + '-' + tid;
  var jfilename = '문법_지문' + idx + '_tid' + tid;
  _trJsonCache[jkey] = _trBuildInstanceJson(pid, tid);
  var _jbtnStyle = 'font-size:10px;padding:4px 10px;border:1px solid #D1D5DB;border-radius:5px;background:#F9FAFB;color:#374151;cursor:pointer';
  html += '<div style="padding:10px 16px 14px;display:flex;gap:8px;flex-wrap:wrap;align-items:center">' +
    '<button class="tr-word-dl-btn" onclick="_trDownloadWordById(' + pid + ',' + tid + ')">📄 Word 다운로드</button>' +
    '<button id="tr-json-btn-' + jkey + '" onclick="_trToggleJson(\'' + jkey + '\')" style="' + _jbtnStyle + '">{ } JSON 보기</button>' +
    '<button onclick="_trDownloadJson(\'' + jkey + '\',\'' + jfilename + '\')" style="' + _jbtnStyle + '">⬇ JSON 다운로드</button>' +
  '</div>' +
  '<pre id="tr-json-' + jkey + '" style="display:none;margin:0 16px 14px;padding:10px 12px;background:#1E293B;color:#7DD3FC;font-size:10px;line-height:1.6;border-radius:7px;overflow-x:auto;white-space:pre-wrap;word-break:break-all"></pre>';

  html += '</div>';
  rp.innerHTML = html;
}

function _trToggleKey(keyId) {
  var key = document.getElementById(keyId + '-key');
  var btn = document.getElementById(keyId + '-btn');
  if (!key) return;
  var showing = key.classList.toggle('show');
  if (btn) btn.textContent = showing ? '정답 숨기기' : '정답 확인';
}

function _trToggleOrig(origId) {
  var key = document.getElementById(origId + '-key');
  var btn = document.getElementById(origId + '-btn');
  if (!key) return;
  var showing = key.classList.toggle('show');
  if (btn) btn.textContent = showing ? '원문 닫기' : '원문 보기';
}

function _trToggleJson(jkey) {
  var el  = document.getElementById('tr-json-' + jkey);
  var btn = document.getElementById('tr-json-btn-' + jkey);
  if (!el) return;
  var open = el.style.display === 'none';
  if (open && !el.dataset.loaded) {
    el.textContent = JSON.stringify(_trJsonCache[jkey] || {}, null, 2);
    el.dataset.loaded = '1';
  }
  el.style.display = open ? 'block' : 'none';
  if (btn) btn.textContent = open ? '{ } JSON 닫기' : '{ } JSON 보기';
}

function _trDownloadJson(jkey, filename) {
  var data = _trJsonCache[jkey];
  if (!data) { showToast('JSON 데이터 없음'); return; }
  var blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
  var url  = URL.createObjectURL(blob);
  var a    = document.createElement('a');
  a.href = url; a.download = (filename || jkey) + '.json';
  document.body.appendChild(a); a.click();
  document.body.removeChild(a);
  setTimeout(function() { URL.revokeObjectURL(url); }, 1000);
}

function trDownloadAllWord() { trDownloadAllZip(); }

/* ── 기본기 훈련 JSON 내보내기 / 뷰어 ── */
function _trGetAllJson() {
  var done = _trPassages.filter(function(p) { return p.status === 'done' || p.status === 'error'; });
  if (!done.length) return null;
  return done.map(function(p, i) {
    var errors = p.errors || {};
    return {
      passageIndex: i + 1,
      passageText:  p.text,
      status:       p.status,
      instances:    (p.typeInstances || []).map(function(ti) {
        var res = (p.results || {})[ti.tid] || null;
        return {
          type:    ti.key,
          typeLabel: _trTypeLabel(ti.key),
          settings: (function() {
            var s = {};
            if (ti.key === 'grammar') { s.questionMode = ti.questionMode || 'underline'; s.passageMode = ti.passageMode || 'original'; s.wordMode = ti.wordMode || 'single'; }
            if (ti.key === 'logic')   { s.lgLevel = ti.lgLevel || 'standard'; }
            if (ti.key === 'chunk')   { s.chunkMode = ti.chunkMode || 'original'; s.chunkLevel = ti.chunkLevel || 'standard'; }
            return s;
          })(),
          settingsLabel: _trSettingsLabel(ti),
          modelId: res && res.modelId || null,
          result: res,
          error: errors[ti.tid] || null
        };
      }),
      errorDetails: Object.keys(errors).length ? errors : undefined
    };
  });
}

function trDownloadAllJson() {
  var data = _trGetAllJson();
  if (!data) { showToast('다운로드할 결과가 없습니다'); return; }
  var blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
  var url  = URL.createObjectURL(blob);
  var a    = document.createElement('a');
  var ts   = new Date().toISOString().slice(0, 19).replace(/[:.]/g, '-');
  a.href = url; a.download = '기본기훈련_' + ts + '.json';
  document.body.appendChild(a); a.click(); document.body.removeChild(a);
  setTimeout(function() { URL.revokeObjectURL(url); }, 1000);
  showToast('JSON 다운로드 완료');
}

function trOpenJsonView() {
  var data = _trGetAllJson();
  if (!data) { showToast('표시할 결과가 없습니다'); return; }
  var pre   = document.getElementById('tr-json-pre');
  var modal = document.getElementById('tr-json-modal');
  if (pre)   pre.textContent = JSON.stringify(data, null, 2);
  if (modal) modal.style.display = 'flex';
}

function trCloseJsonView() {
  var modal = document.getElementById('tr-json-modal');
  if (modal) modal.style.display = 'none';
}

function trCopyAllJson() {
  var pre = document.getElementById('tr-json-pre');
  if (!pre || !pre.textContent) return;
  _trCopyJsonText(pre.textContent, 'tr-json-copy-btn', '전체 복사');
}

function trCopyAllJsonDirect() {
  var data = _trGetAllJson();
  if (!data) { showToast('복사할 결과가 없습니다'); return; }
  _trCopyJsonText(JSON.stringify(data, null, 2), 'tr-json-copy-all-btn', '📋 전체 JSON 복사');
}

function _trCopyJsonText(text, btnId, restoreText) {
  if (!text) return;
  navigator.clipboard.writeText(text).then(function() {
    var btn = document.getElementById(btnId);
    if (btn) { btn.textContent = '✓ 복사됨'; setTimeout(function() { btn.textContent = restoreText; }, 2000); }
    showToast('클립보드에 복사됨');
  }).catch(function() {
    var ta = document.createElement('textarea');
    ta.value = text;
    document.body.appendChild(ta); ta.select(); document.execCommand('copy'); document.body.removeChild(ta);
    var btn = document.getElementById(btnId);
    if (btn) { btn.textContent = '✓ 복사됨'; setTimeout(function() { btn.textContent = restoreText; }, 2000); }
    showToast('클립보드에 복사됨');
  });
}

function _trFindInstance(pid, tid) {
  var p = _trPassages.find(function(x) { return x.id === pid; });
  return p && (p.typeInstances || []).find(function(ti) { return ti.tid === tid; });
}

function _trTypeLabel(key) {
  return ({ grammar: '문법', logic: '지문이해', chunk: '해석훈련' })[key] || key || '';
}

function _trSettingsLabel(ti) {
  if (!ti) return '';
  if (ti.key === 'grammar') {
    var q = ti.questionMode === 'choice' ? '선택형' : '밑줄형';
    var p = ti.passageMode === 'paraphrase' ? '패러프레이즈 지문' : '원문 지문';
    var w = ti.wordMode === 'multi' ? '여러 단어 밑줄' : '한 단어 밑줄';
    return q + ' · ' + p + ' · ' + w;
  }
  if (ti.key === 'logic') {
    var lv = ({ basic: '기본', standard: '표준', advanced: '심화' })[ti.lgLevel || 'standard'] || (ti.lgLevel || '표준');
    return '난이도: ' + lv;
  }
  if (ti.key === 'chunk') {
    var cm = ti.chunkMode === 'paraphrase' ? '패러프레이즈 지문' : '원문 지문';
    var cl = ({ basic: '기본', standard: '실전' })[ti.chunkLevel || 'standard'] || (ti.chunkLevel || '실전');
    return cm + ' · 수준: ' + cl;
  }
  return '';
}

function _trResultMeta(pid, tid) {
  var p = _trPassages.find(function(x) { return x.id === pid; });
  var ti = _trFindInstance(pid, tid);
  var res = p && p.results && p.results[tid];
  return {
    ai: (res && res.modelId) || '',
    type: _trTypeLabel(ti && ti.key),
    settings: _trSettingsLabel(ti)
  };
}

function _trMetaHtml(pid, tid) {
  var meta = _trResultMeta(pid, tid);
  var parts = [];
  if (meta.ai) parts.push('사용 AI: ' + meta.ai);
  if (meta.type) parts.push('유형: ' + meta.type);
  if (meta.settings) parts.push('설정: ' + meta.settings);
  return parts.length ? '<div class="meta">' + escH(parts.join(' / ')) + '</div>' : '';
}

function _trBuildInstanceJson(pid, tid) {
  var p = _trPassages.find(function(x) { return x.id === pid; });
  var ti = _trFindInstance(pid, tid);
  var res = p && p.results && p.results[tid];
  if (!p || !ti || !res) return res || null;
  return {
    type: ti.key,
    typeLabel: _trTypeLabel(ti.key),
    settings: (function() {
      var s = {};
      if (ti.key === 'grammar') { s.questionMode = ti.questionMode || 'underline'; s.passageMode = ti.passageMode || 'original'; s.wordMode = ti.wordMode || 'single'; }
      if (ti.key === 'logic')   { s.lgLevel = ti.lgLevel || 'standard'; }
      if (ti.key === 'chunk')   { s.chunkMode = ti.chunkMode || 'original'; s.chunkLevel = ti.chunkLevel || 'standard'; }
      return s;
    })(),
    settingsLabel: _trSettingsLabel(ti),
    modelId: res.modelId || null,
    result: res
  };
}

/* ── Word HTML 빌더 (blob 반환용) ── */
function _trBuildGrammarHtml(pid, tid) {
  var p = _trPassages.find(function(x) { return x.id === pid; });
  var result = p && p.results && p.results[tid];
  if (!p || !result || !result.items) return null;
  if (result.questionMode === 'choice' || result.passageWithChoices) return _trBuildChoiceGrammarHtml(pid, tid);
  var ri = _trPassages.indexOf(p);
  var CIRCLES = ['①','②','③','④','⑤','⑥','⑦','⑧','⑨','⑩'];
  var passageHtml = escH(result.passageWithMarks || result.passageText)
    .replace(/\[\[(\d+):([^\]]+)\]\]/g, function(_, num, word) {
      var n = parseInt(num, 10);
      var circle = CIRCLES[n - 1] || ('(' + n + ')');
      return '<sup style="font-size:7pt;color:#1D4ED8;font-weight:bold">' + circle + '</sup>' +
             '<u style="color:#1D4ED8;font-weight:bold">' + escH(word) + '</u>';
    });
  var css = 'body{font-family:"Malgun Gothic",sans-serif;font-size:11pt;line-height:1.9;margin:35px}' +
    'h2{font-size:13pt;border-bottom:2px solid #111;padding-bottom:5px;margin-bottom:14px}' +
    '.passage{font-size:11pt;line-height:2;margin-bottom:18px;padding:12px 14px;border:1px solid #ccc;background:#fafafa}' +
    '.instruction{font-size:10pt;color:#444;margin-bottom:10px}' +
    'table{width:100%;border-collapse:collapse;font-size:10pt}' +
    'th{background:#374151;color:#fff;padding:6px 8px;text-align:center;font-size:9pt}' +
    'td{border:1px solid #ccc;padding:6px 8px;vertical-align:top}' +
    '.num-cell{text-align:center;width:32px;font-weight:bold;color:#1D4ED8}' +
    '.point-cell{width:110px;font-size:9pt;color:#374151}' +
    '.write-cell{width:120px}.reason-cell{width:auto}' +
    '.answer-sec{margin-top:24px}' +
    '.answer-row{display:flex;gap:10px;margin-bottom:10px;padding:8px 10px;border:1px solid #ddd;border-radius:4px}' +
    '.a-circle{font-size:13pt;font-weight:bold;color:#1D4ED8;min-width:22px}' +
    '.a-body{flex:1;font-size:10pt;line-height:1.6}' +
    '.meta{font-size:9pt;color:#6B7280;margin:-6px 0 12px;padding:4px 8px;background:#F9FAFB;border:1px solid #E5E7EB}' +
    '.verdict-err{color:#DC2626;font-weight:bold}.verdict-ok{color:#059669;font-weight:bold}' +
    '.reason-text{color:#555;font-size:9.5pt;margin-top:2px}';
  var isPara = !!(result.originalPassage);
  var body = '<h2>기본기 훈련 — 지문 ' + (ri + 1) + (isPara ? ' (패러프레이즈)' : '') + '</h2>';
  body += _trMetaHtml(pid, tid);
  if (isPara && result.originalPassage) {
    body += '<div style="margin-bottom:6px;font-size:9pt;color:#6B7280;font-weight:bold">원문</div>' +
            '<div class="passage" style="background:#F3F4F6;color:#374151">' + escH(result.originalPassage) + '</div>' +
            '<div style="margin:10px 0 6px;font-size:9pt;color:#1D4ED8;font-weight:bold">【패러프레이즈 지문】</div>';
  }
  body += '<div class="passage">' + passageHtml + '</div>';
  body += '<div class="instruction">위 지문에서 밑줄 친 부분을 고치고, 그 이유를 올바르게 적으세요.</div>';
  body += '<table><tr><th>번호</th><th>어법 포인트</th><th>고친 표현</th><th>이 유</th></tr>';
  result.items.forEach(function(item) {
    var n = item.number || 1; var circle = CIRCLES[n-1] || ('('+n+')');
    body += '<tr><td class="num-cell">' + circle + '</td>' +
      '<td class="point-cell">' + escH(item.point_name||'') + (item.catalog_ref ? '<br><span style="color:#9CA3AF;font-size:8pt">' + escH(item.catalog_ref) + '</span>' : '') + '</td>' +
      '<td class="write-cell">&nbsp;</td><td class="reason-cell">&nbsp;</td></tr>';
  });
  body += '</table><div class="answer-sec"><h2 style="font-size:12pt">정 답</h2>';
  result.items.forEach(function(item) {
    var n = item.number || 1; var circle = CIRCLES[n-1] || ('('+n+')'); var isErr = !!item.is_error;
    body += '<div class="answer-row"><div class="a-circle">' + circle + '</div><div class="a-body">' +
      (isErr ? '<span class="verdict-err">✗ 오류</span> → <b>' + escH(item.correction||'') + '</b>'
             : '<span class="verdict-ok">✓ 올바름</span> — 수정 불필요') +
      '<div class="reason-text">' + escH(item.reason_ko||'') + '</div></div></div>';
  });
  body += '</div>';
  return { html: '<!DOCTYPE html><html><head><meta charset="utf-8"><style>' + css + '</style></head><body>' + body + '</body></html>',
           filename: '기본기훈련_지문' + (ri+1) + '_tid' + tid + '.docx' };
}

function _trBuildChoiceGrammarHtml(pid, tid) {
  var p = _trPassages.find(function(x) { return x.id === pid; });
  var result = p && p.results && p.results[tid];
  if (!p || !result || !result.items) return null;
  var ri = _trPassages.indexOf(p);
  var CIRCLES = ['①','②','③','④','⑤','⑥','⑦','⑧','⑨','⑩'];
  var passageHtml = escH(result.passageWithChoices || result.passageText)
    .replace(/\[\[(\d+):A:([^|\]]+)\|B:([^\]]+)\]\]/g, function(_, num, a, b) {
      var n = parseInt(num, 10);
      var circle = CIRCLES[n - 1] || ('(' + n + ')');
      return '<sup style="font-size:7pt;color:#1D4ED8;font-weight:bold">' + circle + '</sup>' +
             '<span style="color:#1D4ED8;font-weight:bold">[(A) ' + escH(a) + ' / (B) ' + escH(b) + ']</span>';
    });
  var css = 'body{font-family:"Malgun Gothic",sans-serif;font-size:11pt;line-height:1.9;margin:35px}' +
    'h2{font-size:13pt;border-bottom:2px solid #111;padding-bottom:5px;margin-bottom:14px}' +
    '.passage{font-size:11pt;line-height:2;margin-bottom:18px;padding:12px 14px;border:1px solid #ccc;background:#fafafa}' +
    '.instruction{font-size:10pt;color:#444;margin-bottom:10px}' +
    'table{width:100%;border-collapse:collapse;font-size:10pt}' +
    'th{background:#374151;color:#fff;padding:6px 8px;text-align:center;font-size:9pt}' +
    'td{border:1px solid #ccc;padding:6px 8px;vertical-align:top}' +
    '.num-cell{text-align:center;width:32px;font-weight:bold;color:#1D4ED8}' +
    '.point-cell{width:110px;font-size:9pt;color:#374151}' +
    '.choice-cell{width:120px;text-align:center}.reason-cell{width:auto}' +
    '.choice-btn{display:inline-block;border:1px solid #aaa;border-radius:4px;padding:2px 10px;margin:0 4px;color:#111}' +
    '.answer-sec{margin-top:24px}' +
    '.answer-row{display:flex;gap:10px;margin-bottom:10px;padding:8px 10px;border:1px solid #ddd;border-radius:4px}' +
    '.a-circle{font-size:13pt;font-weight:bold;color:#1D4ED8;min-width:22px}' +
    '.a-body{flex:1;font-size:10pt;line-height:1.6}' +
    '.meta{font-size:9pt;color:#6B7280;margin:-6px 0 12px;padding:4px 8px;background:#F9FAFB;border:1px solid #E5E7EB}' +
    '.verdict-ok{color:#059669;font-weight:bold}' +
    '.reason-text{color:#555;font-size:9.5pt;margin-top:2px}';
  var isPara = !!(result.originalPassage);
  var body = '<h2>기본기 훈련 — 지문 ' + (ri + 1) + ' (선택형' + (isPara ? ' · 패러프레이즈' : '') + ')</h2>';
  body += _trMetaHtml(pid, tid);
  if (isPara && result.originalPassage) {
    body += '<div style="margin-bottom:6px;font-size:9pt;color:#6B7280;font-weight:bold">원문</div>' +
            '<div class="passage" style="background:#F3F4F6;color:#374151">' + escH(result.originalPassage) + '</div>' +
            '<div style="margin:10px 0 6px;font-size:9pt;color:#1D4ED8;font-weight:bold">【패러프레이즈 지문】</div>';
  }
  body += '<div class="passage">' + passageHtml + '</div>';
  body += '<div class="instruction">각 번호의 A/B 중 알맞은 표현을 고르고, 그 이유를 적으세요.</div>';
  body += '<table><tr><th>번호</th><th>어법 포인트</th><th>선택</th><th>이 유</th></tr>';
  result.items.forEach(function(item) {
    var n = item.number || 1; var circle = CIRCLES[n-1] || ('('+n+')');
    body += '<tr><td class="num-cell">' + circle + '</td>' +
      '<td class="point-cell">' + escH(item.point_name||'') + (item.catalog_ref ? '<br><span style="color:#9CA3AF;font-size:8pt">' + escH(item.catalog_ref) + '</span>' : '') + '</td>' +
      '<td class="choice-cell"><span class="choice-btn">(A)</span><span class="choice-btn">(B)</span></td><td class="reason-cell">&nbsp;</td></tr>';
  });
  body += '</table><div class="answer-sec"><h2 style="font-size:12pt">정 답</h2>';
  result.items.forEach(function(item) {
    var n = item.number || 1; var circle = CIRCLES[n-1] || ('('+n+')'); var ans = _trChoiceAnswerText(item);
    body += '<div class="answer-row"><div class="a-circle">' + circle + '</div><div class="a-body">' +
      '<span class="verdict-ok">✓ ' + escH(ans.label) + '</span> — <b>' + escH(ans.text) + '</b>' +
      '<div class="reason-text">' + escH(item.reason_ko||'') + '</div></div></div>';
  });
  body += '</div>';
  return { html: '<!DOCTYPE html><html><head><meta charset="utf-8"><style>' + css + '</style></head><body>' + body + '</body></html>',
           filename: '기본기훈련_선택형_지문' + (ri+1) + '_tid' + tid + '.docx' };
}

function _trDownloadWordById(pid, tid) {
  var built = _trBuildGrammarHtml(pid, tid);
  if (!built) return;
  var p = _trPassages.find(function(x) { return x.id === pid; });
  var ri = p ? _trPassages.indexOf(p) + 1 : 1;
  built.filename = '기본기훈련_지문' + ri + '.docx';
  try {
    var blob = window.htmlDocx ? window.htmlDocx.asBlob(built.html) : new Blob([built.html], { type: 'application/msword' });
    var url = URL.createObjectURL(blob);
    var a = document.createElement('a');
    a.href = url; a.download = built.filename;
    document.body.appendChild(a); a.click();
    document.body.removeChild(a); URL.revokeObjectURL(url);
  } catch (e) { showToast('다운로드 오류: ' + e.message); }
}

/* ── 메인 탭 전환 ────────────────────────────────────────────────── */
function switchTab(tab) {
  console.log('[switchTab] called with:', tab);
  var mainEl      = document.getElementById('tab-main');
  var trainEl     = document.getElementById('tab-training');
  var synEl       = document.getElementById('tab-synonym');
  var bpEl        = document.getElementById('tab-blueprint');
  var btnMain     = document.getElementById('tab-btn-main');
  var btnTrain    = document.getElementById('tab-btn-training');
  var btnSyn      = document.getElementById('tab-btn-synonym');
  var btnBp       = document.getElementById('tab-btn-blueprint');

  [mainEl, trainEl, synEl, bpEl].forEach(function(el) {
    if (el) {
      el.style.display = 'none';
      el.setAttribute('hidden', '');
    }
  });
  [btnMain, btnTrain, btnSyn, btnBp].forEach(function(b) {
    if (b) {
      b.classList.remove('active');
      b.setAttribute('aria-selected', 'false');
    }
  });

  if (tab === 'main') {
    mainEl.style.display = '';
    mainEl.removeAttribute('hidden');
    btnMain.classList.add('active');
    btnMain.setAttribute('aria-selected', 'true');
  } else if (tab === 'training') {
    trainEl.style.display = '';
    trainEl.removeAttribute('hidden');
    btnTrain.classList.add('active');
    btnTrain.setAttribute('aria-selected', 'true');
    _syncTrPvFromMain();
    _refreshAllKeyStatus();
    _trEnsureInitialPassage();
    _trRenderQueue();
    _trRenderRight();
    setTimeout(function() {
      var ta = document.getElementById('tr-edit-ta');
      if (ta && !ta.value) ta.focus();
    }, 40);
  } else if (tab === 'synonym') {
    if (synEl) {
      synEl.style.display = '';
      synEl.removeAttribute('hidden');
    }
    if (btnSyn) {
      btnSyn.classList.add('active');
      btnSyn.setAttribute('aria-selected', 'true');
    }
    _refreshAllKeyStatus();
    _synRefreshKeyStatus();
  } else if (tab === 'blueprint') {
    if (bpEl) {
      bpEl.style.display = '';
      bpEl.removeAttribute('hidden');
    }
    if (btnBp) {
      btnBp.classList.add('active');
      btnBp.setAttribute('aria-selected', 'true');
    }
    _refreshAllKeyStatus();
    if (window.bpInit) window.bpInit();
  }
}

/* (서브탭 전환은 통합 큐 방식으로 대체) */

/* ═══════════════════════════════════════════════════════════════════
   지문이해 모듈 (basic-logic-train)
   ═══════════════════════════════════════════════════════════════════ */

var _LG_LEVEL_DESC = {
  basic:    '내용 확인 5문항 (사실 4~5 + 함축 0~1) + 심화 1문항',
  standard: '내용 확인 3문항 (사실 2~3 + 함축 0~1) + 심화 3문항',
  advanced: '내용 확인 1문항 (사실·함축 중 택) + 심화 최대 5문항'
};
var _LG_LEVEL_SPEC = {
  basic:    { content: 5, advanced: 1 },
  standard: { content: 3, advanced: 3 },
  advanced: { content: 1, advanced: 5 }
};

var _lgPassages   = [];
var _lgIdCounter  = 0;
var _lgSelectedId = null;
var _lgLevel      = 'standard';
var _lgRunning    = false;

/* ── 레벨 설정 ── */
function lgSetLevel(lv) {
  _lgLevel = lv;
  document.querySelectorAll('#lg-level-grp .ps').forEach(function(b) {
    b.classList.toggle('on', b.dataset.lv === lv);
  });
  var desc = document.getElementById('lg-level-desc');
  if (desc) desc.textContent = _LG_LEVEL_DESC[lv] || '';
}

/* ── 지문 추가 / 삭제 ── */
function lgAddPassage() {
  var id = ++_lgIdCounter;
  _lgPassages.push({ id: id, text: '', status: 'idle', result: null });
  _lgRenderQueue();
  lgSelectPassage(id);
  setTimeout(function() {
    var ta = document.getElementById('lg-edit-ta');
    if (ta) ta.focus();
  }, 60);
}

function lgDelPassage(id) {
  _lgPassages = _lgPassages.filter(function(p) { return p.id !== id; });
  if (_lgSelectedId === id) {
    _lgSelectedId = _lgPassages.length ? _lgPassages[_lgPassages.length - 1].id : null;
  }
  _lgRenderQueue();
  _lgRenderRight();
}

function _lgSaveEditText() {
  var ta = document.getElementById('lg-edit-ta');
  if (!ta) return;
  var p = _lgPassages.find(function(x) { return x.id === _lgSelectedId; });
  if (p) p.text = ta.value;
}

function lgSelectPassage(id) {
  _lgSaveEditText();
  _lgSelectedId = id;
  _lgRenderQueue();
  _lgRenderRight();
}

/* ── 큐 렌더 ── */
function _lgRenderQueue() {
  var container = document.getElementById('lg-passage-queue');
  var statusEl  = document.getElementById('lg-queue-status');
  if (statusEl) statusEl.textContent = _lgPassages.length + '개';
  if (_lgPassages.length === 0) {
    container.innerHTML = '<div style="font-size:11px;color:#D1D5DB;text-align:center;padding:12px 0">지문을 추가하세요</div>';
    return;
  }
  var _ST_LABEL = { idle:'대기', processing:'출제 중', done:'완료', error:'오류' };
  var _ST_CLS   = { idle:'idle', processing:'processing', done:'done', error:'error' };
  var html = '';
  _lgPassages.forEach(function(p, i) {
    var isActive = (p.id === _lgSelectedId);
    var preview  = p.text.trim().replace(/\s+/g,' ').slice(0, 28) || '(비어 있음)';
    var stCls    = _ST_CLS[p.status]   || 'idle';
    var stLbl    = _ST_LABEL[p.status] || '대기';
    var itemCls  = 'passage-q-item' +
      (isActive          ? ' active'         : '') +
      (p.status==='done' ? ' st-done'        : '') +
      (p.status==='error'? ' st-error'       : '') +
      (p.status==='processing'?' st-processing':'');
    html +=
      '<div class="' + itemCls + '" onclick="lgSelectPassage(' + p.id + ')" data-lgpid="' + p.id + '">' +
        '<div class="pq-head">' +
          '<span class="pq-num">' + (i + 1) + '</span>' +
          '<span class="pq-preview">' + escH(preview) + '</span>' +
          '<span class="pq-status ' + stCls + '">' + stLbl + '</span>' +
          '<button class="pq-del" onclick="event.stopPropagation();lgDelPassage(' + p.id + ')">✕</button>' +
        '</div>' +
      '</div>';
  });
  container.innerHTML = html;
}

/* ── 오른쪽 패널 ── */
function _lgRenderRight() {
  var rp = document.getElementById('lg-right-panel');
  if (_lgSelectedId === null || _lgPassages.length === 0) {
    rp.innerHTML = '<div class="card"><div class="tr-result-empty"><div class="empty-icon">←</div><div>왼쪽에서 지문을 추가하거나 선택하세요</div></div></div>';
    return;
  }
  var p   = _lgPassages.find(function(x) { return x.id === _lgSelectedId; });
  var idx = _lgPassages.indexOf(p) + 1;
  if (!p) { rp.innerHTML = ''; return; }

  if (p.status === 'idle' || p.status === 'error') {
    var errHtml = (p.status === 'error' && p.result && p.result.error)
      ? '<div style="margin-bottom:8px;padding:6px 10px;border-radius:7px;background:#FEF2F2;border:1px solid #FCA5A5;font-size:11px;color:#EF4444">오류: ' + escH(p.result.error) + '</div>'
      : '';
    rp.innerHTML =
      '<div class="card">' +
        '<div class="card-hd"><span>지문 ' + idx + ' · 편집</span></div>' +
        '<div style="padding:12px 16px 14px">' +
          errHtml +
          '<textarea id="lg-edit-ta" style="min-height:160px;font-size:12px" ' +
            'placeholder="영어 지문을 붙여넣으세요..." ' +
            'oninput="_lgLiveText()">' + escH(p.text) + '</textarea>' +
          '<div style="margin-top:6px;font-size:10px;color:#9CA3AF">지문 입력 후 ⚡ 버튼을 눌러 출제하세요.</div>' +
        '</div>' +
      '</div>';
  } else if (p.status === 'processing') {
    rp.innerHTML =
      '<div class="card"><div class="card-hd"><span>지문 ' + idx + ' · 출제 중</span></div>' +
        '<div style="padding:32px 16px;text-align:center;color:#6B7280;font-size:12px">' +
          '<div class="spin" style="font-size:20px;display:block;margin-bottom:8px">⟳</div>' +
          'AI가 지문을 분석하고 있습니다...' +
        '</div></div>';
  } else {
    _lgRenderResultCard(p, idx, rp);
  }
}

function _lgLiveText() {
  var ta = document.getElementById('lg-edit-ta');
  var p  = _lgPassages.find(function(x) { return x.id === _lgSelectedId; });
  if (ta && p) p.text = ta.value;
}

/* ── 해석훈련 시스템 프롬프트 ── */
function _chunBuildSystem(chunkMode, chunkLevel) {
  var cm = chunkMode  || 'original';
  var lv = chunkLevel || 'standard';
  var isBasic = lv === 'basic';

  /* ── 난이도별 적용 기준 ── */
  var criteriaBlock = isBasic
    ? '## 난이도: 기본\n' +
      '| 원칙 | 적용 기준 |\n' +
      '|---|---|\n' +
      '| 원칙 1 (주어) | 수식받는 주어 또는 명사구/명사절 주어 **3~5단어** |\n' +
      '| 원칙 2 (전치사구) | 전치사구 **3~4단어** |\n' +
      '| 원칙 3 (접속사절) | 접속사절 **4~7단어** |\n' +
      '| 원칙 4 (명사 뒤 수식) | 명사 뒤 수식어 **2~3단어** |\n\n' +
      '기본에서 2단어 미만은 제외합니다.\n\n'
    : '## 난이도: 실전\n' +
      '| 원칙 | 적용 기준 |\n' +
      '|---|---|\n' +
      '| 원칙 1 (주어) | 수식받는 주어 또는 명사구/명사절 주어 **6단어 이상** |\n' +
      '| 원칙 2 (전치사구) | 전치사구 **5단어 이상** 또는 익숙하지 않은 의미로 쓰인 전치사 |\n' +
      '| 원칙 3 (접속사절) | 접속사절 **8단어 이상** |\n' +
      '| 원칙 4 (명사 뒤 수식) | 명사 뒤 수식어 **4단어 이상** |\n\n';

  /* ── 패러프레이즈 모드 블록 ── */
  var paraphraseBlock = cm === 'paraphrase'
    ? '## 모드: 패러프레이즈 (구문 포인트 최대 2개 교체)\n\n' +
      '### [1단계] 원문 구문 포인트 분석\n' +
      '원문 지문의 각 문장에서 4원칙에 해당하는 구문 포인트를 모두 파악합니다.\n' +
      '(내부 작업용, 출력하지 않음)\n\n' +
      '### [2단계] 교체 포인트 선정 (최대 2개)\n' +
      '원문의 구문 포인트 중 최대 2개를 선정하여 다른 구문 유형으로 교체합니다.\n' +
      '교체 방향 예시:\n' +
      '- 관계절(원칙 4) → 분사구(원칙 4) 또는 접속사절(원칙 3)\n' +
      '- 긴 전치사구(원칙 2) → 부사절(원칙 3)\n' +
      '- 분사구(원칙 4) → 관계절(원칙 4)\n' +
      '교체 원칙: 의미는 최대한 보존, 나머지 문장은 원문 그대로 유지\n\n' +
      '### [3단계] 패러프레이즈 작성\n' +
      '교체 포인트 2개만 바꾸고 나머지 문장은 원문에 가깝게 유지합니다.\n' +
      '"original_passage" 필드에 원문을, "passage_text"에 패러프레이즈 지문을 저장합니다.\n\n'
    : '';

  /* ── 4원칙 상세 ── */
  var principlesBlock =
    '## 4가지 끊어읽기 원칙\n\n' +

    '### 원칙 1. 주어가 길면 동사를 찾아라\n' +
    '적용 대상:\n' +
    '- 명사가 수식어(관계절·분사구·전치사구)를 받아 길어진 주어\n' +
    '- 가주어(It) — 진주어(to-v / that절) 구조\n' +
    '- 동명사구·to부정사구·명사절이 주어인 경우\n' +
    '밑줄 범위: 주어 첫 단어 ~ 동사 직전 단어\n' +
    (isBasic
      ? '기본 예시: "Students fond of sweets" (3단어) → 단것을 좋아하는 학생들\n\n'
      : '실전 예시: "The only health disadvantage identified for supertasters thus far" (7단어) → 지금까지 슈퍼테이스터들에게서 확인된 유일한 건강상의 단점\n\n') +

    '### 원칙 2. 전치사구 앞에서 끊어라\n' +
    '적용 대상: 기준 단어 수를 충족하는 전치사구' +
    (isBasic ? '' : ' 또는 익숙하지 않은 의미로 쓰인 전치사 (on=~에 관하여, in=~한 상태로, beyond=~을 넘어서 등)') + '\n' +
    '제외: 구동사(look at, wait for 등), 명사 of 명사, prior to / due to 등 복합전치사\n' +
    '밑줄 범위: 전치사 ~ 전치사구 마지막 단어\n' +
    (isBasic
      ? '기본 예시: "by telling stories" (3단어) → 이야기를 들려줌으로써\n\n'
      : '실전 예시: "in addition to acting as guides to the land and its flora and fauna" (14단어) → 땅과 동식물에 대한 안내자 역할을 하는 것 외에도\n\n') +

    '### 원칙 3. 접속사 앞에서 끊어라\n' +
    '적용 대상:\n' +
    '- 명사절 접속사: that, what, whether, if\n' +
    '- 부사절 접속사: because, although, while, unless, when, even though\n' +
    '(관계사는 원칙 4에서 처리)\n' +
    '밑줄 범위: 접속사 ~ 절의 마지막 단어\n' +
    (isBasic
      ? '기본 예시: "that monsters are not real" (4단어) → 괴물은 실재하지 않는다는 것을\n\n'
      : '실전 예시: "that retaining principles and values during the process of change is not only possible but necessary" (16단어) → 변화 과정에서 원칙과 가치를 유지하는 것이 가능할 뿐 아니라 필요하다는 것을\n\n') +

    '### 원칙 4. 명사 뒤에서 끊어라\n' +
    '적용 대상:\n' +
    '- 관계대명사절 (who / which / that / in which)\n' +
    '- 분사구 (-ing / p.p.)\n' +
    '- to부정사구\n' +
    '밑줄 범위: 수식어 첫 단어 ~ 수식어 마지막 단어\n' +
    '해석 주의: 콤마 뒤 계속적 용법 관계대명사(which 등)는 앞 명사를 단순 수식하는 "~하는"으로만 옮기지 말고, 앞 절 전체나 앞 명사를 받아 "그런데/그리고 그것은 ..."처럼 자연스러운 절로 풀어 해석합니다.\n' +
    '예) antibiotics, which can damage the microbiome at the same time as treating the bacteria making them ill → 그런데 그것은 그들을 아프게 하는 세균을 치료하는 동시에 마이크로바이옴을 손상시킬 수 있다\n' +
    (isBasic
      ? '기본 예시: "known for honesty" (3단어) → 정직함으로 알려진 / "to rest" (2단어) → 쉴 수 있는\n\n'
      : '실전 예시: "who together define the fundamental cognitive orientation of the people" (10단어) → 함께 사람들의 근본적인 인지적 방향을 정의하는\n\n');

  /* ── 선정 기준 ── */
  var selectionBlock =
    '## 밑줄 선정 기준\n' +
    '- 지문 1개당 밑줄 문장 **4~6개** 목표\n' +
    '- 한 문장에 후보가 2개 이상이면 **학습 효과가 높은 1개만** 선택\n' +
    '- 4원칙이 **고루 포함**되도록 구성 (한 원칙에만 치우치지 않도록)\n' +
    (isBasic ? '- 기본: 2단어 미만 수식어는 제외\n' : '') +
    '\n';

  /* ── 검증 블록 ── */
  var verifyBlock =
    '## 검증 (2회 실시)\n\n' +
    '### 1차 검증 — 문항별 점검\n' +
    '각 밑줄 항목에 대해 순서대로 확인합니다:\n' +
    '□ 밑줄 어구가 해당 원칙의 단어 수 기준을 정확히 충족하는가?\n' +
    '□ 밑줄이 full_sentence 안에 실제로 존재하는 문자열인가? (오타·생략 없이 동일한가?)\n' +
    '□ 한국어 해석(answer)이 밑줄 어구와 정확히 대응하는가?\n' +
    '□ 콤마 뒤 계속적 용법 관계대명사를 제한적 용법처럼 "~하는"으로만 오역하지 않았는가?\n' +
    '□ 밑줄 총 개수가 4~6개인가?\n' +
    '오류 발견 시 즉시 수정합니다.\n\n' +
    '### 2차 검증 — 자연스러운 영어 표현 확인\n' +
    '□ 각 밑줄 문장이 현대 영어에서 실제로 자주 쓰이는 표현인가?\n' +
    '□ 어색하거나 억지스러운 구문이 없는가? (특히 패러프레이즈 모드)\n' +
    '□ 고등학교 수능·내신 지문 수준에 적합한 문장인가?\n' +
    '부자연스러운 표현이 있으면 더 자연스러운 표현으로 수정 후 최종 출력합니다.\n\n';

  return (
    '당신은 한국 고등학교 영어 교사입니다. 영어 지문을 받아 끊어읽기 워크시트를 만듭니다.\n\n' +
    criteriaBlock +
    paraphraseBlock +
    principlesBlock +
    selectionBlock +
    verifyBlock +
    '## 출력 형식 (순수 JSON만, 코드블록 없이)\n' +
    (cm === 'paraphrase'
      ? '{\n  "original_passage": "원문 지문 전체 (수정 없이 그대로)",\n  "passage_text": "패러프레이즈된 지문 전체",\n'
      : '{\n  "passage_text": "입력된 지문 전체 (수정 없이 그대로)",\n') +
    '  "level": "' + (isBasic ? '기본' : '실전') + '",\n' +
    '  "items": [\n' +
    '    {\n' +
    '      "number": 1,\n' +
    '      "principle": 1,\n' +
    '      "principle_name": "주어가 길면 동사를 찾아라",\n' +
    '      "full_sentence": "전체 문장을 여기에 그대로 씁니다.",\n' +
    '      "underlined": "밑줄 친 어구만 여기에 씁니다 (full_sentence의 부분 문자열)",\n' +
    '      "answer": "한국어 해석 (밑줄 친 어구만 해석)"\n' +
    '    }\n' +
    '  ]\n' +
    '}'
  );
}

/* ── 시스템 프롬프트 ── */
function _lgBuildSystem(level) {
  var lv = level || _lgLevel || 'standard';

  var levelSpec = {
    basic:    '내용 확인 5문항 (사실 4~5 + 함축 설명 0~1) + 심화 1문항',
    standard: '내용 확인 3문항 (사실 2~3 + 함축 설명 0~1) + 심화 3문항',
    advanced: '내용 확인 1문항 (사실 0~1 또는 함축 설명 0~1) + 심화 최대 5문항'
  };

  return (
    '당신은 한국 고등학교 영어 교사입니다. 아래 절차를 따라 학생의 지문 이해를 확인하는 주관식 문제 세트를 출제합니다.\n\n' +

    '## 레벨: ' + { basic:'기본', standard:'실전', advanced:'심화' }[lv] + '\n' +
    levelSpec[lv] + '\n\n' +

    '## Step 1. 지문 구조 파악\n' +
    '출제 전 지문의 논리 구조를 파악합니다.\n' +
    '| 구조 | 핵심 패턴 | 잘 맞는 심화 유형 |\n' +
    '|---|---|---|\n' +
    '| 통념 반박 | ~라고 생각하지만, 실제로는 ~ | 대조, 형태 지정 |\n' +
    '| 주제와 예시 | ~이다. 예를 들어 ~ | 인과 연결, 형태 지정 |\n' +
    '| 문제와 해결 | ~라는 문제. ~해야 한다 | 인과 연결, 지문에서 찾기 |\n' +
    '| 원인과 결과 | ~이기 때문에 ~이다 | 인과 연결, 지문에서 찾기 |\n' +
    '| 비교와 대조 | A는 ~이지만, B는 ~ | 대조, 분류 |\n\n' +

    '## Step 2. 내용 확인 문제 출제 원칙 5가지\n' +
    '1. 지문에 명시된 내용만 묻는다 (추론·평가·의도·교훈 금지)\n' +
    '2. 1문항 = 1정보 (복합 질문 반드시 분리)\n' +
    '3. 답의 범위를 명확히 제시한다 ("두 가지", "한 문장으로" 등)\n' +
    '4. 문제의 전제(수량·구조)가 지문과 정확히 일치해야 한다\n' +
    '5. 심화 문제는 지문 안의 구조를 묻는다 (더 어렵게가 아니라 더 깊게)\n\n' +

    '## Step 2-1. 쉬운 한국어 문제 작성 기준\n' +
    '- 문제 문장은 중학생도 이해할 수 있을 정도로 쉬운 한국어로 쓴다.\n' +
    '- 추상어·어려운 한자어·평가자식 표현을 피하고, 본문 내용을 일상적인 말로 풀어 쓴다.\n' +
    '- 한 문항에는 하나의 질문만 담는다.\n' +
    '- 질문이 길어지면 두 문장으로 나눈다.\n' +
    '- 학생이 문제 문장 자체를 이해하느라 막히면 실패한 문항이다.\n' +
    '- 단, 정답 근거는 반드시 지문 안에 있어야 한다.\n' +
    '- 금지 표현 예: "인과적 구조", "생리적 안정성", "인지적 결핍", "전략적으로 회피", "함의", "양상"\n\n' +

    '## Step 3-A. 함축 설명 문항 포함 여부 판단\n' +
    '지문에 아래 표현이 있으면 내용 확인 문제 안에 함축 설명 문항 1개를 포함한다. 없으면 건너뛴다.\n\n' +
    '- A. 비유/상징: 사물이나 행위로 추상적 의미를 표현한 문장\n' +
    '  예) "Burn the house, but save the nails."\n' +
    '  형식: "이 문장이 실제로 의미하는 바를 지문의 내용을 바탕으로 설명하시오."\n' +
    '  type 값: "함축설명-비유"\n\n' +
    '- B. 역설: 언뜻 모순처럼 보이지만 지문 안에서 성립하는 주장\n' +
    '  예) "강한 원칙을 가진 조직이 오히려 더 높은 적응력을 가진다."\n' +
    '  형식: "언뜻 모순처럼 보이는 이 주장이 왜 성립하는지 지문에서 근거를 찾아 설명하시오."\n' +
    '  type 값: "함축설명-역설"\n\n' +

    '## Step 3-B. 심화 문제 유형 선택 (지문 구조에 맞는 것)\n' +
    '- 대조: "A와 B를 대조하여 서술하시오."\n' +
    '- 인과 연결: "A가 B에 미치는 영향을 C와 연결하여 설명하시오."\n' +
    '- 지문에서 찾기: "~을 지문에서 N가지 찾아 쓰시오."\n' +
    '- 형태 지정: "핵심 주장을 \'~ 형태\'로 한 문장으로 쓰시오."\n' +
    '- 분류: "A와 B를 각각 쓰시오."\n\n' +

    '## Step 4. 검증 루프 (2회 실시)\n\n' +
    '### 1차 검증 — 문항별 원칙 점검\n' +
    '[ ] 이 답이 지문 안에 명확히 존재하는가?\n' +
    '[ ] 한 문항이 두 가지 이상을 동시에 묻고 있지 않은가?\n' +
    '[ ] 답의 개수나 범위 조건이 명시되어 있는가?\n' +
    '[ ] 문제 속 전제(수량, 구조)가 지문과 정확히 일치하는가?\n' +
    '[ ] 심화 문제가 지문 밖 추론을 요구하고 있지 않은가?\n' +
    '[ ] 함축 설명 문항이 있다면, 비유/역설 표현이 지문에 실제로 존재하는가?\n' +
    '[ ] 문제 문장이 쉬운 한국어로 되어 있어 학생이 질문 자체를 이해하기 쉬운가?\n' +
    '→ 하나라도 ✗이면 즉시 수정\n\n' +
    '### 2차 검증 — 지문 구조와 정합성 점검\n' +
    '[ ] 내용 확인 문제들이 지문의 핵심 정보를 고르게 다루는가?\n' +
    '[ ] 심화 문제의 유형이 지문 구조에 맞게 선택되었는가?\n' +
    '[ ] 예시 답이 지문의 실제 내용과 완전히 일치하는가?\n' +
    '[ ] 레벨에 맞는 문항 수가 정확히 지켜졌는가?\n' +
    '→ 하나라도 ✗이면 해당 항목 수정 후 1차부터 다시 점검\n\n' +

    '## 출력 형식 (순수 JSON만, 코드블록 없이)\n' +
    '{\n' +
    '  "passage_structure": "통념 반박",\n' +
    '  "content_questions": [\n' +
    '    { "number": 1, "type": "사실확인", "question": "문항 (한국어)", "answer": "예시 답 (한국어, 간결하게)" },\n' +
    '    { "number": 2, "type": "함축설명-비유", "question": "\\"Burn the house, but save the nails.\\"가 의미하는 바를 설명하시오.", "answer": "예시 답" }\n' +
    '  ],\n' +
    '  "advanced_questions": [\n' +
    '    { "number": 1, "type": "대조", "question": "문항 (한국어)", "answer": "예시 답 (한국어)" }\n' +
    '  ]\n' +
    '}\n' +
    '(content_questions의 type은 "사실확인" / "함축설명-비유" / "함축설명-역설" 중 하나)'
  );
}

/* ── 주관식 문제 검수 시스템 프롬프트 ── */
function _lgBuildVerifySystem(level) {
  var lv = level || 'standard';
  var levelSpec = {
    basic:    '내용 확인 5문항 (사실 4~5 + 함축 설명 0~1) + 심화 1문항',
    standard: '내용 확인 3문항 (사실 2~3 + 함축 설명 0~1) + 심화 3문항',
    advanced: '내용 확인 1문항 + 심화 최대 5문항'
  };
  return (
    '당신은 한국 고등학교 영어 주관식 문제 전문 검수자입니다.\n' +
    '1차 출제된 문제 세트를 받아 아래 체크리스트로 점검하고, 오류가 있으면 즉시 수정하여 최종본을 반환합니다.\n' +
    '수정이 없더라도 반드시 동일한 JSON 형식으로 반환해야 합니다.\n\n' +

    '## 레벨 기준\n' +
    levelSpec[lv] + '\n\n' +

    '## 문항별 검증 (각 문항에 대해 순서대로 확인)\n' +
    '1. 답이 지문 안에 명확히 존재하는가?\n' +
    '   → 추론·평가·의도·교훈이 요구되면 지문 내 사실만 묻도록 수정\n' +
    '2. 한 문항이 두 가지 이상의 정보를 동시에 묻는가?\n' +
    '   → 복합 질문이면 단일 정보만 묻도록 수정 또는 분리\n' +
    '3. 답의 개수·범위 조건이 명시되어 있는가?\n' +
    '   → "두 가지를 쓰시오", "한 문장으로" 등 조건 추가\n' +
    '4. 문제 속 전제(수량·구조)가 지문과 정확히 일치하는가?\n' +
    '   → 불일치 시 지문 기준으로 수정\n' +
    '5. 심화 문제가 지문 밖 추론을 요구하는가?\n' +
    '   → 지문 내부 구조·관계만 묻도록 수정\n' +
    '6. 함축 설명 문항(type: 함축설명-비유/역설)이 있다면,\n' +
    '   해당 비유·역설 표현이 지문에 실제로 존재하는가?\n' +
    '   → 없으면 해당 문항을 사실확인 문항으로 교체\n\n' +

    '## 쉬운 말 검증\n' +
    '각 문항의 question을 반드시 쉬운 한국어로 다시 점검합니다.\n' +
    '다음 중 하나라도 해당하면 반드시 고쳐 씁니다:\n' +
    '1. 질문에 어려운 한자어·추상어가 많다.\n' +
    '2. 질문이 한 문장에 두 가지 이상을 묻는다.\n' +
    '3. 학생이 본문보다 문제 문장을 이해하기 더 어렵다.\n' +
    '4. "인과적 구조", "생리적 안정성", "인지적 결핍", "전략적으로 회피", "함의", "양상" 같은 표현을 그대로 쓴다.\n' +
    '5. 지문 내용을 쉬운 한국어로 풀지 않고 영어 표현을 직역했다.\n' +
    '수정 기준: 쉬운 한국어로 바꾸고, 질문은 짧게 쓰며, 필요한 경우 구체적으로 묻는다. 정답 근거는 유지한다.\n\n' +

    '## 전체 구조 검증\n' +
    '7. 내용 확인 문제들이 지문의 핵심 정보를 고르게 다루는가?\n' +
    '   → 도입부 편중이면 중반·결론 내용도 묻도록 조정\n' +
    '8. 심화 문제의 유형이 지문 구조(통념반박·인과·비교 등)에 맞는가?\n' +
    '   → 부적합 유형이면 더 적합한 유형으로 교체\n' +
    '9. 예시 답이 지문의 실제 내용과 완전히 일치하는가?\n' +
    '   → 지문과 한 문장씩 대조하여 불일치 수정\n' +
    '10. 레벨 기준 문항 수가 정확히 지켜졌는가?\n' +
    '    → 초과/부족이면 가장 중요도 낮은 문항 삭제 또는 추가\n\n' +

    '## 출력 형식 (순수 JSON만, 코드블록 없이)\n' +
    '{\n' +
    '  "passage_structure": "...",\n' +
    '  "verification_notes": "수정한 내용 1~3줄 (수정 없으면 \'검증 통과\')",\n' +
    '  "content_questions": [\n' +
    '    { "number": 1, "type": "사실확인", "question": "...", "answer": "..." }\n' +
    '  ],\n' +
    '  "advanced_questions": [\n' +
    '    { "number": 1, "type": "대조", "question": "...", "answer": "..." }\n' +
    '  ]\n' +
    '}'
  );
}

/* ── 순차 출제 ── */
async function runLogic() {
  if (_lgRunning) return;
  _lgSaveEditText();
  var toRun = _lgPassages.filter(function(p) { return p.text.trim().length > 0; });
  if (toRun.length === 0) { showToast('지문을 입력하세요'); return; }
  var apiKey = getKey();
  if (!apiKey) { showToast('Claude API 키가 필요합니다 (객관식 출제 탭에서 저장)'); return; }

  _lgRunning = true;
  var btn  = document.getElementById('lg-run-btn');
  var prog = document.getElementById('lg-progress');
  btn.disabled = true;
  btn.textContent = '출제 중...';

  for (var i = 0; i < toRun.length; i++) {
    var p = toRun[i];
    p.status = 'processing';
    p.result = null;
    prog.textContent = '지문 ' + (i + 1) + ' / ' + toRun.length + ' 출제 중...';
    _lgRenderQueue();
    if (_lgSelectedId === p.id) _lgRenderRight();

    try {
      var raw   = await _callAPI(
        _lgBuildSystem(),
        '다음 영어 지문으로 지문이해 확인 문제를 출제해 주세요:\n\n' + p.text.trim(),
        apiKey, 3, null, 'logic', 'claude-sonnet-4-6'
      );
      var parsed = _safeParseJSON(raw);
      p.status = 'done';
      p.result = {
        passageText:       p.text.trim(),
        passageStructure:  parsed.passage_structure  || parsed.passageStructure  || '',
        verificationNotes: parsed.verification_notes || parsed.verificationNotes || '',
        contentQuestions:  parsed.content_questions  || parsed.contentQuestions  || [],
        advancedQuestions: parsed.advanced_questions || parsed.advancedQuestions || []
      };
    } catch (e) {
      p.status = 'error';
      p.result = { passageText: p.text.trim(), error: e.message };
    }

    _lgRenderQueue();
    if (_lgSelectedId === p.id) _lgRenderRight();
    if (_lgSelectedId === null) { _lgSelectedId = p.id; _lgRenderQueue(); _lgRenderRight(); }
  }

  _lgRunning = false;
  btn.disabled = false;
  btn.textContent = '⚡ 지문이해 출제';
  var errCnt = _lgPassages.filter(function(p) { return p.status === 'error'; }).length;
  prog.textContent = errCnt > 0 ? (errCnt + '개 오류 발생') : '완료!';

  if (!_lgPassages.find(function(p) { return p.id === _lgSelectedId && p.status === 'done'; })) {
    var firstDone = _lgPassages.find(function(p) { return p.status === 'done'; });
    if (firstDone) { _lgSelectedId = firstDone.id; _lgRenderQueue(); _lgRenderRight(); }
  }
}

/* ── 해석훈련 결과 카드 렌더 ── */
function _chunRenderResultCard(p, idx, rp, tid, instLabel) {
  var result   = p.results && p.results[tid];
  var isPara   = !!(result && result.originalPassage);
  var inst     = (p.typeInstances || []).find(function(t) { return t.tid === tid; }) || {};
  var lvLabel  = (inst.chunkLevel === 'basic') ? '기본' : '실전';
  var cardTitle = instLabel ? ('지문 ' + idx + ' · ' + instLabel) : ('지문 ' + idx + ' · 해석훈련');
  var html     = '<div class="card">';
  html += '<div class="card-hd"><span>' + cardTitle + '</span>' +
    '<span class="aux">' + lvLabel + ' · ' + (isPara ? '<span style="color:#059669;font-weight:600">패러프레이즈</span>' : '원문') + '</span>' +
  '</div>';

  /* ── 메타 정보 ── */
  if (result) {
    var metaModel = result.modelId || 'claude-sonnet-4-6';
    html +=
      '<div style="padding:6px 16px 8px;display:flex;flex-wrap:wrap;gap:6px;font-size:10px;color:#374151">' +
        '<span style="background:#EFF6FF;border:1px solid #BFDBFE;border-radius:5px;padding:2px 8px">🎯 해석 수준: ' + lvLabel + '</span>' +
        '<span style="background:#EFF6FF;border:1px solid #BFDBFE;border-radius:5px;padding:2px 8px">📄 지문: ' + (isPara ? '패러프레이즈' : '원문') + '</span>' +
        '<span style="background:#F0FDF4;border:1px solid #BBF7D0;border-radius:5px;padding:2px 8px">🤖 출제 AI: ' + escH(metaModel) + '</span>' +
      '</div>';
  }

  if (!result || !result.items || result.items.length === 0) {
    html += '<div style="padding:12px 16px;font-size:11px;color:#9CA3AF">출제된 항목이 없습니다.</div></div>';
    rp.innerHTML = html;
    return;
  }

  /* 원문 접기 (패러프레이즈 모드) */
  if (isPara && result.originalPassage) {
    var origId = 'chk-orig-' + p.id + '-' + tid;
    html +=
      '<div style="padding:8px 16px 0">' +
        '<button class="tr-key-btn" id="' + origId + '-btn" onclick="_trToggleOrig(\'' + origId + '\')" style="font-size:10px;padding:3px 10px">원문 보기</button>' +
      '</div>' +
      '<div class="tr-key-block" id="' + origId + '-key" style="margin:6px 16px 0;border-radius:7px;background:#F9FAFB;border:1px solid var(--bdr);padding:10px 12px;font-size:11px;line-height:1.7;color:#374151">' +
        escH(result.originalPassage) +
      '</div>';
  }

  /* 지시문 */
  html += '<div style="padding:10px 16px 4px;font-size:11px;color:#374151;font-weight:500">다음 밑줄 친 부분을 해석하세요.</div>';

  var PRINCIPLE_COLOR = ['','#7C3AED','#2563EB','#059669','#D97706'];

  /* 문항 */
  result.items.forEach(function(item) {
    var uid      = 'chk-' + p.id + '-' + tid + '-' + item.number;
    var sent     = escH(item.full_sentence || '');
    var ul       = item.underlined || '';
    var pNum     = item.principle || 1;
    var pColor   = PRINCIPLE_COLOR[Math.min(pNum, 4)] || '#374151';

    /* 밑줄 하이라이트 */
    var highlighted = sent.replace(
      escH(ul),
      '<span style="border-bottom:2px solid ' + pColor + ';color:' + pColor + ';font-weight:600">' + escH(ul) + '</span>'
    );

    html +=
      '<div class="lg-q-item">' +
        '<div class="lg-q-hd">' +
          '<span class="lg-q-num">' + item.number + '</span>' +
          '<span style="font-size:9px;color:' + pColor + ';background:' + pColor + '18;border:1px solid ' + pColor + '44;border-radius:5px;padding:1px 6px">원칙 ' + pNum + '</span>' +
          '<span style="flex:1"></span>' +
          '<button class="lg-ans-toggle" id="' + uid + '-btn" onclick="lgToggleAns(\'' + uid + '\')">예시 답 확인</button>' +
        '</div>' +
        '<div class="lg-q-body">' +
          '<div class="lg-q-text" style="font-size:11px;line-height:1.8">' + highlighted + '</div>' +
          '<textarea class="lg-ans-input" placeholder="밑줄 친 부분의 해석을 쓰세요..."></textarea>' +
          '<div class="lg-ans-key" id="' + uid + '-key">' + escH(item.answer || '') + '</div>' +
        '</div>' +
      '</div>';
  });

  /* Word 다운로드 + JSON */
  var cjkey = p.id + '-' + tid;
  var cjfilename = '해석훈련_지문' + idx + '_tid' + tid;
  _trJsonCache[cjkey] = _trBuildInstanceJson(p.id, tid);
  var _cjbtnStyle = 'font-size:10px;padding:4px 10px;border:1px solid #D1D5DB;border-radius:5px;background:#F9FAFB;color:#374151;cursor:pointer';
  html += '<div style="padding:10px 16px 14px;display:flex;gap:8px;flex-wrap:wrap;align-items:center">' +
    '<button class="tr-word-dl-btn" style="background:#059669" onclick="_chunDownloadWord(' + p.id + ',' + tid + ')">📄 Word 다운로드</button>' +
    '<button id="tr-json-btn-' + cjkey + '" onclick="_trToggleJson(\'' + cjkey + '\')" style="' + _cjbtnStyle + '">{ } JSON 보기</button>' +
    '<button onclick="_trDownloadJson(\'' + cjkey + '\',\'' + cjfilename + '\')" style="' + _cjbtnStyle + '">⬇ JSON 다운로드</button>' +
  '</div>' +
  '<pre id="tr-json-' + cjkey + '" style="display:none;margin:0 16px 14px;padding:10px 12px;background:#1E293B;color:#7DD3FC;font-size:10px;line-height:1.6;border-radius:7px;overflow-x:auto;white-space:pre-wrap;word-break:break-all"></pre>';
  html += '</div>';
  rp.innerHTML = html;
}

/* ── 결과 카드 렌더 ── */
function _lgRenderResultCard(p, idx, rp, tid, instLabel) {
  var result = p.results && p.results[tid];
  var inst   = (p.typeInstances || []).find(function(t) { return t.tid === tid; }) || {};
  var cardTitle = instLabel ? ('지문 ' + idx + ' · ' + instLabel) : ('지문 ' + idx + ' · 지문이해');
  var html   = '<div class="card">';
  html += '<div class="card-hd"><span>' + cardTitle + '</span></div>';

  /* ── 메타 정보 ── */
  if (result) {
    var lgLevelMap = { basic: '기본', standard: '표준', advanced: '고급' };
    var lgLevelLabel = lgLevelMap[inst.lgLevel || 'standard'] || '표준';
    var metaModel = result.modelId || 'claude-sonnet-4-6';
    html +=
      '<div style="padding:6px 16px 8px;display:flex;flex-wrap:wrap;gap:6px;font-size:10px;color:#374151">' +
        '<span style="background:#EFF6FF;border:1px solid #BFDBFE;border-radius:5px;padding:2px 8px">📊 문제 수준: ' + lgLevelLabel + '</span>' +
        '<span style="background:#F0FDF4;border:1px solid #BBF7D0;border-radius:5px;padding:2px 8px">🤖 출제 AI: ' + escH(metaModel) + '</span>' +
        '<span style="background:#F0FDF4;border:1px solid #BBF7D0;border-radius:5px;padding:2px 8px">🔍 검수 AI: ' + escH(metaModel) + '</span>' +
      '</div>';
  }

  html += '<div style="padding:12px 16px 6px">';
  if (result && result.passageStructure) {
    html += '<span class="lg-structure-badge">📐 ' + escH(result.passageStructure) + '</span>';
  }

  var spec = _LG_LEVEL_SPEC[inst.lgLevel || _lgLevel] || _LG_LEVEL_SPEC.standard;
  var cq   = (result && result.contentQuestions)  || [];
  var aq   = (result && result.advancedQuestions) || [];

  html += '</div>';

  if (result) {
    var passageForLogic = result.passageText || p.text || '';
    if (passageForLogic) {
      html +=
        '<div style="padding:4px 16px 10px">' +
          '<div style="font-size:10px;font-weight:600;color:#9CA3AF;text-transform:uppercase;letter-spacing:.06em;margin-bottom:7px">지문</div>' +
          '<div class="tr-passage-display">' + escH(passageForLogic) + '</div>' +
        '</div>' +
        '<div style="padding:0 16px 8px;font-size:11px;color:#374151">다음 글을 읽고 물음에 답하세요.</div>';
    }
  }

  /* ── 내용 확인 ── */
  if (cq.length > 0) {
    html += '<div class="lg-section-hd">✅ 내용 확인 문제 · ' + cq.length + '문항</div>';
    cq.forEach(function(q) {
      var uid       = 'lg-cq-' + p.id + '-' + tid + '-' + q.number;
      var qType     = q.type || '사실확인';
      var isImply   = qType.indexOf('함축설명') === 0;
      var typeLabel = isImply
        ? (qType === '함축설명-역설' ? '함축 설명 · 역설' : '함축 설명 · 비유')
        : '사실 확인';
      var typeBadgeStyle = isImply
        ? 'font-size:9px;color:#7C3AED;background:#F5F3FF;border:1px solid #DDD6FE;border-radius:5px;padding:1px 6px'
        : 'font-size:10px;color:#6B7280';
      html += '<div class="lg-q-item">' +
        '<div class="lg-q-hd">' +
          '<span class="lg-q-num">' + q.number + '</span>' +
          '<span style="flex:1"><span style="' + typeBadgeStyle + '">' + typeLabel + '</span></span>' +
          '<button class="lg-ans-toggle" id="' + uid + '-btn" onclick="lgToggleAns(\'' + uid + '\')">예시 답 확인</button>' +
        '</div>' +
        '<div class="lg-q-body">' +
          '<div class="lg-q-text">' + escH(q.question || '') + '</div>' +
          '<textarea class="lg-ans-input" placeholder="답 작성..."' + (isImply ? ' style="min-height:70px"' : '') + '></textarea>' +
          '<div class="lg-ans-key" id="' + uid + '-key">' + escH(q.answer || '') + '</div>' +
        '</div>' +
      '</div>';
    });
  }

  /* ── 심화 확인 ── */
  if (aq.length > 0) {
    html += '<div class="lg-section-hd">🔍 심화 확인 문제 · ' + aq.length + '문항</div>';
    aq.forEach(function(q) {
      var uid = 'lg-aq-' + p.id + '-' + tid + '-' + q.number;
      html += '<div class="lg-q-item">' +
        '<div class="lg-q-hd">' +
          '<span class="lg-q-num">' + q.number + '</span>' +
          (q.type ? '<span class="lg-q-type">' + escH(q.type) + '</span>' : '') +
          '<span style="flex:1"></span>' +
          '<button class="lg-ans-toggle" id="' + uid + '-btn" onclick="lgToggleAns(\'' + uid + '\')">예시 답 확인</button>' +
        '</div>' +
        '<div class="lg-q-body">' +
          '<div class="lg-q-text">' + escH(q.question || '') + '</div>' +
          '<textarea class="lg-ans-input" placeholder="답 작성..." style="min-height:70px"></textarea>' +
          '<div class="lg-ans-key" id="' + uid + '-key">' + escH(q.answer || '') + '</div>' +
        '</div>' +
      '</div>';
    });
  }

  var ljkey = p.id + '-' + tid;
  var ljfilename = '지문이해_지문' + idx + '_tid' + tid;
  _trJsonCache[ljkey] = _trBuildInstanceJson(p.id, tid);
  var _ljbtnStyle = 'font-size:10px;padding:4px 10px;border:1px solid #D1D5DB;border-radius:5px;background:#F9FAFB;color:#374151;cursor:pointer';
  html += '<div style="padding:10px 16px 14px;display:flex;gap:8px;flex-wrap:wrap;align-items:center">' +
    '<button class="tr-word-dl-btn" style="background:#059669" onclick="lgDownloadWord(' + p.id + ',' + tid + ')">📄 Word 다운로드</button>' +
    '<button id="tr-json-btn-' + ljkey + '" onclick="_trToggleJson(\'' + ljkey + '\')" style="' + _ljbtnStyle + '">{ } JSON 보기</button>' +
    '<button onclick="_trDownloadJson(\'' + ljkey + '\',\'' + ljfilename + '\')" style="' + _ljbtnStyle + '">⬇ JSON 다운로드</button>' +
  '</div>' +
  '<pre id="tr-json-' + ljkey + '" style="display:none;margin:0 16px 14px;padding:10px 12px;background:#1E293B;color:#7DD3FC;font-size:10px;line-height:1.6;border-radius:7px;overflow-x:auto;white-space:pre-wrap;word-break:break-all"></pre>';
  html += '</div>';
  rp.innerHTML = html;
}

function lgToggleAns(uid) {
  var key = document.getElementById(uid + '-key');
  var btn = document.getElementById(uid + '-btn');
  if (!key) return;
  var showing = key.classList.toggle('show');
  if (btn) btn.textContent = showing ? '예시 답 숨기기' : '예시 답 확인';
}

function _trBuildLogicHtml(pid, tid) {
  var p = _trPassages.find(function(x) { return x.id === pid; });
  var result = p && p.results && p.results[tid];
  if (!p || !result) return null;
  var pidx = _trPassages.indexOf(p) + 1;
  var cq = result.contentQuestions || [];
  var aq = result.advancedQuestions || [];
  var css = 'body{font-family:"Malgun Gothic",sans-serif;font-size:11pt;line-height:1.9;margin:35px}' +
    'h2{font-size:13pt;border-bottom:2px solid #111;padding-bottom:5px;margin-bottom:14px}' +
    'h3{font-size:11pt;color:#1D4ED8;margin:18px 0 8px}' +
    '.structure{display:inline-block;padding:3px 12px;border-radius:99px;background:#EFF6FF;color:#1D4ED8;font-size:10pt;border:1px solid #BFDBFE;margin-bottom:14px}' +
    '.passage{font-size:11pt;line-height:2;margin-bottom:14px;padding:12px 14px;border:1px solid #ccc;background:#fafafa;white-space:pre-wrap}' +
    '.instruction{font-size:10pt;color:#444;margin-bottom:16px}' +
    '.q-item{margin-bottom:18px;padding:10px 14px;border:1px solid #ccc;border-radius:4px}' +
    '.q-num{font-weight:bold;font-size:11pt;margin-bottom:6px}' +
    '.q-type{display:inline-block;font-size:9pt;padding:2px 8px;border-radius:99px;background:#F5F3FF;color:#6D28D9;border:1px solid #DDD6FE;margin-left:6px}' +
    '.q-text{font-size:11pt;margin-bottom:8px;line-height:1.8}' +
    '.ans-line{border-bottom:1px solid #aaa;min-height:28px;margin:4px 0}' +
    '.ans-section{margin-top:28px;border-top:2px dashed #ccc;padding-top:14px}' +
    '.ans-item{margin-bottom:10px;font-size:10pt;color:#374151}' +
    '.meta{font-size:9pt;color:#6B7280;margin:-6px 0 12px;padding:4px 8px;background:#F9FAFB;border:1px solid #E5E7EB}' +
    '.ans-label{font-weight:bold;color:#059669}';
  var body = '<h2>지문이해 · 지문 ' + pidx + '</h2>';
  body += _trMetaHtml(pid, tid);
  if (result.passageStructure) body += '<div class="structure">📐 ' + escH(result.passageStructure) + '</div>';
  body += '<div class="passage">' + escH(result.passageText || p.text || '') + '</div>';
  body += '<div class="instruction">다음 글을 읽고 물음에 답하세요.</div>';
  if (cq.length > 0) {
    body += '<h3>✅ 내용 확인 문제</h3>';
    cq.forEach(function(q) {
      body += '<div class="q-item"><div class="q-num">' + q.number + '.</div><div class="q-text">' + escH(q.question||'') + '</div><div class="ans-line"></div><div class="ans-line"></div></div>';
    });
  }
  if (aq.length > 0) {
    body += '<h3>🔍 심화 확인 문제</h3>';
    aq.forEach(function(q) {
      body += '<div class="q-item"><div class="q-num">' + q.number + '.' + (q.type ? '<span class="q-type">' + escH(q.type) + '</span>' : '') + '</div><div class="q-text">' + escH(q.question||'') + '</div><div class="ans-line"></div><div class="ans-line"></div><div class="ans-line"></div></div>';
    });
  }
  body += '<div class="ans-section"><h3>📝 예시 답</h3>';
  cq.concat(aq).forEach(function(q, i) {
    var label = i >= cq.length ? ('심화 ' + q.number) : ('내용 ' + q.number);
    body += '<div class="ans-item"><span class="ans-label">' + label + '</span> ' + escH(q.answer||'') + '</div>';
  });
  body += '</div>';
  return { html: '<!DOCTYPE html><html><head><meta charset="utf-8"><style>' + css + '</style></head><body>' + body + '</body></html>',
           filename: '지문이해_지문' + pidx + '_tid' + tid + '.docx' };
}

function lgDownloadWord(pid, tid) {
  var built = _trBuildLogicHtml(pid, tid);
  if (!built) return;
  var p = _trPassages.find(function(x) { return x.id === pid; });
  var ri = p ? _trPassages.indexOf(p) + 1 : 1;
  built.filename = '지문이해_지문' + ri + '.docx';
  try {
    var blob = window.htmlDocx ? window.htmlDocx.asBlob(built.html) : new Blob([built.html], { type: 'application/msword' });
    var url = URL.createObjectURL(blob);
    var a = document.createElement('a');
    a.href = url; a.download = built.filename;
    document.body.appendChild(a); a.click();
    document.body.removeChild(a); URL.revokeObjectURL(url);
  } catch (e) { showToast('다운로드 오류: ' + e.message); }
}

function _trBuildChunkHtml(pid, tid) {
  var p = _trPassages.find(function(x) { return x.id === pid; });
  var result = p && p.results && p.results[tid];
  if (!p || !result || !result.items || result.items.length === 0) return null;
  var ri = _trPassages.indexOf(p);
  var isPara = !!(result.originalPassage);
  var css = 'body{font-family:"Malgun Gothic",sans-serif;font-size:11pt;line-height:1.9;margin:35px}' +
    'h2{font-size:13pt;border-bottom:2px solid #111;padding-bottom:5px;margin-bottom:14px}' +
    '.passage{font-size:11pt;line-height:2;margin-bottom:18px;padding:12px 14px;border:1px solid #ccc;background:#fafafa}' +
    '.instruction{font-size:10pt;color:#444;margin-bottom:16px}' +
    '.q-item{margin-bottom:18px}' +
    '.q-num{font-weight:bold;color:#1D4ED8;margin-right:6px}' +
    '.q-prin{font-size:9pt;color:#7C3AED;margin-right:8px}' +
    '.q-sent{font-size:11pt;line-height:1.9}' +
    '.q-ul{border-bottom:2pt solid #1D4ED8;color:#1D4ED8;font-weight:bold}' +
    '.q-blank{display:block;border-bottom:1pt solid #555;min-width:300px;height:22px;margin-top:6px}' +
    '.answer-sec{margin-top:32px;page-break-before:always}' +
    '.meta{font-size:9pt;color:#6B7280;margin:-6px 0 12px;padding:4px 8px;background:#F9FAFB;border:1px solid #E5E7EB}' +
    '.ans-item{margin-bottom:10px;padding:6px 10px;border:1px solid #ddd;border-radius:4px;font-size:10pt}';
  var body = '<h2>해석훈련 워크시트 — 지문 ' + (ri+1) + (isPara ? ' (패러프레이즈)' : '') + '</h2>';
  body += _trMetaHtml(pid, tid);
  if (isPara && result.originalPassage) {
    body += '<div style="margin-bottom:6px;font-size:9pt;color:#6B7280;font-weight:bold">원문</div>' +
            '<div class="passage" style="background:#F3F4F6;color:#374151">' + escH(result.originalPassage) + '</div>' +
            '<div style="margin:10px 0 6px;font-size:9pt;color:#1D4ED8;font-weight:bold">지문</div>';
  }
  body += '<div class="passage">' + escH(result.passageUsed || result.passageText || '') + '</div>';
  body += '<div class="instruction">다음 밑줄 친 부분을 해석하세요.</div>';
  result.items.forEach(function(item) {
    var sent = item.full_sentence || '', ul = item.underlined || '';
    var sentHtml = escH(sent).replace(escH(ul), '<span class="q-ul">' + escH(ul) + '</span>');
    body += '<div class="q-item"><span class="q-num">' + item.number + '.</span><span class="q-prin">[원칙 ' + (item.principle||1) + ']</span><span class="q-sent">' + sentHtml + '</span><span class="q-blank"></span></div>';
  });
  body += '<div class="answer-sec"><h2 style="font-size:12pt">정 답</h2>';
  result.items.forEach(function(item) {
    body += '<div class="ans-item"><b>' + item.number + '.</b> ' + escH(item.answer||'') + '</div>';
  });
  body += '</div>';
  return { html: '<!DOCTYPE html><html><head><meta charset="utf-8"><style>' + css + '</style></head><body>' + body + '</body></html>',
           filename: '해석훈련_지문' + (ri+1) + '_tid' + tid + '.docx' };
}

function _chunDownloadWord(pid, tid) {
  var built = _trBuildChunkHtml(pid, tid);
  if (!built) return;
  var p = _trPassages.find(function(x) { return x.id === pid; });
  var ri = p ? _trPassages.indexOf(p) + 1 : 1;
  built.filename = '해석훈련_지문' + ri + '.docx';
  try {
    var blob = window.htmlDocx ? window.htmlDocx.asBlob(built.html) : new Blob([built.html], { type: 'application/msword' });
    var url  = URL.createObjectURL(blob);
    var a    = document.createElement('a');
    a.href = url; a.download = built.filename;
    document.body.appendChild(a); a.click();
    document.body.removeChild(a); URL.revokeObjectURL(url);
  } catch (e) { showToast('다운로드 오류: ' + e.message); }
}

/* ── 전체 Word 단일 파일 다운로드 ── */
function trDownloadAllWord() {
  var bodyParts = [];
  _trPassages.forEach(function(p) {
    var pi = _trPassages.indexOf(p) + 1;
    (p.typeInstances || []).forEach(function(ti) {
      var res = p.results && p.results[ti.tid];
      if (!res) return;
      var built = null;
      if      (ti.key === 'grammar') built = _trBuildGrammarHtml(p.id, ti.tid);
      else if (ti.key === 'logic')   built = _trBuildLogicHtml(p.id, ti.tid);
      else if (ti.key === 'chunk')   built = _trBuildChunkHtml(p.id, ti.tid);
      if (!built) return;
      var m = built.html.match(/<body>([\s\S]*?)<\/body>/i);
      var content = m ? m[1] : built.html;
      bodyParts.push(content);
    });
  });

  if (bodyParts.length === 0) { showToast('다운로드할 결과가 없습니다'); return; }

  var css =
    'body{font-family:"Malgun Gothic",sans-serif;font-size:11pt;line-height:1.9;margin:35px}' +
    'h2{font-size:13pt;border-bottom:2px solid #111;padding-bottom:5px;margin-bottom:14px}' +
    'h3{font-size:11pt;color:#1D4ED8;margin:18px 0 8px}' +
    '.passage{font-size:11pt;line-height:2;margin-bottom:18px;padding:12px 14px;border:1px solid #ccc;background:#fafafa}' +
    '.instruction{font-size:10pt;color:#444;margin-bottom:12px}' +
    'table{width:100%;border-collapse:collapse;font-size:10pt}' +
    'th{background:#374151;color:#fff;padding:6px 8px;text-align:center;font-size:9pt}' +
    'td{border:1px solid #ccc;padding:6px 8px;vertical-align:top}' +
    '.num-cell{text-align:center;width:32px;font-weight:bold;color:#1D4ED8}' +
    '.point-cell{width:110px;font-size:9pt;color:#374151}' +
    '.write-cell{width:120px}.reason-cell{width:auto}' +
    '.answer-sec{margin-top:24px}' +
    '.answer-row{display:flex;gap:10px;margin-bottom:10px;padding:8px 10px;border:1px solid #ddd;border-radius:4px}' +
    '.a-circle{font-size:13pt;font-weight:bold;color:#1D4ED8;min-width:22px}' +
    '.a-body{flex:1;font-size:10pt;line-height:1.6}' +
    '.verdict-err{color:#DC2626;font-weight:bold}.verdict-ok{color:#059669;font-weight:bold}' +
    '.reason-text{color:#555;font-size:9.5pt;margin-top:2px}' +
    '.meta{font-size:9pt;color:#6B7280;margin:-6px 0 12px;padding:4px 8px;background:#F9FAFB;border:1px solid #E5E7EB}' +
    '.structure{display:inline-block;padding:3px 12px;border-radius:99px;background:#EFF6FF;color:#1D4ED8;font-size:10pt;border:1px solid #BFDBFE;margin-bottom:14px}' +
    '.q-item{margin-bottom:18px;padding:10px 14px;border:1px solid #ccc;border-radius:4px}' +
    '.q-num{font-weight:bold;font-size:11pt;margin-bottom:6px;color:#1D4ED8}' +
    '.q-type{display:inline-block;font-size:9pt;padding:2px 8px;border-radius:99px;background:#F5F3FF;color:#6D28D9;border:1px solid #DDD6FE;margin-left:6px}' +
    '.q-text{font-size:11pt;margin-bottom:8px;line-height:1.8}' +
    '.ans-line{border-bottom:1px solid #aaa;min-height:28px;margin:4px 0}' +
    '.ans-section{margin-top:28px;border-top:2px dashed #ccc;padding-top:14px}' +
    '.ans-item{margin-bottom:10px;font-size:10pt;color:#374151}' +
    '.ans-label{font-weight:bold;color:#059669}' +
    '.q-prin{font-size:9pt;color:#7C3AED;margin-right:8px}' +
    '.q-sent{font-size:11pt;line-height:1.9}' +
    '.q-ul{border-bottom:2pt solid #1D4ED8;color:#1D4ED8;font-weight:bold}' +
    '.q-blank{display:block;border-bottom:1pt solid #555;min-width:300px;height:22px;margin-top:6px}';

  var combinedBody = bodyParts.map(function(part, i) {
    return (i > 0 ? '<div style="page-break-before:always"></div>' : '') + part;
  }).join('');

  var html = '<!DOCTYPE html><html><head><meta charset="utf-8"><style>' + css + '</style></head><body>' + combinedBody + '</body></html>';

  try {
    var blob = htmlDocx.asBlob(html);
    var now = new Date();
    var stamp = now.getFullYear() + '' + String(now.getMonth()+1).padStart(2,'0') + '' + String(now.getDate()).padStart(2,'0');
    var url = URL.createObjectURL(blob);
    var a = document.createElement('a');
    a.href = url; a.download = '기본기훈련_' + stamp + '.docx';
    document.body.appendChild(a); a.click(); document.body.removeChild(a);
    setTimeout(function() { URL.revokeObjectURL(url); }, 1000);
    showToast('Word 파일 다운로드 완료 (' + bodyParts.length + '개 섹션)');
  } catch(e) { showToast('다운로드 오류: ' + e.message); }
}

