/* ── 로그 추가 (pId = passage queue id) ── */
function _synLog(msg, type, pId) {
  var boxId = (pId != null) ? 'syn-pq-' + pId + '-log' : 'syn-log-box';
  var box = document.getElementById(boxId);
  if (!box) return;
  box.style.display = '';
  var line = document.createElement('div');
  line.className = 'syn-log-line ' + (type || 'info');
  var t = new Date();
  var ts = String(t.getHours()).padStart(2,'0') + ':' + String(t.getMinutes()).padStart(2,'0') + ':' + String(t.getSeconds()).padStart(2,'0');
  line.textContent = '[' + ts + '] ' + msg;
  box.appendChild(line);
  box.scrollTop = box.scrollHeight;
}

/* ── 스텝 인디케이터 ── */
function _synSetStep(stepNum, state, pId) {
  var prefix = (pId != null) ? 'syn-pq-' + pId + '-step-' : 'syn-step-';
  for (var i = 1; i <= 4; i++) {
    var el = document.getElementById(prefix + i);
    if (!el) continue;
    el.classList.remove('active', 'done');
    if (i < stepNum) el.classList.add('done');
    else if (i === stepNum && state === 'active') el.classList.add('active');
    else if (i === stepNum && state === 'done') el.classList.add('done');
  }
}

/* ── 지정 스텝까지 모두 done ── */
function _synMarkStepsDone(upToStep, pId) {
  var prefix = (pId != null) ? 'syn-pq-' + pId + '-step-' : 'syn-step-';
  for (var i = 1; i <= upToStep; i++) {
    var el = document.getElementById(prefix + i);
    if (el) { el.classList.remove('active'); el.classList.add('done'); }
  }
}

/* ── 유의어 병합 (키워드 기준 레벨별 concat + 중복 제거) ── */
function _synMerge(keywords, collectResults) {
  var wordMap = {};
  keywords.forEach(function(kw) {
    var key = kw.word.toLowerCase();
    wordMap[key] = {
      word: kw.word,
      pos: kw.pos || '',
      meaning_ko: kw.meaning_ko || '',
      type: kw.type || 'A',
      star: !!kw.star,
      context_hint: kw.context_hint || null,
      star_note: kw.star_note || null,
      synonyms_with_ko: [],
      antonyms_with_ko: []
    };
  });

  collectResults.forEach(function(res) {
    if (!res || !Array.isArray(res.synonyms)) return;
    res.synonyms.forEach(function(item) {
      var key = (item.word || '').toLowerCase();
      if (!wordMap[key]) return;
      if (Array.isArray(item.synonyms_with_ko)) {
        wordMap[key].synonyms_with_ko = wordMap[key].synonyms_with_ko.concat(item.synonyms_with_ko);
      }
      if (Array.isArray(item.antonyms_with_ko)) {
        wordMap[key].antonyms_with_ko = wordMap[key].antonyms_with_ko.concat(item.antonyms_with_ko);
      }
    });
  });

  // en 값 기준 중복 제거
  Object.values(wordMap).forEach(function(item) {
    var seenSyn = {};
    item.synonyms_with_ko = item.synonyms_with_ko.filter(function(x) {
      var k = (x.en || '').toLowerCase();
      if (!k || seenSyn[k]) return false;
      seenSyn[k] = true;
      return true;
    });
    var seenAnt = {};
    item.antonyms_with_ko = item.antonyms_with_ko.filter(function(x) {
      var k = (x.en || '').toLowerCase();
      if (!k || seenAnt[k]) return false;
      seenAnt[k] = true;
      return true;
    });
  });

  return Object.values(wordMap);
}

/* ── 전체 AI 결과 병합 (키워드 기준 없음, word 기준 자동 수집) ── */
function _synMergeAll(collectResults) {
  var wordMap = {};
  collectResults.forEach(function(res) {
    if (!res || !Array.isArray(res.synonyms)) return;
    res.synonyms.forEach(function(item) {
      var key = (item.word || '').toLowerCase();
      if (!key) return;
      if (!wordMap[key]) {
        var tokens = (item.context || '').split(/\s+/).filter(Boolean);
        var wLow = key.replace(/[^a-z]/g, '');
        var idx = tokens.findIndex(function(t) { return t.toLowerCase().replace(/[^a-z]/g,'') === wLow; });
        wordMap[key] = {
          word: item.word,
          pos: item.pos || '',
          context: item.context || '',
          context_before: idx > 0 ? tokens.slice(Math.max(0, idx-3), idx) : [],
          context_after:  idx >= 0 && idx < tokens.length-1 ? tokens.slice(idx+1, Math.min(tokens.length, idx+4)) : [],
          levels: { L01: [], L02: [], L03: [], L04: [] }
        };
      }
      ['L01','L02','L03','L04'].forEach(function(lv) {
        if (Array.isArray(item[lv])) {
          wordMap[key].levels[lv] = wordMap[key].levels[lv].concat(item[lv]);
        }
      });
    });
  });

  Object.values(wordMap).forEach(function(item) {
    ['L01','L02','L03','L04'].forEach(function(lv) {
      var seen = {};
      item.levels[lv] = item.levels[lv].filter(function(w) {
        var k = (w || '').toLowerCase();
        if (!k || seen[k]) return false;
        seen[k] = true;
        return true;
      });
    });
  });

  return Object.values(wordMap);
}

/* ── 고빈도어 JS fallback 분리 ── */
var _SYN_COMMON_LIST = [
  'behavior','increase','decrease','change','result','effect','cause','situation',
  'problem','important','significant','various','different','specific','general',
  'social','economic','political','cultural','individual','society','human',
  'people','world','time','way','life','mind','work','nature','process','system',
  'relationship','development','research','study','ability','activity',
  'information','knowledge','experience','value','role','factor','feature',
  'function','level','pattern','structure','condition'
];

function _synFallbackSplit(synonymsArr) {
  var main = [], common = [];
  synonymsArr.forEach(function(item) {
    var w = (item.word || '').toLowerCase();
    if (_SYN_COMMON_LIST.indexOf(w) >= 0) common.push(item);
    else main.push(item);
  });
  return { main_words: main, common_words: common };
}

/* ── modelId → 올바른 API 키 반환 ── */
function _synGetKey(modelId) {
  var cfg = _detectProvider(modelId);
  if (cfg.type === 'gemini') return getGeminiKey();
  if (cfg.type === 'openai') return getOpenAIKey();
  if (cfg.type === 'deepseek') return getDeepSeekKey();
  if (cfg.type === 'fable') return getFableKey() || getKey();
  return getKey();
}

function _synGetCollectModelsFromUI() {
  return ['syn-ai1', 'syn-ai2', 'syn-ai3', 'syn-ai4'].map(function(id) {
    var el = document.getElementById(id);
    return el ? el.value : '';
  }).filter(Boolean);
}

function _synNormalizeCollectModels(config, fallbackModels) {
  var models = [];
  if (config) {
    if (Array.isArray(config.collectModels)) {
      models = config.collectModels.slice();
    } else {
      models = [config.ai1, config.ai2, config.ai3, config.ai4];
    }
  }
  if (models.filter(Boolean).length === 0 && Array.isArray(fallbackModels)) {
    models = fallbackModels.slice();
  }
  return models.filter(Boolean).slice(0, 4);
}

function _synSetCollectModelsToUI(models) {
  (models || []).slice(0, 4).forEach(function(modelId, i) {
    var sel = document.getElementById('syn-ai' + (i + 1));
    if (!sel || !modelId) return;
    var opt = Array.from(sel.options).find(function(o) { return o.value === modelId; });
    if (opt) sel.value = modelId;
  });
}

function _synBuildCollectMergeSections(collectResults) {
  return (collectResults || []).map(function(result, i) {
    return '\n\n[AI ' + (i + 1) + ' 수집 결과]\n' + JSON.stringify(result || {});
  }).join('');
}

/* ── JSON 카드 표시/갱신 ── */
function _synShowJsonCard(data) {
  _synRawData = data;
  var card = document.getElementById('syn-json-card');
  var pre  = document.getElementById('syn-json-pre');
  var body = document.getElementById('syn-json-body');
  var btn  = document.getElementById('syn-json-toggle-btn');
  if (!card) return;
  if (pre)  pre.textContent = JSON.stringify(data, null, 2);
  if (body) body.style.display = 'none';
  if (btn)  btn.textContent = '펼치기';
  card.style.display = '';
}

/* ── JSON 펼치기/접기 ── */
function synToggleJson() {
  var body = document.getElementById('syn-json-body');
  var btn  = document.getElementById('syn-json-toggle-btn');
  if (!body) return;
  var open = body.style.display !== 'none';
  body.style.display = open ? 'none' : '';
  if (btn) btn.textContent = open ? '펼치기' : '접기';
}

/* ── JSON 다운로드 ── */
function synDownloadJson() {
  if (!_synRawData) { showToast('데이터가 없습니다'); return; }
  var blob = new Blob([JSON.stringify(_synRawData, null, 2)], { type: 'application/json' });
  var now  = new Date();
  var stamp = now.getFullYear() + '' + String(now.getMonth()+1).padStart(2,'0') + '' + String(now.getDate()).padStart(2,'0');
  var url = URL.createObjectURL(blob);
  var a = document.createElement('a');
  a.href = url; a.download = '유의어_' + stamp + '.json';
  document.body.appendChild(a); a.click(); document.body.removeChild(a);
  setTimeout(function() { URL.revokeObjectURL(url); }, 1000);
  showToast('JSON 다운로드 완료');
}

/* ── step1_keywords 정규화 ── */
// 저장된 형식이 {word,context}[] 또는 {word,pos,context_before,context_after}[] 두 가지를 처리
function _synNormalizeKeywords(raw) {
  // raw가 {keywords:[...]} 형태면 꺼냄
  var arr = Array.isArray(raw) ? raw : (raw && Array.isArray(raw.keywords) ? raw.keywords : null);
  if (!arr) return null;
  return arr.map(function(kw) {
    if (kw.context_before !== undefined) return kw; // 이미 정규화됨
    // {word, context} → {word, pos, context_before, context_after} 변환
    var tokens = (kw.context || '').split(/\s+/).filter(Boolean);
    var wLow = (kw.word || '').toLowerCase().replace(/[^a-z]/g, '');
    var idx = tokens.findIndex(function(t) { return t.toLowerCase().replace(/[^a-z]/g, '') === wLow; });
    var before = idx > 0 ? tokens.slice(Math.max(0, idx - 3), idx) : [];
    var after  = idx >= 0 && idx < tokens.length - 1 ? tokens.slice(idx + 1, Math.min(tokens.length, idx + 4)) : [];
    return { word: kw.word, pos: kw.pos || '', context_before: before, context_after: after };
  });
}

/* ── JSON 불러오기 ── */
function synLoadJson(input) {
  var file = input && input.files && input.files[0];
  if (!file) return;
  input.value = ''; // 같은 파일 재선택 허용

  var reader = new FileReader();
  reader.onload = function(e) {
    var data;
    try { data = JSON.parse(e.target.result); } catch(err) {
      showToast('JSON 파싱 오류: ' + err.message); return;
    }

    // 지문 채우기 (첫 번째 패시지 카드)
    var passageEl = document.getElementById('syn-pq-0-text') || document.getElementById('syn-passage');
    if (passageEl && data.passage) passageEl.value = data.passage;

    // AI 모델 선택 복원
    if (data.config) {
      _synSetCollectModelsToUI(_synNormalizeCollectModels(data.config));
      var cfgMap = { val1:'syn-val1', val2:'syn-val2' };
      Object.keys(cfgMap).forEach(function(k) {
        var sel = document.getElementById(cfgMap[k]);
        if (!sel || !data.config[k]) return;
        var opt = Array.from(sel.options).find(function(o) { return o.value === data.config[k]; });
        if (opt) sel.value = data.config[k];
      });
    }

    // JSON 카드 표시
    _synShowJsonCard(data);

    // 재개 버튼 표시 조건: step1_keywords 있고 step4_final 없음
    var resumeBtn = document.getElementById('syn-resume-btn');
    var hasStep1 = !!(data.step1_keywords &&
      (_synNormalizeKeywords(data.step1_keywords) || []).length > 0);
    var hasStep4 = !!(data.step4_final && Array.isArray(data.step4_final.main_words));
    if (resumeBtn) resumeBtn.style.display = (hasStep1 && !hasStep4) ? '' : 'none';

    // step4_final이 완성된 경우 결과 카드도 표시
    if (hasStep4 && data.passage) {
      _synResult = { passage: data.passage, finalResult: data.step4_final };
      _synPassageResults['loaded'] = { passage: data.passage, finalResult: data.step4_final, rd: data };
      _synRenderResultCard('loaded', data.passage, data.step4_final, '—', 0, data);
      showToast('JSON 불러오기 완료 — 결과 복원됨');
    } else {
      _synResult = null;
      var msg = 'JSON 불러오기 완료';
      if (hasStep1 && !hasStep4) msg += ' — Step 1 완료, Step 2부터 재개 가능';
      else if (data.error) msg += ' (오류: ' + data.error + ')';
      showToast(msg);
    }
  };
  reader.readAsText(file, 'utf-8');
}

/* ── Step 2부터 재개 실행 ── */
async function synResumeRun() {
  if (_synRunning) { showToast('이미 실행 중입니다'); return; }
  if (!_synRawData || !_synRawData.step1_keywords) {
    showToast('먼저 JSON을 불러오세요'); return;
  }
  if (!getKey() && !getGeminiKey() && !getOpenAIKey()) {
    showToast('API 키를 먼저 저장해주세요'); return;
  }

  var normalizedKws = _synNormalizeKeywords(_synRawData.step1_keywords);
  if (!normalizedKws || normalizedKws.length === 0) {
    showToast('step1_keywords를 읽을 수 없습니다'); return;
  }

  var passage = _synRawData.passage || ((document.getElementById('syn-passage') || {}).value || '').trim();
  if (!passage) { showToast('지문 데이터가 없습니다'); return; }

  var step1 = { keywords: normalizedKws };

  // config에서 AI 설정 읽기 (또는 화면 드롭다운 폴백)
  var cfg = _synRawData.config || {};
  var collectModels = _synNormalizeCollectModels(cfg, _synGetCollectModelsFromUI());
  var ai1  = collectModels[0];
  var val1 = cfg.val1 || document.getElementById('syn-val1').value;
  var val2 = cfg.val2 || document.getElementById('syn-val2').value;
  if (!ai1) { showToast('수집 AI를 1개 이상 선택해주세요'); return; }

  _synRunning = true;
  _synResult  = null;

  var resumeBtn = document.getElementById('syn-resume-btn');
  var runBtn    = document.getElementById('syn-run-btn');
  if (resumeBtn) resumeBtn.disabled = true;
  if (runBtn)    runBtn.disabled    = true;

  // progress/result cards now handled per-passage

  // _rd 초기화 (step1은 이미 있음)
  var _rd = {
    passage: passage,
    config: { collectModels: collectModels, ai1: collectModels[0] || null, ai2: collectModels[1] || null, ai3: collectModels[2] || null, ai4: collectModels[3] || null, val1: val1, val2: val2 },
    step1_keywords: _synRawData.step1_keywords,
    step2_collect: null,
    step2_merged: null,
    step3_verified: null,
    step4_final: null,
    error: null
  };

  var pId = 'resume';
  // ensure a resume log area exists
  var resCfg = document.getElementById('syn-col-cfg') || document.getElementById('syn-json-card');
  _synLog('JSON 복원 개시 — Step 2부터…', 'info');

  // Step 1은 이미 완료

  try {
    /* ── Step 2: 유의어 수집 병렬 ── */
    _synSetStep(2, 'active');
    _synLog('Step 2: 유의어 수집 병렬 시작', 'info');

    var sys2 = '당신은 영어 어휘 전문가입니다.\n\n아래 핵심어 목록의 각 단어에 대해 영어 동의어(한글 뜻 포함)와 반의어(한글 뜻 포함)를 수집하라.\n요약·설명·레벨 분류는 하지 않는다.\n\n[수집 규칙]\n1. synonyms_with_ko: 지문 문맥에서 교체 가능한 동의어 최대 4개 (각각 영어 + 한국어 뜻)\n2. antonyms_with_ko: 반의어 최대 2개 (각각 영어 + 한국어 뜻), 없으면 빈 배열\n3. 어근이 같은 단어 제외 (achieve \u2192 achievement 불가)\n4. 지문 문맥 의미에 맞는 단어만 (여러 뜻 중 지문에서 쓰인 뜻 기준)\n\n[출력 형식 — JSON만, 설명 없음]\n{"synonyms":[{"word":"단어","synonyms_with_ko":[{"en":"동의어","ko":"한국어 뜻"}],"antonyms_with_ko":[{"en":"반의어","ko":"한국어 뜻"}]}]}';
    var kwList = JSON.stringify(step1.keywords.map(function(k) { return { word: k.word, pos: k.pos, meaning_ko: k.meaning_ko }; }));
    var userMsg2 = '[지문]\n' + passage + '\n\n[핵심어 목록]\n' + kwList + '\n\n각 핵심어의 동의어와 반의어를 수집해줘. JSON만 반환.';

    var collectTasks = collectModels.map(function(modelId) {
      return { modelId: modelId, key: _synGetKey(modelId) };
    });

    _synLog('수집 AI ' + collectTasks.length + '개 병렬 호출 중…', 'info');

    var collectPromises = collectTasks.map(function(t) {
      return _callLLM(sys2, userMsg2, t.modelId, t.key, null, 'syn')
        .then(function(raw) { return _extractJson(raw); })
        .catch(function(e) {
          _synLog('수집 오류 (' + t.modelId + '): ' + e.message, 'err');
          return null;
        });
    });

    var collectResults = await Promise.all(collectPromises);
    _rd.step2_collect = collectTasks.map(function(t, i) {
      return { model: t.modelId, result: collectResults[i] };
    });
    var validCount = collectResults.filter(function(r) { return r && Array.isArray(r.synonyms); }).length;
    if (validCount === 0) throw new Error('수집 실패 — 유효한 AI 응답 없음');
    _synLog('Step 2 완료 — ' + validCount + '/' + collectTasks.length + '개 성공, 병합 중…', 'ok');

    _synLog('Step 2 병합: AI 병합 시작 (' + val1 + ')\u2026', 'info');
    var sysMerge2 = '당신은 영어 어휘 전문가입니다.\n\n여러 AI가 수집한 유의어·반의어를 하나로 병합하라.\n\n[병합 규칙]\n1. 여러 AI가 공통으로 제안한 동의어는 우선 포함 (신뢰도 높음)\n2. 한 AI만 제안한 동의어는 지문 문맥에서 자연스러운 경우만 포함\n3. 같은 영어 단어가 중복되면 한국어 뜻이 더 정확한 것으로 통합\n4. 최종 synonyms_with_ko: 최대 4개 (가장 적합한 것)\n5. 최종 antonyms_with_ko: 최대 2개\n6. word, pos, meaning_ko, type, star, context_hint, star_note 필드는 [핵심어 정보] 기준으로 유지\n\n[출력 형식 — JSON만, 설명 없음]\n{"synonyms":[{"word":"단어","synonyms_with_ko":[{"en":"동의어","ko":"한국어 뜻"}],"antonyms_with_ko":[{"en":"반의어","ko":"한국어 뜻"}]}]}';
    var kwInfoForMerge2 = JSON.stringify(step1.keywords.map(function(k) {
      return { word: k.word, pos: k.pos, meaning_ko: k.meaning_ko, type: k.type, star: k.star, context_hint: k.context_hint, star_note: k.star_note };
    }));
    var userMsgMerge2 = '[지문]\n' + passage + '\n\n[핵심어 정보]\n' + kwInfoForMerge2 + _synBuildCollectMergeSections(collectResults) + '\n\n병합 후 JSON 반환.';
    var rawMerge2 = await _callLLM(sysMerge2, userMsgMerge2, val1, _synGetKey(val1), null, 'syn');
    var mergeResult2 = _extractJson(rawMerge2);
    _rd.step2_merged_ai = mergeResult2;

    var kwMap2r = {};
    step1.keywords.forEach(function(kw) { kwMap2r[kw.word.toLowerCase()] = kw; });
    var merged;
    if (mergeResult2 && Array.isArray(mergeResult2.synonyms)) {
      merged = mergeResult2.synonyms.map(function(item) {
        var orig = kwMap2r[(item.word || '').toLowerCase()];
        if (orig) {
          if (!item.meaning_ko) item.meaning_ko = orig.meaning_ko || '';
          if (!item.type) item.type = orig.type || 'A';
          if (item.star === undefined || item.star === null) item.star = orig.star || false;
          if (!item.context_hint) item.context_hint = orig.context_hint || null;
          if (!item.star_note) item.star_note = orig.star_note || null;
          if (!item.synonyms_with_ko) item.synonyms_with_ko = [];
          if (!item.antonyms_with_ko) item.antonyms_with_ko = [];
        }
        return item;
      });
    } else {
      _synLog('AI 병합 실패 \u2192 JS 병합으로 대체', 'err');
      merged = _synMerge(step1.keywords, collectResults);
    }
    _rd.step2_merged = merged;
    _synMarkStepsDone(2);

    /* ── Step 3: 검증 1 ── */
    _synSetStep(3, 'active');
    _synLog('Step 3: 문맥 검증 시작 (' + val2 + ')', 'info');

    var ctxMap = {};
    step1.keywords.forEach(function(kw) { ctxMap[kw.word.toLowerCase()] = kw; });

    var sys3 = '당신은 영어 어휘 검증 전문가입니다.\n\n[1단계 — 제거]\n아래 기준에 해당하는 동의어를 synonyms_with_ko에서 삭제한다:\n- 지문 문맥에서 교체 시 의미 부자연스러운 경우\n- 품사 불일치\n- 레지스터 불일치 (지나치게 구어적이거나 고어)\n- 원래 단어와 실질적으로 다른 의미\n\n[2단계 — 보완]\n1단계 후 synonyms_with_ko가 1개 이하인 단어에 동의어 1~2개를 추가한다:\n- 지문 문맥에서 교체 가능한 단어만\n- 각 동의어에 한국어 뜻 포함 ({"en":"단어","ko":"뜻"} 형식)\n\n입력과 동일한 JSON 구조로만 반환, 설명 없음\n(word, pos, meaning_ko, type, star, context_hint, star_note 필드는 그대로 유지)';
    var userMsg3 = '[지문]\n' + passage + '\n\n[유의어 목록]\n' + JSON.stringify({ synonyms: merged }, null, 2) + '\n\n검증 후 동일 구조 JSON 반환.';
    var raw3 = await _callLLM(sys3, userMsg3, val2, _synGetKey(val2), null, 'syn');
    var step3 = _extractJson(raw3);
    _rd.step3_verified = step3;
    if (step3 && Array.isArray(step3.synonyms)) {
      merged = step3.synonyms.map(function(item) {
        var orig = ctxMap[(item.word || '').toLowerCase()];
        if (orig) {
          if (!item.meaning_ko) item.meaning_ko = orig.meaning_ko || '';
          if (!item.type) item.type = orig.type || 'A';
          if (item.star === undefined || item.star === null) item.star = orig.star || false;
          if (!item.context_hint) item.context_hint = orig.context_hint || null;
          if (!item.star_note) item.star_note = orig.star_note || null;
          if (!item.synonyms_with_ko || item.synonyms_with_ko.length === 0) item.synonyms_with_ko = orig.synonyms_with_ko || [];
          if (!item.antonyms_with_ko || item.antonyms_with_ko.length === 0) item.antonyms_with_ko = orig.antonyms_with_ko || [];
        }
        return item;
      });
    }
    _synMarkStepsDone(3);
    _synLog('Step 3 완료 — 검증 후 ' + merged.length + '개', 'ok');

    /* ── Step 4: Type A/B 분류 (JS 기반, Step 1-A 결과 활용) ── */
    _synSetStep(4, 'active');
    _synLog('Step 4: Type A/B 분류 중…', 'info');

    var typeA = merged.filter(function(item) { return (item.type || 'A') === 'A'; });
    var typeB = merged.filter(function(item) { return item.type === 'B'; });
    var finalResult = { type_a: typeA, type_b: typeB };
    _rd.step4_final = finalResult;

    _synMarkStepsDone(4);
    _synLog('Step 4 완료 — Type A ' + typeA.length + '개 / Type B ' + typeB.length + '개', 'ok');

    _synResult = { passage: passage, finalResult: finalResult };
    _synRawData = _rd;
    _synAccumulated.push({ passage: passage, finalResult: finalResult });
    _synUpdateAccumBar();
    // resume: use pId 'resume' for result card
    _synPassageResults['resume'] = { passage: passage, finalResult: finalResult, rd: _rd };
    _synRenderResultCard('resume', passage, finalResult, '—', 0, _rd);
    synDownloadWordP('resume');
    synDownloadExcelP('resume');
    showToast('재개 완료 (A:' + typeA.length + '개 / B:' + typeB.length + '개) — Word · Excel 자동 다운로드');

  } catch(e) {
    _rd.error = e.message;
    _synLog('오류: ' + e.message, 'err');
    showToast('오류: ' + e.message);
  } finally {
    _synRunning = false;
    if (resumeBtn) { resumeBtn.disabled = false; resumeBtn.style.display = 'none'; }
    if (runBtn)    runBtn.disabled = false;
    _synShowJsonCard(_rd);
  }
}

/* ── 모델별 비용 추정 테이블 ($/MTok) ── */
var _SYN_PRICES = {
  'claude-sonnet-5':   { i: 3,     o: 15   },
  'claude-sonnet-4-6': { i: 3,     o: 15   },
  'gemini-3.6-flash':  { i: 1.50,  o: 7.50 },
  'gemini-3.5-flash':  { i: 1.50,  o: 9.00 },
  'gemini-3.5-flash-lite': { i: 0.30, o: 2.50 },
  'gpt-5.6-sol':       { i: 5.00,  o: 30.00 },
  'gpt-5.6-terra':     { i: 2.50,  o: 15.00 },
  'gpt-5.6-luna':      { i: 1.00,  o: 6.00 },
  'gemini-2.5-pro':    { i: 1.25,  o: 10   },
  'gemini-3-flash':    { i: 0.50,  o: 3.00 },
  'gemini-2.5-flash':  { i: 0.30,  o: 2.50 },
  'gpt-4o':            { i: 2.5,   o: 10   },
  'deepseek-chat':     { i: 0.14,  o: 0.28 },
  'deepseek-reasoner': { i: 0.55,  o: 2.19 }
};

function _synEstimateCost(passage, models) {
  // 지문당 약 5회 API 호출: 입력 ~(passage/4+600)tok, 출력 ~1000tok 추정
  var inputToks = Math.ceil(passage.length / 4) + 600;
  var outputToks = 1000;
  var total = 0;
  models.filter(Boolean).forEach(function(m) {
    var p = _SYN_PRICES[m] || { i: 3, o: 15 };
    total += (inputToks * p.i + outputToks * p.o) / 1e6;
  });
  return total;
}

/* ── 지문 큐 패시지 카드 레이블 가져오기 ── */
function _synGetPassageLabel(pId) {
  var card = document.getElementById('syn-pq-' + pId);
  if (card) {
    var titleEl = card.querySelector('.syn-pq-title');
    if (titleEl) return titleEl.textContent;
  }
  return '지문';
}

/* ── 패시지 상태 뱃지 업데이트 ── */
function _synPqSetStatus(pId, cls, text) {
  var el = document.getElementById('syn-pq-' + pId + '-status');
  if (!el) return;
  el.className = 'syn-pq-status';
  if (cls) el.classList.add('s-' + cls);
  el.textContent = text;
}

/* ── 결과 카드 렌더링 (오른쪽 패널) ── */
function _synRenderResultCard(pId, passage, finalResult, elapsedSec, costEst, rd) {
  var panel = document.getElementById('syn-results-panel');
  if (!panel) return;
  // 빈 상태 숨김
  var emptyEl = document.getElementById('syn-results-empty');
  if (emptyEl) emptyEl.style.display = 'none';
  // 기존 카드 교체
  var existing = document.getElementById('syn-res-' + pId);
  if (existing) existing.remove();

  var typeA = (finalResult.type_a || finalResult.main_words || []).length;
  var typeB = (finalResult.type_b || finalResult.common_words || []).length;
  var label = _synGetPassageLabel(pId) || '불러온 결과';
  var costStr = costEst < 0.001 ? '<$0.001' : '$' + costEst.toFixed(3);

  var card = document.createElement('div');
  card.className = 'card';
  card.id = 'syn-res-' + pId;
  card.dataset.pid = pId;
  card.innerHTML =
    '<div class="card-hd"><span>' + label + ' 결과</span>'
    + '<div class="syn-res-meta"><span class="syn-res-tag">⏱ ' + elapsedSec + 's</span><span class="syn-res-tag">💰 ' + costStr + '</span></div></div>'
    + '<div style="padding:8px 12px 12px;display:flex;flex-direction:column;gap:8px">'
    + '<div style="font-size:12px;color:#374151">Type A ' + typeA + '개 · Type B ' + typeB + '개</div>'
    + '<div style="display:flex;gap:5px;flex-wrap:wrap">'
    + '<button class="syn-dl-btn" style="padding:6px;font-size:11px" onclick="synViewJsonP(\'' + pId + '\')">📋 JSON 보기</button>'
    + '<button class="syn-dl-btn" style="background:#374151;padding:6px;font-size:11px" onclick="synDownloadWordP(\'' + pId + '\')">📄 Word</button>'
    + '<button class="syn-dl-btn" style="background:#1D6F42;padding:6px;font-size:11px" onclick="synDownloadExcelP(\'' + pId + '\')">📊 Excel</button>'
    + '</div></div>';
  panel.appendChild(card);
}

/* ── 패시지별 JSON/Word/Excel ── */
var _synPassageResults = {};  // pId -> {passage, finalResult, rd}

function synViewJsonP(pId) {
  var r = _synPassageResults[pId];
  if (!r) { showToast('결과 없음'); return; }
  _synRawData = r.rd;
  _synShowJsonCard(r.rd);
}
function synDownloadWordP(pId) {
  var r = _synPassageResults[pId];
  if (!r) { showToast('결과 없음'); return; }
  try {
    var html = _synBuildWordDoc(r.passage, r.finalResult);
    var blob = new Blob(['﻿' + html], { type: 'application/msword' });
    var label = _synGetPassageLabel(pId).replace(/\s+/g, '_');
    var a = document.createElement('a'); a.href = URL.createObjectURL(blob);
    a.download = '유의어_' + label + '.doc'; document.body.appendChild(a); a.click(); document.body.removeChild(a);
  } catch(e) { showToast('Word 오류: ' + e.message); }
}
function synDownloadExcelP(pId) {
  var r = _synPassageResults[pId];
  if (!r) { showToast('결과 없음'); return; }
  try {
    var wb = _synBuildExcelWorkbook([{ passage: r.passage, finalResult: r.finalResult }]);
    var label = _synGetPassageLabel(pId).replace(/\s+/g, '_');
    XLSX.writeFile(wb, '유의어_' + label + '.xlsx');
  } catch(e) { showToast('Excel 오류: ' + e.message); }
}

/* ── 지문 추가 ── */
var _synPassageCounter = 1;  // 0 is the default card
function synAddPassage() {
  var pId = _synPassageCounter++;
  var num = document.getElementById('syn-queue-panel').querySelectorAll('.syn-pq-card').length + 1;
  var card = document.createElement('div');
  card.className = 'card syn-pq-card';
  card.id = 'syn-pq-' + pId;
  card.dataset.pid = pId;
  card.innerHTML =
    '<div class="syn-pq-hd">'
    + '<span class="syn-pq-title">지문 ' + num + '</span>'
    + '<span class="syn-pq-status" id="syn-pq-' + pId + '-status">대기</span>'
    + '<button class="syn-pq-del" onclick="synRemovePassage(' + pId + ')" title="삭제">✕</button>'
    + '</div>'
    + '<div style="padding:8px 12px 10px"><textarea id="syn-pq-' + pId + '-text" class="syn-pq-ta" placeholder="영어 지문을 붙여넣으세요…"></textarea></div>'
    + '<div class="syn-mini-step-bar" id="syn-pq-' + pId + '-steps" style="display:none">'
    + '<div class="syn-step" id="syn-pq-' + pId + '-step-1"><div class="syn-step-dot">①</div><div class="syn-step-lbl">추출</div></div>'
    + '<div class="syn-step" id="syn-pq-' + pId + '-step-2"><div class="syn-step-dot">②</div><div class="syn-step-lbl">수집</div></div>'
    + '<div class="syn-step" id="syn-pq-' + pId + '-step-3"><div class="syn-step-dot">③</div><div class="syn-step-lbl">병합</div></div>'
    + '<div class="syn-step" id="syn-pq-' + pId + '-step-4"><div class="syn-step-dot">④</div><div class="syn-step-lbl">검증</div></div>'
    + '</div>'
    + '<div class="syn-mini-log" id="syn-pq-' + pId + '-log" style="display:none"></div>';
  document.getElementById('syn-queue-panel').appendChild(card);
}

/* ── 지문 삭제 ── */
function synRemovePassage(pId) {
  var card = document.getElementById('syn-pq-' + pId);
  if (card) card.remove();
  var resCard = document.getElementById('syn-res-' + pId);
  if (resCard) resCard.remove();
  delete _synPassageResults[pId];
  // 번호 재정렬
  var cards = document.getElementById('syn-queue-panel').querySelectorAll('.syn-pq-card');
  cards.forEach(function(c, i) {
    var t = c.querySelector('.syn-pq-title');
    if (t) t.textContent = '지문 ' + (i + 1);
  });
  // 결과 패널 비어있으면 empty state 복원
  var rPanel = document.getElementById('syn-results-panel');
  if (rPanel && rPanel.querySelectorAll('.card:not(#syn-results-empty)').length === 0) {
    var emptyEl = document.getElementById('syn-results-empty');
    if (emptyEl) emptyEl.style.display = '';
  }
}

/* ── 핵심 파이프라인 (passage + pId 기반) ── */
var _synRunningSet = new Set();

async function _synRunPassageCore(passage, pId, collectModels, val1, val2) {
  collectModels = _synNormalizeCollectModels({ collectModels: collectModels });
  var ai1 = collectModels[0];
  if (!ai1) throw new Error('수집 AI를 1개 이상 선택해주세요');
  _synPqSetStatus(pId, 'run', '실행 중');
  var stepsEl = document.getElementById('syn-pq-' + pId + '-steps');
  var logEl   = document.getElementById('syn-pq-' + pId + '-log');
  if (stepsEl) stepsEl.style.display = '';
  if (logEl)   { logEl.style.display = ''; logEl.innerHTML = ''; }
  for (var si = 1; si <= 4; si++) {
    var sel = document.getElementById('syn-pq-' + pId + '-step-' + si);
    if (sel) sel.classList.remove('active', 'done');
  }

  var startTime = Date.now();
  var _rd = {
    passage: passage,
    config: { collectModels: collectModels, ai1: collectModels[0] || null, ai2: collectModels[1] || null, ai3: collectModels[2] || null, ai4: collectModels[3] || null, val1: val1, val2: val2 },
    step1_keywords: null, step1_collect: null,
    step2_merged_ai: null, step2_merged: null,
    step3_verified: null, step4_final: null, error: null
  };

  try {
    /* ── Step 1-A: 핵심어 추출 ── */
    _synSetStep(1, 'active', pId);
    _synLog('Step 1-A: 핵심어 추출 중 (' + ai1 + ')…', 'info', pId);

    var sysExtract = `당신은 영어 어휘 교육 전문가입니다.

아래 지문에서 핵심어를 추출하고 분류하라. 유의어·반의어 수집은 하지 않는다.

[핵심어 선정 기준]
- 포함: 명사(고유명사는 제외), 동사(기능동사는 제외), 형용사, 부사
- 제외: 관사, 전치사, 접속사, 대명사, 조동사
- 제외 기본동사: be, have, do, make, get, go, say, come, take, give, know, think, see, look, want, use
- 전체 내용어의 약 30% 추출

[Type 분류]
- Type A: 지문 이해에 꼭 필요한 핵심어
- Type B: 지문 내용 주변 맥락에서 나온 보조적인 단어 (전체의 20% 이하)

[★ 단어 선정]
- 이 지문에서 특별히 중요하거나 다의어·문맥 의존적 뜻을 가진 단어
- 전체 추출 단어 중 3~5개만 선정

[출력 형식 — JSON만, 설명 없음]
{"keywords":[{"word":"원형","pos":"n/v/adj/adv","meaning_ko":"지문 내 한국어 뜻","type":"A","star":false,"context_hint":null,"star_note":null}]}

※ Type B 단어: context_hint에 뜻 유추에 도움이 되는 짧은 문맥 힌트(한국어) 작성
※ ★ 단어: star_note에 2~3문장의 문맥 의미 설명(한국어) 작성, star: true로 설정`;
    var rawExtract = await _callLLM(sysExtract, '[지문]\n' + passage + '\n\n핵심어를 추출해줘. JSON만 반환.', ai1, _synGetKey(ai1), null, 'syn');
    var extractResult = _extractJson(rawExtract);
    if (!extractResult || !Array.isArray(extractResult.keywords) || extractResult.keywords.length === 0) {
      throw new Error('핵심어 추출 실패 — AI 응답을 읽을 수 없음');
    }
    var keywords = extractResult.keywords;
    _rd.step1_keywords = keywords;
    _synLog('Step 1-A 완료 — 핵심어 ' + keywords.length + '개', 'ok', pId);

    /* ── Step 1-B: 유의어 수집 병렬 ── */
    _synLog('Step 1-B: 유의어 수집 병렬…', 'info', pId);
    var sysSynCollect = `당신은 영어 어휘 전문가입니다.

아래 핵심어 목록의 각 단어에 대해 영어 동의어(한글 뜻 포함)와 반의어(한글 뜻 포함)를 수집하라.
요약·설명·레벨 분류는 하지 않는다.

[수집 규칙]
1. synonyms_with_ko: 지문 문맥에서 교체 가능한 동의어 최대 4개 (각각 영어 + 한국어 뜻)
2. antonyms_with_ko: 반의어 최대 2개 (각각 영어 + 한국어 뜻), 없으면 빈 배열
3. 어근이 같은 단어 제외
4. 지문 문맥 의미에 맞는 단어만

[출력 형식 — JSON만, 설명 없음]
{"synonyms":[{"word":"단어","synonyms_with_ko":[{"en":"동의어","ko":"한국어 뜻"}],"antonyms_with_ko":[{"en":"반의어","ko":"한국어 뜻"}]}]}`;
    var kwForSyn = JSON.stringify(keywords.map(function(k) { return { word: k.word, pos: k.pos, meaning_ko: k.meaning_ko }; }));
    var userMsgSyn = '[지문]\n' + passage + '\n\n[핵심어 목록]\n' + kwForSyn + '\n\n각 핵심어의 동의어와 반의어를 수집해줘. JSON만 반환.';
    var collectTasks = collectModels.map(function(modelId) {
      return { modelId: modelId, key: _synGetKey(modelId) };
    });
    _synLog('수집 AI ' + collectTasks.length + '개 병렬…', 'info', pId);
    var collectPromises = collectTasks.map(function(t) {
      return _callLLM(sysSynCollect, userMsgSyn, t.modelId, t.key, null, 'syn')
        .then(function(raw) { return _extractJson(raw); })
        .catch(function(e) { _synLog('수집 오류 (' + t.modelId + '): ' + e.message, 'err', pId); return null; });
    });
    var collectResults = await Promise.all(collectPromises);
    _rd.step1_collect = collectTasks.map(function(t, i) { return { model: t.modelId, result: collectResults[i] }; });
    var validCount = collectResults.filter(function(r) { return r && Array.isArray(r.synonyms); }).length;
    if (validCount === 0) throw new Error('수집 실패 — 유효한 AI 응답 없음');
    _synMarkStepsDone(1, pId);
    _synLog('Step 1 완료 — ' + validCount + '/' + collectTasks.length + '개 성공', 'ok', pId);

    /* ── Step 2: AI 병합 ── */
    _synSetStep(2, 'active', pId);
    _synLog('Step 2: AI 병합 (' + val1 + ')…', 'info', pId);
    var sysMerge = `당신은 영어 어휘 전문가입니다.

여러 AI가 수집한 유의어·반의어를 하나로 병합하라.

[병합 규칙]
1. 여러 AI가 공통으로 제안한 동의어는 우선 포함
2. 한 AI만 제안한 동의어는 지문 문맥에서 자연스러운 경우만 포함
3. 같은 영어 단어 중복시 한국어 뜻이 더 정확한 것으로 통합
4. 최종 synonyms_with_ko: 최대 4개
5. 최종 antonyms_with_ko: 최대 2개
6. word, pos, meaning_ko, type, star, context_hint, star_note 필드는 [핵심어 정보] 기준으로 유지

[출력 형식 — JSON만, 설명 없음]
{"synonyms":[{"word":"단어","synonyms_with_ko":[{"en":"동의어","ko":"한국어 뜻"}],"antonyms_with_ko":[{"en":"반의어","ko":"한국어 뜻"}]}]}`;
    var kwInfoForMerge = JSON.stringify(keywords.map(function(k) { return { word: k.word, pos: k.pos, meaning_ko: k.meaning_ko, type: k.type, star: k.star, context_hint: k.context_hint, star_note: k.star_note }; }));
    var userMsgMerge = '[지문]\n' + passage + '\n\n[핵심어 정보]\n' + kwInfoForMerge + _synBuildCollectMergeSections(collectResults) + '\n\n병합 후 JSON 반환.';
    var rawMerge = await _callLLM(sysMerge, userMsgMerge, val1, _synGetKey(val1), null, 'syn');
    var mergeResult = _extractJson(rawMerge);
    _rd.step2_merged_ai = mergeResult;
    var kwMap2 = {};
    keywords.forEach(function(kw) { kwMap2[kw.word.toLowerCase()] = kw; });
    var merged;
    if (mergeResult && Array.isArray(mergeResult.synonyms)) {
      merged = mergeResult.synonyms.map(function(item) {
        var orig = kwMap2[(item.word || '').toLowerCase()];
        if (orig) {
          if (!item.meaning_ko) item.meaning_ko = orig.meaning_ko || '';
          if (!item.type) item.type = orig.type || 'A';
          if (item.star === undefined || item.star === null) item.star = orig.star || false;
          if (!item.context_hint) item.context_hint = orig.context_hint || null;
          if (!item.star_note) item.star_note = orig.star_note || null;
          if (!item.synonyms_with_ko) item.synonyms_with_ko = [];
          if (!item.antonyms_with_ko) item.antonyms_with_ko = [];
        }
        return item;
      });
    } else {
      _synLog('AI 병합 실패 → JS 병합 대체', 'err', pId);
      merged = _synMerge(keywords, collectResults);
    }
    _rd.step2_merged = merged;
    _synMarkStepsDone(2, pId);
    _synLog('Step 2 완료 — ' + merged.length + '개 병합', 'ok', pId);

    /* ── Step 3: 검증 ── */
    _synSetStep(3, 'active', pId);
    _synLog('Step 3: 문맥 검증 (' + val2 + ')', 'info', pId);
    var ctxMap = {};
    merged.forEach(function(kw) { ctxMap[(kw.word||'').toLowerCase()] = kw; });
    var sys3 = `당신은 영어 어휘 검증 전문가입니다.

[1단계 — 제거]
아래 기준에 해당하는 동의어를 synonyms_with_ko에서 삭제한다:
- 지문 문맥에서 교체 시 의미 부자연스러운 경우
- 품사 불일치
- 레지스터 불일치
- 원래 단어와 실질적으로 다른 의미

[2단계 — 보완]
1단계 후 synonyms_with_ko가 1개 이하인 단어에 동의어 1~2개를 추가한다.

입력과 동일한 JSON 구조로만 반환, 설명 없음
(word, pos, meaning_ko, type, star, context_hint, star_note 필드는 그대로 유지)`;
    var userMsg3 = '[지문]\n' + passage + '\n\n[유의어 목록]\n' + JSON.stringify({ synonyms: merged }, null, 2) + '\n\n검증 후 동일 구조 JSON 반환.';
    var raw3 = await _callLLM(sys3, userMsg3, val2, _synGetKey(val2), null, 'syn');
    var step3 = _extractJson(raw3);
    _rd.step3_verified = step3;
    if (step3 && Array.isArray(step3.synonyms)) {
      merged = step3.synonyms.map(function(item) {
        var orig = ctxMap[(item.word || '').toLowerCase()];
        if (orig) {
          if (!item.meaning_ko) item.meaning_ko = orig.meaning_ko || '';
          if (!item.type) item.type = orig.type || 'A';
          if (item.star === undefined || item.star === null) item.star = orig.star || false;
          if (!item.context_hint) item.context_hint = orig.context_hint || null;
          if (!item.star_note) item.star_note = orig.star_note || null;
          if (!item.synonyms_with_ko || item.synonyms_with_ko.length === 0) item.synonyms_with_ko = orig.synonyms_with_ko || [];
          if (!item.antonyms_with_ko || item.antonyms_with_ko.length === 0) item.antonyms_with_ko = orig.antonyms_with_ko || [];
        }
        return item;
      });
    }
    _synMarkStepsDone(3, pId);
    _synLog('Step 3 완료 — 검증 후 ' + merged.length + '개', 'ok', pId);

    /* ── Step 4: Type A/B 분류 ── */
    _synSetStep(4, 'active', pId);
    _synLog('Step 4: Type A/B 분류…', 'info', pId);
    var typeA = merged.filter(function(item) { return (item.type || 'A') === 'A'; });
    var typeB = merged.filter(function(item) { return item.type === 'B'; });
    var finalResult = { type_a: typeA, type_b: typeB };
    _rd.step4_final = finalResult;
    _synMarkStepsDone(4, pId);
    _synLog('Step 4 완료 — Type A ' + typeA.length + '개 / Type B ' + typeB.length + '개', 'ok', pId);

    var elapsedSec = ((Date.now() - startTime) / 1000).toFixed(1);
    var costEst = _synEstimateCost(passage, collectModels.concat([val1, val2]));

    // 누적
    _synResult = { passage: passage, finalResult: finalResult };
    _synRawData = _rd;
    _synAccumulated.push({ passage: passage, finalResult: finalResult });
    _synUpdateAccumBar();

    // 결과 저장 및 카드 렌더링
    _synPassageResults[pId] = { passage: passage, finalResult: finalResult, rd: _rd };
    _synPqSetStatus(pId, 'ok', '완료 \u2714');
    _synRenderResultCard(pId, passage, finalResult, elapsedSec, costEst, _rd);

    // 배치 통계 누적
    _synAddBatchStats(passage, collectModels.concat([val1, val2]));
    _synShowJsonCard(_rd);
    showToast('[' + _synGetPassageLabel(pId) + '] 완료 (A:' + typeA.length + ' B:' + typeB.length + ', ' + elapsedSec + 's, $' + costEst.toFixed(3) + ')');

  } catch(e) {
    _rd.error = e.message;
    _synLog('오류: ' + e.message, 'err', pId);
    _synPqSetStatus(pId, 'err', '오류');
    _synShowJsonCard(_rd);
  }
}

/* ── 배치(현재 실행) 통계 ── */
var _synBatchStats = { inputToks: 0, outputToks: 0, cost: 0, passages: 0 };

function _synResetBatchStats() {
  _synBatchStats = { inputToks: 0, outputToks: 0, cost: 0, passages: 0 };
}

function _synAddBatchStats(passage, models) {
  var inputToks = Math.ceil(passage.length / 4) + 600;
  var outputToks = 1000;
  var mods = models.filter(Boolean);
  var cost = 0;
  mods.forEach(function(m) {
    var p = _SYN_PRICES[m] || { i: 3, o: 15 };
    cost += (inputToks * p.i + outputToks * p.o) / 1e6;
  });
  _synBatchStats.inputToks   += inputToks  * mods.length;
  _synBatchStats.outputToks  += outputToks * mods.length;
  _synBatchStats.cost        += cost;
  _synBatchStats.passages    += 1;
}

function _synRenderBatchStats() {
  var el = document.getElementById('syn-gp-cost');
  if (!el) return;
  var s = _synBatchStats;
  if (s.passages === 0) { el.innerHTML = ''; return; }
  var totalTok = (s.inputToks + s.outputToks).toLocaleString();
  var totalKRW = '≈ ₩' + Math.round(s.cost * 1380).toLocaleString();
  el.innerHTML =
    '<div class="gp-cost-row"><span class="gp-cost-model">토큰 (추정)</span>'
    + '<span class="gp-cost-val" style="font-size:9px">'
    + '<span style="color:#3B82F6" title="입력">↑' + s.inputToks.toLocaleString() + '</span>'
    + ' <span style="color:#059669" title="출력">↓' + s.outputToks.toLocaleString() + '</span>'
    + ' (' + totalTok + ')'
    + '</span></div>'
    + '<div class="gp-cost-total"><span>비용 (추정)</span>'
    + '<span class="gp-cost-val">$' + s.cost.toFixed(4) + ' ' + totalKRW + '</span></div>';
}

/* ── 누적 결과 관리 ── */
var _synAccumulated = [];

function _synUpdateAccumBar() {
  var bar   = document.getElementById('syn-accum-bar');
  var count = document.getElementById('syn-accum-count');
  if (!bar) return;
  if (_synAccumulated.length > 0) {
    bar.style.display = '';
    if (count) count.textContent = _synAccumulated.length;
  } else {
    bar.style.display = 'none';
  }
}

function synDownloadWordAll() {
  if (_synAccumulated.length === 0) { showToast('누적 결과가 없습니다'); return; }
  try {
    var doc = _synBuildWordDoc(
      _synAccumulated.map(function(r) { return r.passage; }).join('\n\n---\n\n'),
      { type_a: _synAccumulated.flatMap(function(r) { return r.finalResult.type_a || []; }),
        type_b: _synAccumulated.flatMap(function(r) { return r.finalResult.type_b || []; }) }
    );
    var blob = htmlDocx.asBlob(doc);
    var url = URL.createObjectURL(blob);
    var a = document.createElement('a');
    a.href = url;
    a.download = '유의어_전체_누적.docx';
    a.click();
    setTimeout(function() { URL.revokeObjectURL(url); }, 1000);
    showToast('전체 Word 다운로드 완료');
  } catch(e) { showToast('Word 오류: ' + e.message); }
}

function synDownloadExcelAll() {
  if (_synAccumulated.length === 0) { showToast('누적 결과가 없습니다'); return; }
  try {
    var wb = _synBuildExcelWorkbook(_synAccumulated);
    XLSX.writeFile(wb, '유의어_전체_누적.xlsx');
    showToast('전체 Excel 다운로드 완료');
  } catch(e) { showToast('Excel 오류: ' + e.message); }
}

function synClearAccum() {
  _synAccumulated = [];
  _synUpdateAccumBar();
  showToast('누적 결과 초기화됨');
}

async function synRunAll() {
  var cards = document.getElementById('syn-queue-panel').querySelectorAll('.syn-pq-card');
  var tasks = [];
  cards.forEach(function(card) {
    var pId = card.dataset.pid;
    if (_synRunningSet.has(pId)) return;
    var ta = document.getElementById('syn-pq-' + pId + '-text');
    if (!ta) return;
    var passage = ta.value.trim();
    if (!passage) return;
    tasks.push({ pId: pId, passage: passage });
  });
  if (tasks.length === 0) { showToast('지문을 입력해주세요'); return; }
  if (!getKey() && !getGeminiKey() && !getOpenAIKey() && !getDeepSeekKey()) {
    showToast('API 키를 먼저 저장해주세요'); return;
  }
  var collectModels = _synGetCollectModelsFromUI();
  if (collectModels.length === 0) { showToast('수집 AI를 1개 이상 선택해주세요'); return; }
  var val1 = document.getElementById('syn-val1').value;
  var val2 = document.getElementById('syn-val2').value;
  var runBtn  = document.getElementById('syn-run-all-btn');
  var gpBox   = document.getElementById('syn-gp-box');
  var gpCount = document.getElementById('syn-gp-count');
  var gpFill  = document.getElementById('syn-gp-fill');
  var gpLabel = document.getElementById('syn-gp-label');
  var gpTime  = document.getElementById('syn-gp-time');
  var wBtn    = document.getElementById('syn-word-all-btn');
  var eBtn    = document.getElementById('syn-excel-all-btn');

  // 배치 초기화
  _synResetBatchStats();

  // gp-box 초기화 및 표시
  if (gpBox)   { gpBox.style.display = 'flex'; gpBox.classList.remove('done'); }
  if (gpCount) gpCount.textContent = '0 / ' + tasks.length + ' 지문';
  if (gpFill)  gpFill.style.width  = '0%';
  if (gpLabel) gpLabel.textContent = '실행 중…';
  if (gpTime)  gpTime.textContent  = '0초';
  _synRenderBatchStats();

  // 다운로드 버튼 숨김
  if (wBtn) wBtn.style.display = 'none';
  if (eBtn) eBtn.style.display = 'none';

  var startTime = Date.now();
  var gpTimer = setInterval(function() {
    if (gpTime) gpTime.textContent = Math.round((Date.now() - startTime) / 1000) + '초';
  }, 1000);

  if (runBtn) runBtn.disabled = true;
  tasks.forEach(function(t) { _synRunningSet.add(t.pId); });

  await Promise.all(tasks.map(function(t) {
    return _synRunPassageCore(t.passage, t.pId, collectModels, val1, val2)
      .finally(function() {
        _synRunningSet.delete(t.pId);
        var done = tasks.filter(function(tt) { return !_synRunningSet.has(tt.pId); }).length;
        if (gpCount) gpCount.textContent = done + ' / ' + tasks.length + ' 지문';
        if (gpFill)  gpFill.style.width  = Math.round(done / tasks.length * 100) + '%';
      });
  }));

  clearInterval(gpTimer);
  var totalElapsed = Math.round((Date.now() - startTime) / 1000);
  if (gpTime)  gpTime.textContent  = totalElapsed + '초';
  if (gpLabel) gpLabel.textContent = '전체 완료 ✓';
  if (gpCount) gpCount.textContent = tasks.length + ' / ' + tasks.length + ' 지문';
  if (gpFill)  gpFill.style.width  = '100%';
  if (gpBox)   gpBox.classList.add('done');

  // 비용 통계 렌더링
  _synRenderBatchStats();

  // 다운로드 버튼 표시 (결과가 있을 때만)
  if (_synAccumulated.length > 0) {
    if (wBtn) wBtn.style.display = '';
    if (eBtn) eBtn.style.display = '';
  }

  if (runBtn) runBtn.disabled = false;
}

/* ── 메인 파이프라인 (구버전 호환용 — 첫 번째 지문 실행) ── */
async function synRun() {
  synRunAll();
}

/* ── Word 문서 HTML 생성 ── */
function _synBuildWordDoc(passage, finalResult) {
  var now = new Date();
  var dateStr = now.getFullYear() + '.' + String(now.getMonth()+1).padStart(2,'0') + '.' + String(now.getDate()).padStart(2,'0');

  var css = [
    'body{font-family:"\ub9de\uc740 \uace0\ub515","Malgun Gothic",sans-serif;font-size:10pt;line-height:1.7;color:#111827;margin:18mm 22mm}',
    'h1{font-size:15pt;font-weight:700;margin-bottom:3pt}',
    '.meta{font-size:9pt;color:#6B7280;margin-bottom:14pt}',
    'h2{font-size:11.5pt;font-weight:700;margin:16pt 0 4pt;color:#1D4ED8}',
    '.type-desc{font-size:9pt;color:#6B7280;margin-bottom:8pt}',
    'hr.sec{border:none;border-top:1.5pt solid #E5E7EB;margin:16pt 0}',
    '.passage{font-size:9.5pt;color:#374151;background:#F9FAFB;border:1pt solid #E5E7EB;border-radius:4pt;padding:10pt 12pt;margin-bottom:4pt;line-height:1.8}',
    'table.wt{width:100%;border-collapse:collapse;font-size:9pt;margin-bottom:12pt}',
    'table.wt th{background:#EFF6FF;color:#1E40AF;font-weight:700;padding:5pt 7pt;border:0.5pt solid #BFDBFE;text-align:left;white-space:nowrap}',
    'table.wt td{padding:5pt 7pt;border:0.5pt solid #E5E7EB;vertical-align:top}',
    'table.wt tr:nth-child(even) td{background:#F9FAFB}',
    'td.num{color:#9CA3AF;width:16pt;text-align:center}',
    'td.wc{font-weight:700;white-space:nowrap}',
    'td.ps{color:#6B7280;width:30pt}',
    '.sm{color:#F59E0B;font-weight:700}',
    '.ss{margin:10pt 0 14pt}',
    '.si{margin-bottom:10pt;font-size:9.5pt;line-height:1.6}',
    '.sw{font-weight:700;color:#1E40AF}',
    '.ht{font-size:8.5pt;color:#6B7280;font-style:italic}',
    'th.hc{width:28%}'
  ].join('\n');

  function esc(s) { return (s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;'); }

  function fmtList(arr) {
    if (!Array.isArray(arr) || arr.length === 0) return '<span style="color:#9CA3AF">&mdash;</span>';
    return arr.map(function(x) {
      return esc(x.en||'') + ' <span style="color:#6B7280">(' + esc(x.ko||'') + ')</span>';
    }).join(', ');
  }

  var typeA = finalResult.type_a || [];
  var typeB = finalResult.type_b || [];

  var rowsA = typeA.map(function(item, i) {
    var wc = item.star ? '<span class="sm">&#9733; </span>' + esc(item.word) + '' : esc(item.word);
    return '<tr><td class="num">' + (i+1) + '</td><td class="wc">' + wc + '</td><td class="ps">' + esc(item.pos||'') + '</td><td>' + esc(item.meaning_ko||'') + '</td><td>' + fmtList(item.synonyms_with_ko) + '</td><td>' + fmtList(item.antonyms_with_ko) + '</td></tr>';
  }).join('');

  var tableA = '<table class="wt"><thead><tr><th>#</th><th>\ub2e8\uc5b4</th><th>\ud488\uc0ac</th><th>\uc9c0\ubb38 \ub0b4 \ub73b</th><th>\uc601\uc5b4 \ub3d9\uc758\uc5b4 (\ud55c\uae00 \ub73b)</th><th>\ubc18\uc758\uc5b4 (\ud55c\uae00 \ub73b)</th></tr></thead><tbody>' + rowsA + '</tbody></table>';

  var starred = typeA.filter(function(x) { return x.star && x.star_note; });
  var starSection = '';
  if (starred.length > 0) {
    var si = starred.map(function(x) { return '<div class="si"><span class="sw">&#9733; ' + esc(x.word) + '</span> &mdash; ' + esc(x.star_note) + '</div>'; }).join('');
    starSection = '<h2>&#9733; \ub2e8\uc5b4 \ubb38\ub9e5 \uc758\ubbf8</h2><p class="type-desc">&#9733; \ud45c\uc2dc \ub2e8\uc5b4\uac00 \uc774 \uc9c0\ubb38\uc5d0\uc11c \ud2b9\ubcc4\ud788 \uac16\ub294 \uc758\ubbf8\uc785\ub2c8\ub2e4.</p><div class="ss">' + si + '</div>';
  }

  var typeBSection = '';
  if (typeB.length > 0) {
    var rowsB = typeB.map(function(item, i) {
      return '<tr><td class="num">' + (i+1) + '</td><td class="wc">' + esc(item.word) + '</td><td class="ps">' + esc(item.pos||'') + '</td><td>' + esc(item.meaning_ko||'') + '</td><td class="ht">' + esc(item.context_hint||'') + '</td><td>' + fmtList(item.synonyms_with_ko) + '</td></tr>';
    }).join('');
    typeBSection = '<hr class="sec"><h2>Type B &mdash; \ubb38\ub9e5 \uc720\ucd94 \ub2e8\uc5b4</h2><p class="type-desc">\uc9c0\ubb38 \uc18d \uc8fc\ubcc0 \ub2e8\uc11c\ub85c \ub73b\uc744 \uc720\ucd94\ud560 \uc218 \uc788\ub294 \ub2e8\uc5b4\uc785\ub2c8\ub2e4.</p><table class="wt"><thead><tr><th>#</th><th>\ub2e8\uc5b4</th><th>\ud488\uc0ac</th><th>\uc9c0\ubb38 \ub0b4 \ub73b</th><th class="hc">\ubb38\ub9e5 \ud78c\ud2b8</th><th>\uc601\uc5b4 \ub3d9\uc758\uc5b4 (\ud55c\uae00 \ub73b)</th></tr></thead><tbody>' + rowsB + '</tbody></table>';
  }

  var body = '<h1>\ub2e8\uc5b4 \ud559\uc2b5 \uc790\ub8cc</h1><div class="meta">\uc0dd\uc131\uc77c: ' + dateStr + ' &middot; Type A ' + typeA.length + '\uac1c &middot; Type B ' + typeB.length + '\uac1c</div><h2>\uc6d0\ubb38</h2><div class="passage">' + esc(passage) + '</div><hr class="sec"><h2>Type A &mdash; \ud575\uc2ec\uc5b4</h2><p class="type-desc">\uc9c0\ubb38 \uc774\ud574\uc5d0 \uaf43 \ud544\uc694\ud55c \ub2e8\uc5b4\uc785\ub2c8\ub2e4.</p>' + tableA + starSection + typeBSection;

  return '<!DOCTYPE html><html><head><meta charset="utf-8"><style>' + css + '</style></head><body>' + body + '</body></html>';
}

/* ── Word 다운로드 ── */
/* ── JSON 보기 (결과 카드 → JSON 카드 열기 + 스크롤) ── */
function synViewJson() {
  if (!_synRawData) { showToast('데이터가 없습니다'); return; }
  var card = document.getElementById('syn-json-card');
  var body = document.getElementById('syn-json-body');
  var btn  = document.getElementById('syn-json-toggle-btn');
  if (card) card.style.display = '';
  if (body) body.style.display = '';
  if (btn)  btn.textContent = '접기';
  if (card) card.scrollIntoView({ behavior: 'smooth', block: 'start' });
}


/* ── Excel 워크북 생성 (공통 로직) ── */
function _synBuildExcelWorkbook(results) {
  var wb = XLSX.utils.book_new();
  var multi = results.length > 1;

  /* Type A 시트 */
  var headA = ['#', '단어', '품사', '지문 내 뜻', '★', '동의어 1', '동의어 2', '동의어 3', '동의어 4', '반의어 1', '반의어 2', '문맥 의미'];
  if (multi) headA.unshift('지문');
  var rowsA = [headA];
  results.forEach(function(r, pi) {
    var passagePreview = (r.passage || '').slice(0, 30) + (r.passage && r.passage.length > 30 ? '…' : '');
    var typeA = r.finalResult.type_a || [];
    if (multi && typeA.length > 0) {
      var labelRow = new Array(headA.length).fill('');
      labelRow[0] = '▶ 지문 ' + (pi+1);
      labelRow[1] = passagePreview;
      rowsA.push(labelRow);
    }
    typeA.forEach(function(item, i) {
      var syns = item.synonyms_with_ko || [];
      var ants = item.antonyms_with_ko || [];
      function fmt(x) { return x ? (x.en || '') + ' (' + (x.ko || '') + ')' : ''; }
      var row = [
        i + 1,
        item.word || '',
        item.pos || '',
        item.meaning_ko || '',
        item.star ? '★' : '',
        fmt(syns[0]), fmt(syns[1]), fmt(syns[2]), fmt(syns[3]),
        fmt(ants[0]), fmt(ants[1]),
        item.star_note || ''
      ];
      if (multi) row.unshift(pi + 1);
      rowsA.push(row);
    });
  });
  var wsA = XLSX.utils.aoa_to_sheet(rowsA);
  /* 열 너비 */
  wsA['!cols'] = (multi ? [{wch:6}] : []).concat([{wch:4},{wch:14},{wch:6},{wch:18},{wch:4},{wch:22},{wch:22},{wch:22},{wch:22},{wch:18},{wch:18},{wch:40}]);
  XLSX.utils.book_append_sheet(wb, wsA, 'Type A');

  /* Type B 시트 */
  var headB = ['#', '단어', '품사', '지문 내 뜻', '문맥 힌트', '동의어 1', '동의어 2', '동의어 3', '동의어 4'];
  if (multi) headB.unshift('지문');
  var rowsB = [headB];
  results.forEach(function(r, pi) {
    var passagePreview = (r.passage || '').slice(0, 30) + (r.passage && r.passage.length > 30 ? '…' : '');
    var typeB = r.finalResult.type_b || [];
    if (multi && typeB.length > 0) {
      var labelRow = new Array(headB.length).fill('');
      labelRow[0] = '▶ 지문 ' + (pi+1);
      labelRow[1] = passagePreview;
      rowsB.push(labelRow);
    }
    typeB.forEach(function(item, i) {
      var syns = item.synonyms_with_ko || [];
      function fmt(x) { return x ? (x.en || '') + ' (' + (x.ko || '') + ')' : ''; }
      var row = [
        i + 1,
        item.word || '',
        item.pos || '',
        item.meaning_ko || '',
        item.context_hint || '',
        fmt(syns[0]), fmt(syns[1]), fmt(syns[2]), fmt(syns[3])
      ];
      if (multi) row.unshift(pi + 1);
      rowsB.push(row);
    });
  });
  var wsB = XLSX.utils.aoa_to_sheet(rowsB);
  wsB['!cols'] = (multi ? [{wch:6}] : []).concat([{wch:4},{wch:14},{wch:6},{wch:18},{wch:24},{wch:22},{wch:22},{wch:22},{wch:22}]);
  XLSX.utils.book_append_sheet(wb, wsB, 'Type B');

  return wb;
}
